   371→  async projectTrainPMs(
   372→    trainIds: string[],
   373→    horizonYears: number = 10
   374→  ): Promise<PMRequirement[]> {
   375→    const requirements: PMRequirement[] = [];
   376→
   377→    for (const trainId of trainIds) {
   378→      const train = await this.db.query.trains.findFirst({
