   418→  private async getFleetState(fleetId?: string): Promise<FleetState> {
   419→    const trainData = await this.db.query.trains.findMany({
   420→      where: fleetId ? eq(trains.fleetId, fleetId) : undefined,
   421→    });
   422→
   423→    return {
