   752→  private async generateEnvelopes(
   753→    startDate: Date,
   754→    endDate: Date
   755→  ): Promise<ConstraintEnvelope[]> {
   756→    const envelopes: ConstraintEnvelope[] = [];
   757→    const depotIds = await this.getAllDepotIds();
   758→
   759→    // Generate envelope for each quarter
   760→    for (let q = 0; q < differenceInDays(endDate, startDate) / 90; q++) {
   761→      const quarterStart = addMonths(startDate, q * 3);
   762→      const quarterEnd = addMonths(quarterStart, 3);
   763→
   764→      if (quarterStart > endDate) break;
   765→
   766→      const envelope = await this.generateEnvelopeForPeriod(
   767→        quarterStart,
   768→        quarterEnd,
   769→        depotIds
   770→      );
   771→
   772→      envelopes.push(envelope);
   773→    }
   774→
   775→    return envelopes;
   776→  }
