   911→  /**
   912→   * Calculate and update fleet mileage targets for balancing.
   913→   * Target = fleet average mileage, variance = current - target
   914→   */
   915→  async recalculateFleetTargets(fleetId: string): Promise<void> {
   916→    return this.inTransaction('recalculateFleetTargets', async (tx, span) => {
   917→      span.setAttribute(MmsAttributes.FLEET_ID, fleetId);
   918→
   919→      // Get average mileage for the fleet
   920→      const [{ avgMileage }] = await tx
   921→        .select({ avgMileage: avg(trains.currentMileageKm) })
   922→        .from(trains)
   923→        .where(and(eq(trains.fleetId, fleetId), eq(trains.active, true)));
   924→
   925→      const targetMileage = Math.round(Number(avgMileage) || 0);
   926→      span.setAttribute('mileage.target', targetMileage);
   927→
   928→      // Update all trains in fleet with new target
   929→      await tx
   930→        .update(trains)
   931→        .set({
   932→          targetMileageKm: targetMileage,
   933→          updatedAt: new Date(),
   934→        })
   935→        .where(and(eq(trains.fleetId, fleetId), eq(trains.active, true)));
   936→
   937→      this.log.info(
   938→        { fleetId, targetMileage },
   939→        'Fleet mileage targets recalculated'
   940→      );
   941→    });
   942→  }
