  // ===========================================================================
  // Mileage Operations
  // ===========================================================================

  /**
   * Update train mileage (typically called by ingestion service)
   *
   * Validates:
   * - New mileage must be >= current (no rollback unless meter event)
   * - Maximum daily increase: 2000 km (configurable)
   */
  async updateMileage(request: MileageUpdateRequest): Promise<Train> {
    return this.inTransaction('updateMileage', async (tx, span) => {
      const { trainId, newMileageKm, source } = request;

      span.setAttribute(MmsAttributes.TRAIN_ID, trainId);
      span.setAttribute(MmsAttributes.MILEAGE_KM, newMileageKm);

      const train = await tx.query.trains.findFirst({
        where: eq(trains.id, trainId),
      });

      if (!train) {
        throw new TrainNotFoundError(trainId);
      }

      const oldMileage = train.currentMileageKm;
      const delta = newMileageKm - oldMileage;

      span.setAttribute('mileage.old', oldMileage);
      span.setAttribute('mileage.delta', delta);

      // Validate mileage increase
      if (delta < 0) {
        throw new BusinessRuleError(
          `Mileage cannot decrease (${oldMileage} -> ${newMileageKm}). Use meter event for corrections.`,
          {
            rule: 'mileage_no_decrease',
            context: { trainId, oldMileage, newMileageKm },
          }
        );
      }

      // Warn on large delta (>2000km in single update)
      if (delta > 2000) {
        this.log.warn(
          {
            trainId,
            trainNumber: train.trainNumber,
            oldMileage,
            newMileageKm,
            delta,
            source,
          },
          'Large mileage delta detected - possible anomaly'
        );
      }

      const [result] = await tx
        .update(trains)
        .set({
          currentMileageKm: newMileageKm,
          updatedAt: new Date(),
        })
        .where(eq(trains.id, trainId))
        .returning();

      this.log.info(
        {
          trainId,
          trainNumber: train.trainNumber,
          oldMileage,
          newMileageKm,
          delta,
          source,
        },
        `Train mileage updated: ${oldMileage} -> ${newMileageKm} (+${delta} km)`
      );

      return result;
    });
  }

  /**
   * Calculate and update fleet mileage targets for balancing.
   * Target = fleet average mileage, variance = current - target
   */
  async recalculateFleetTargets(fleetId: string): Promise<void> {
    return this.inTransaction('recalculateFleetTargets', async (tx, span) => {
      span.setAttribute(MmsAttributes.FLEET_ID, fleetId);

      // Get average mileage for the fleet
      const [{ avgMileage }] = await tx
        .select({ avgMileage: avg(trains.currentMileageKm) })
        .from(trains)
        .where(and(eq(trains.fleetId, fleetId), eq(trains.active, true)));

      const targetMileage = Math.round(Number(avgMileage) || 0);
      span.setAttribute('mileage.target', targetMileage);

      // Update all trains in fleet with new target
      await tx
        .update(trains)
        .set({
          targetMileageKm: targetMileage,
          updatedAt: new Date(),
        })
        .where(and(eq(trains.fleetId, fleetId), eq(trains.active, true)));

      this.log.info(
        { fleetId, targetMileage },
        'Fleet mileage targets recalculated'
      );
    });
  }

