  /**
   * List components with optional filters
   */
  async listComponents(
    filters?: ComponentListFilters,
    pagination?: PaginationOptions
  ): Promise<PaginatedResult<TrainComponent>> {
    return this.traced('listComponents', async (span) => {
      const conditions: SQL<unknown>[] = [];

      if (filters?.componentType) {
        conditions.push(eq(trainComponents.componentType, filters.componentType));
      }
      if (filters?.status) {
        if (Array.isArray(filters.status)) {
          conditions.push(inArray(trainComponents.status, filters.status));
        } else {
          conditions.push(eq(trainComponents.status, filters.status));
        }
      }
      if (filters?.trainId) {
        conditions.push(eq(trainComponents.currentTrainId, filters.trainId));
      }
      if (filters?.serialNumbers && filters.serialNumbers.length > 0) {
        conditions.push(inArray(trainComponents.serialNumber, filters.serialNumbers));
      }
      if (filters?.hasCurrentTrain !== undefined) {
        if (filters.hasCurrentTrain) {
          conditions.push(sql`${trainComponents.currentTrainId} IS NOT NULL`);
        } else {
          conditions.push(sql`${trainComponents.currentTrainId} IS NULL`);
        }
      }

      const whereClause = conditions.length > 0 ? and(...conditions) : undefined;

      // Get total count
      const [{ totalCount }] = await this.db
        .select({ totalCount: count() })
        .from(trainComponents)
        .where(whereClause);

      // Apply pagination
      const page = pagination?.page ?? 1;
      const pageSize = Math.min(pagination?.pageSize ?? 50, 500);
      const offset = (page - 1) * pageSize;

      // Determine sort order
      const sortDirection = pagination?.sortOrder === 'desc' ? desc : asc;
      const getOrderBy = () => {
        switch (pagination?.sortBy) {
          case 'mileage':
            return sortDirection(trainComponents.componentMileageKm);
          case 'status':
            return sortDirection(trainComponents.status);
          case 'type':
            return sortDirection(trainComponents.componentType);
          default:
            return sortDirection(trainComponents.serialNumber);
        }
      };

      const data = await this.db.query.trainComponents.findMany({
        where: whereClause,
        orderBy: getOrderBy(),
        limit: pageSize,
        offset,
      });

      span.setAttribute('result.count', data.length);
      span.setAttribute('result.total', totalCount);

      return {
        data,
        total: totalCount,
        page,
        pageSize,
        totalPages: Math.ceil(totalCount / pageSize),
      };
    });
  }

