   782→  /**
   783→   * Check for track conflicts.
   784→   */
   785→  async checkTrackConflict(
   786→    trackId: string,
   787→    targetDate: string,
   788→    durationDays: number,
   789→    excludePmId?: string
   790→  ): Promise<PmScheduleRecord | null> {
   791→    return this.traced('checkTrackConflict', async (span) => {
   792→      span.setAttribute('track.id', trackId);
   793→      span.setAttribute('pm.targetDate', targetDate);
   794→
   795→      const endDate = new Date(targetDate);
   796→      endDate.setDate(endDate.getDate() + durationDays - 1);
   797→      const endDateStr = endDate.toISOString().split('T')[0];
   798→
   799→      const conditions: SQL<unknown>[] = [
   800→        eq(pmSchedule.assignedTrackId, trackId),
   801→        inArray(pmSchedule.status, ['SCHEDULED', 'IN_PROGRESS']),
   802→        isNull(pmSchedule.scenarioId),
   803→        sql`${pmSchedule.targetDate} <= ${endDateStr}`,
   804→        sql`DATE(${pmSchedule.targetDate}) + COALESCE(
   805→          (SELECT min_track_days FROM pm_types WHERE id = ${pmSchedule.pmTypeId}), 1
   806→        ) > ${targetDate}`,
   807→      ];
   808→
   809→      if (excludePmId) {
   810→        conditions.push(sql`${pmSchedule.id} != ${excludePmId}`);
   811→      }
   812→
   813→      const conflict = await this.db.query.pmSchedule.findFirst({
   814→        where: and(...conditions),
   815→      });
   816→
   817→      return conflict ?? null;
   818→    });
   819→  }
