   930→  /**
   931→   * Check if PM is locked by Maximo (INPRG work order).
   932→   */
   933→  async checkMaximoLock(pmScheduleId: string): Promise<{
   934→    isLocked: boolean;
   935→    workOrderId: string | null;
   936→    maximoStatus: string | null;
   937→    reason: string | null;
   938→  }> {
   939→    return this.traced('checkMaximoLock', async (span) => {
   940→      span.setAttribute('pm.scheduleId', pmScheduleId);
   941→
   942→      const pm = await this.db.query.pmSchedule.findFirst({
   943→        where: eq(pmSchedule.id, pmScheduleId),
   944→      });
   945→
   946→      if (!pm) {
   947→        throw new PmScheduleNotFoundError(pmScheduleId);
   948→      }
   949→
   950→      // Check explicit lock
   951→      if (pm.isLocked) {
   952→        return {
   953→          isLocked: true,
   954→          workOrderId: pm.maximoWoId,
   955→          maximoStatus: null,
   956→          reason: pm.lockedReason ?? 'Manually locked',
   957→        };
   958→      }
   959→
   960→      // Check Maximo work order status
   961→      if (pm.maximoWoId) {
   962→        // In a full implementation, we would query Maximo for status
   963→        // For now, check if status is IN_PROGRESS
   964→        if (pm.status === 'IN_PROGRESS') {
   965→          return {
   966→            isLocked: true,
   967→            workOrderId: pm.maximoWoId,
   968→            maximoStatus: 'INPRG',
   969→            reason: 'Work order is in progress in Maximo',
   970→          };
   971→        }
   972→      }
   973→
   974→      return {
   975→        isLocked: false,
   976→        workOrderId: pm.maximoWoId,
   977→        maximoStatus: null,
   978→        reason: null,
   979→      };
   980→    });
   981→  }
