  1439→  /**
  1440→   * Lock a PM to prevent optimizer changes.
  1441→   */
  1442→  async lockPm(
  1443→    pmScheduleId: string,
  1444→    reason: string,
  1445→    lockedBy: string
  1446→  ): Promise<PmScheduleRecord> {
  1447→    return this.inTransaction('lockPm', async (tx, span) => {
  1448→      span.setAttribute('pm.scheduleId', pmScheduleId);
  1449→
  1450→      const existing = await tx.query.pmSchedule.findFirst({
  1451→        where: eq(pmSchedule.id, pmScheduleId),
  1452→      });
  1453→
  1454→      if (!existing) {
  1455→        throw new PmScheduleNotFoundError(pmScheduleId);
  1456→      }
  1457→
  1458→      if (existing.isLocked) {
  1459→        throw new BusinessRuleError('PM is already locked', {
  1460→          rule: 'pm_already_locked',
  1461→          context: { lockedBy: existing.lockedBy, lockedAt: existing.lockedAt },
  1462→        });
  1463→      }
  1464→
  1465→      const [updated] = await tx
  1466→        .update(pmSchedule)
  1467→        .set({
  1468→          isLocked: true,
  1469→          lockedReason: reason,
  1470→          lockedBy,
  1471→          lockedAt: new Date(),
  1472→          updatedAt: new Date(),
  1473→        })
  1474→        .where(eq(pmSchedule.id, pmScheduleId))
  1475→        .returning();
  1476→
  1477→      // Create audit history
  1478→      const historyRecord: NewPmScheduleHistory = {
  1479→        pmScheduleId,
  1480→        changeType: 'LOCKED',
  1481→        changedBy: lockedBy,
  1482→        changeReason: reason,
  1483→        changeSource: 'USER',
  1484→      };
  1485→
  1486→      await tx.insert(pmScheduleHistory).values(historyRecord);
  1487→
  1488→      this.log.info(
  1489→        { pmScheduleId, reason, lockedBy },
  1490→        `PM locked: ${pmScheduleId}`
  1491→      );
  1492→
  1493→      return updated;
  1494→    });
  1495→  }
