    95→/** Alert types */
    96→export type AlertType = 'REPLAN_REQUIRED' | 'APPROACHING_THRESHOLD' | 'FLEET_REPLAN_RECOMMENDED';
    97→
    98→/** Drift alert structure */
    99→export interface DriftAlert {
   100→  trainId?: string;
   101→  trainNumber?: string;
   102→  severity: AlertSeverity;
   103→  type: AlertType;
   104→  message: string;
   105→  metrics: {
   106→    mileageDriftPct?: number;
   107→    avgPmDriftDays?: number;
   108→    affectedTrains?: number;
   109→  };
   110→}
   111→
   112→/** Result when drift analysis is skipped */
   113→export interface DriftAnalysisSkipped {
   114→  skipped: true;
   115→  reason: string;
   116→}
   117→
   118→/** Result of successful drift analysis */
   119→export interface DriftAnalysisSuccess {
   120→  skipped: false;
   121→  baselineId: string;
   122→  baselineVersion: string;
   123→  analysisDate: string;
   124→  trainAnalyses: TrainDriftAnalysis[];
   125→  alerts: DriftAlert[];
   126→  summary: {
   127→    totalTrains: number;
   128→    trainsWithDrift: number;
   129→    trainsRequiringReplan: number;
   130→    avgFleetDriftPct: number;
   131→  };
   132→}
   133→
   134→/** Full drift analysis result */
   135→export type DriftAnalysisResult = DriftAnalysisSkipped | DriftAnalysisSuccess;
   136→
   137→/** Filters for querying drift history */
   138→export interface DriftHistoryFilters {
   139→  baselineId?: string;
   140→  trainId?: string;
   141→  fromDate?: Date;
   142→  toDate?: Date;
   143→  requiresReplan?: boolean;
   144→}
   145→
   146→/** Paginated drift history result */
   147→export interface PaginatedDriftHistory {
   148→  data: DriftAnalysis[];
   149→  total: number;
   150→  page: number;
   151→  pageSize: number;
   152→  totalPages: number;
   153→}
