/**
 * MMS Drift Monitor Service
 *
 * Monitors plan stability by comparing actual fleet state against published baselines.
 * Runs nightly drift analysis and generates alerts when thresholds are exceeded.
 *
 * Key responsibilities:
 * - Compare current mileage against baseline projections
 * - Compare current PM schedule against baseline snapshots
 * - Generate alerts when drift exceeds thresholds
 * - Persist drift analysis results for trending
 * - Update Prometheus metrics for monitoring
 *
 * Drift Thresholds (from spec):
 * - Mileage: ±5.0%
 * - Schedule: ±14 days
 * - Fleet: ≥5 trains requiring replan triggers CRITICAL alert
 *
 * @see specs/004-domain-services.md Section 4.10
 */

import { eq, and, desc, sql, inArray, gte, lte, isNull, count } from 'drizzle-orm';
import { differenceInDays, format, parseISO } from 'date-fns';
import { BaseService, MmsAttributes } from '../lib/services/base';
import {
  driftAnalysis,
  planBaselines,
  baselineMileageProjection,
  baselinePmSchedule,
  pmSchedule,
  trains,
  pmTypes,
  type PlanBaseline,
  type DriftAnalysis,
} from '../lib/db/schema';
import { NotFoundError } from '../lib/errors';
import {
  driftTrainsRequiringReplan,
  driftMileagePercent,
  driftAnalysisTotal,
} from '../lib/metrics';

// =============================================================================
// Types
// =============================================================================

/** Drift threshold configuration */
export interface DriftThresholds {
  /** Maximum acceptable mileage drift percentage (default: 5.0) */
  mileageDriftPct: number;
  /** Maximum acceptable PM schedule drift in days (default: 14) */
  scheduleDriftDays: number;
  /** Fleet-level threshold for CRITICAL alert (default: 5) */
  fleetDriftTrainCount: number;
}

/** Default thresholds from specification */
export const DEFAULT_DRIFT_THRESHOLDS: DriftThresholds = {
  mileageDriftPct: 5.0,
  scheduleDriftDays: 14,
  fleetDriftTrainCount: 5,
};

/** Direction of PM schedule drift */
export type DriftDirection = 'LATER' | 'EARLIER' | 'ON_TRACK';

/** Drift analysis for individual PM */
export interface PMDrift {
  pmTypeId: string;
  pmCode: string;
  baselineDate: string;
  currentDate: string;
  driftDays: number;
  direction: DriftDirection;
}

/** Per-train drift analysis result */
export interface TrainDriftAnalysis {
  trainId: string;
  trainNumber: string;
  baselineProjectedKm: number;
  actualKm: number;
  mileageDriftKm: number;
  mileageDriftPct: number;
  pmDrifts: PMDrift[];
  avgPmDriftDays: number;
  maxPmDriftDays: number;
  requiresReplan: boolean;
  replanReason?: string;
}

/** Alert severity levels */
export type AlertSeverity = 'HIGH' | 'MEDIUM' | 'CRITICAL';

/** Alert types */
export type AlertType = 'REPLAN_REQUIRED' | 'APPROACHING_THRESHOLD' | 'FLEET_REPLAN_RECOMMENDED';

/** Drift alert structure */
export interface DriftAlert {
  trainId?: string;
  trainNumber?: string;
  severity: AlertSeverity;
  type: AlertType;
  message: string;
  metrics: {
    mileageDriftPct?: number;
    avgPmDriftDays?: number;
    affectedTrains?: number;
  };
}

/** Result when drift analysis is skipped */
export interface DriftAnalysisSkipped {
  skipped: true;
  reason: string;
}

/** Result of successful drift analysis */
export interface DriftAnalysisSuccess {
  skipped: false;
  baselineId: string;
  baselineVersion: string;
  analysisDate: string;
  trainAnalyses: TrainDriftAnalysis[];
  alerts: DriftAlert[];
  summary: {
    totalTrains: number;
    trainsWithDrift: number;
    trainsRequiringReplan: number;
    avgFleetDriftPct: number;
  };
}

/** Full drift analysis result */
export type DriftAnalysisResult = DriftAnalysisSkipped | DriftAnalysisSuccess;

/** Filters for querying drift history */
export interface DriftHistoryFilters {
  baselineId?: string;
  trainId?: string;
  fromDate?: Date;
  toDate?: Date;
  requiresReplan?: boolean;
}

/** Paginated drift history result */
export interface PaginatedDriftHistory {
  data: DriftAnalysis[];
  total: number;
  page: number;
  pageSize: number;
  totalPages: number;
}

// =============================================================================
// Singleton instance
// =============================================================================

let instance: DriftMonitorService | null = null;

/**
 * Get the singleton DriftMonitorService instance
 */
export function getDriftMonitorService(): DriftMonitorService {
  if (!instance) {
    instance = new DriftMonitorService();
  }
  return instance;
}

// =============================================================================
// DriftMonitorService Implementation
// =============================================================================

/**
 * Drift Monitor Service for monitoring plan stability
 *
 * @example
 * ```typescript
 * const driftService = getDriftMonitorService();
 *
 * // Run nightly drift analysis
 * const result = await driftService.runDriftAnalysis();
 *
 * if (!result.skipped) {
 *   console.log(`Analyzed ${result.trainAnalyses.length} trains`);
 *   console.log(`${result.alerts.length} alerts generated`);
 * }
 *
 * // Get latest analysis for a specific train
 * const trainDrift = await driftService.getLatestTrainDrift('train-123');
 * ```
 */
export class DriftMonitorService extends BaseService {
  /** Drift thresholds */
  private readonly thresholds: DriftThresholds;

  constructor(thresholds?: Partial<DriftThresholds>) {
    super({ name: 'drift-monitor-service' });
    this.thresholds = {
      ...DEFAULT_DRIFT_THRESHOLDS,
      ...thresholds,
    };
  }

  // ===========================================================================
  // Public Methods
  // ===========================================================================

  /**
   * Run drift analysis comparing current state against published baseline
   *
   * This is the main nightly job that:
   * 1. Retrieves the latest published baseline
   * 2. Compares each active train's mileage against baseline projections
   * 3. Compares current PM schedule against baseline snapshots
   * 4. Generates alerts for threshold breaches
   * 5. Persists results for trending
   * 6. Updates Prometheus metrics
   *
   * @param analysisDate - Date for analysis (defaults to today)
   * @returns Analysis result or skipped indicator
   */
  async runDriftAnalysis(analysisDate?: Date): Promise<DriftAnalysisResult> {
    return this.traced('runDriftAnalysis', async (span) => {
      const effectiveDate = analysisDate ?? new Date();
      const dateStr = format(effectiveDate, 'yyyy-MM-dd');
      span.setAttribute('drift.analysisDate', dateStr);

      // 1. Get latest published baseline
      const baseline = await this.getPublishedBaseline();

      if (!baseline) {
        this.log.info('No published baseline found, skipping drift analysis');
        driftAnalysisTotal.inc({ result: 'skipped' });
        return {
          skipped: true,
          reason: 'No published baseline exists',
        };
      }

      span.setAttribute(MmsAttributes.BASELINE_ID, baseline.id);
      span.setAttribute('baseline.version', baseline.version);

      // 2. Get all active trains
      const activeTrains = await this.db
        .select({
          id: trains.id,
          trainNumber: trains.trainNumber,
          currentMileageKm: trains.currentMileageKm,
        })
        .from(trains)
        .where(eq(trains.active, true));

      span.setAttribute('drift.trainCount', activeTrains.length);

      if (activeTrains.length === 0) {
        this.log.info('No active trains found, skipping drift analysis');
        driftAnalysisTotal.inc({ result: 'skipped' });
        return {
          skipped: true,
          reason: 'No active trains in fleet',
        };
      }

      // 3. Analyze each train
      const trainAnalyses: TrainDriftAnalysis[] = [];

      for (const train of activeTrains) {
        const analysis = await this.analyzeTrainDrift(
          train.id,
          train.trainNumber,
          train.currentMileageKm ?? 0,
          baseline,
          effectiveDate
        );
        trainAnalyses.push(analysis);
      }

      // 4. Generate alerts
      const alerts = this.generateAlerts(trainAnalyses);

      // 5. Persist results
      await this.persistDriftAnalysis(trainAnalyses, baseline.id, dateStr);

      // 6. Update metrics
      this.updateMetrics(trainAnalyses, baseline.id);

      // Calculate summary
      const trainsWithDrift = trainAnalyses.filter(
        (a) => Math.abs(a.mileageDriftPct) > 1.0
      ).length;
      const trainsRequiringReplan = trainAnalyses.filter(
        (a) => a.requiresReplan
      ).length;
      const avgFleetDriftPct =
        trainAnalyses.length > 0
          ? trainAnalyses.reduce((sum, a) => sum + a.mileageDriftPct, 0) /
            trainAnalyses.length
          : 0;

      span.setAttribute('drift.trainsWithDrift', trainsWithDrift);
      span.setAttribute('drift.trainsRequiringReplan', trainsRequiringReplan);
      span.setAttribute('drift.alertCount', alerts.length);

      driftAnalysisTotal.inc({ result: 'completed' });

      this.log.info(
        {
          baselineId: baseline.id,
          baselineVersion: baseline.version,
          trainCount: trainAnalyses.length,
          trainsRequiringReplan,
          alertCount: alerts.length,
        },
        'Drift analysis completed'
      );

      return {
        skipped: false,
        baselineId: baseline.id,
        baselineVersion: baseline.version,
        analysisDate: dateStr,
        trainAnalyses,
        alerts,
        summary: {
          totalTrains: trainAnalyses.length,
          trainsWithDrift,
          trainsRequiringReplan,
          avgFleetDriftPct: Math.round(avgFleetDriftPct * 100) / 100,
        },
      };
    });
  }

  /**
   * Get the latest drift analysis for a specific train
   *
   * @param trainId - Train to retrieve drift for
   * @throws NotFoundError if no drift analysis exists
   */
  async getLatestTrainDrift(trainId: string): Promise<DriftAnalysis> {
    return this.traced('getLatestTrainDrift', async (span) => {
      span.setAttribute(MmsAttributes.TRAIN_ID, trainId);

      const result = await this.db
        .select()
        .from(driftAnalysis)
        .where(eq(driftAnalysis.trainId, trainId))
        .orderBy(desc(driftAnalysis.analysisDate))
        .limit(1);

      const drift = result[0];
      if (!drift) {
        throw new NotFoundError(`No drift analysis found for train: ${trainId}`);
      }

      return drift;
    });
  }

  /**
   * Get drift analysis history with filtering and pagination
   */
  async getDriftHistory(
    filters?: DriftHistoryFilters,
    pagination?: { page?: number; pageSize?: number }
  ): Promise<PaginatedDriftHistory> {
    return this.traced('getDriftHistory', async (span) => {
      const page = pagination?.page ?? 1;
      const pageSize = pagination?.pageSize ?? 50;
      const offset = (page - 1) * pageSize;

      // Build where conditions
      const conditions: ReturnType<typeof eq>[] = [];

      if (filters?.baselineId) {
        conditions.push(eq(driftAnalysis.baselineId, filters.baselineId));
      }

      if (filters?.trainId) {
        conditions.push(eq(driftAnalysis.trainId, filters.trainId));
      }

      if (filters?.fromDate) {
        conditions.push(
          gte(driftAnalysis.analysisDate, format(filters.fromDate, 'yyyy-MM-dd'))
        );
      }

      if (filters?.toDate) {
        conditions.push(
          lte(driftAnalysis.analysisDate, format(filters.toDate, 'yyyy-MM-dd'))
        );
      }

      if (filters?.requiresReplan !== undefined) {
        conditions.push(eq(driftAnalysis.requiresReplan, filters.requiresReplan));
      }

      const whereClause = conditions.length > 0 ? and(...conditions) : undefined;

      // Get total count
      const [{ totalCount }] = await this.db
        .select({ totalCount: count() })
        .from(driftAnalysis)
        .where(whereClause);

      // Get paginated data
      const data = await this.db
        .select()
        .from(driftAnalysis)
        .where(whereClause)
        .orderBy(desc(driftAnalysis.analysisDate), driftAnalysis.trainId)
        .limit(pageSize)
        .offset(offset);

      span.setAttribute('drift.resultCount', data.length);
      span.setAttribute('drift.totalCount', totalCount);

      return {
        data,
        total: totalCount,
        page,
        pageSize,
        totalPages: Math.ceil(totalCount / pageSize),
      };
    });
  }

  /**
   * Get latest drift analysis results for all trains requiring replan
   */
  async getTrainsRequiringReplan(): Promise<DriftAnalysis[]> {
    return this.traced('getTrainsRequiringReplan', async (span) => {
      // Get the latest baseline
      const baseline = await this.getPublishedBaseline();

      if (!baseline) {
        return [];
      }

      // Get most recent analysis date for this baseline
      const latestDate = await this.db
        .select({ maxDate: sql<string>`MAX(analysis_date)` })
        .from(driftAnalysis)
        .where(eq(driftAnalysis.baselineId, baseline.id));

      if (!latestDate[0]?.maxDate) {
        return [];
      }

      // Get all trains requiring replan from that date
      const results = await this.db
        .select()
        .from(driftAnalysis)
        .where(
          and(
            eq(driftAnalysis.baselineId, baseline.id),
            eq(driftAnalysis.analysisDate, latestDate[0].maxDate),
            eq(driftAnalysis.requiresReplan, true)
          )
        )
        .orderBy(desc(sql`ABS(${driftAnalysis.mileageDriftPct})`));

      span.setAttribute('drift.trainsRequiringReplan', results.length);

      return results;
    });
  }

  /**
   * Get drift analysis summary for a baseline
   */
  async getDriftSummary(baselineId: string, analysisDate?: string): Promise<{
    totalTrains: number;
    trainsWithDrift: number;
    trainsRequiringReplan: number;
    avgMileageDriftPct: number;
    maxMileageDriftPct: number;
    avgPmDriftDays: number;
    maxPmDriftDays: number;
  } | null> {
    return this.traced('getDriftSummary', async (span) => {
      span.setAttribute(MmsAttributes.BASELINE_ID, baselineId);

      // Determine analysis date to use
      let dateToUse = analysisDate;
      if (!dateToUse) {
        const latestDate = await this.db
          .select({ maxDate: sql<string>`MAX(analysis_date)` })
          .from(driftAnalysis)
          .where(eq(driftAnalysis.baselineId, baselineId));

        dateToUse = latestDate[0]?.maxDate;
      }

      if (!dateToUse) {
        return null;
      }

      span.setAttribute('drift.analysisDate', dateToUse);

      // Get summary statistics
      const summary = await this.db
        .select({
          totalTrains: count(),
          avgMileageDriftPct: sql<string>`AVG(${driftAnalysis.mileageDriftPct})`,
          maxMileageDriftPct: sql<string>`MAX(ABS(${driftAnalysis.mileageDriftPct}))`,
          avgPmDriftDays: sql<string>`AVG(${driftAnalysis.avgPmDriftDays})`,
          maxPmDriftDays: sql<number>`MAX(${driftAnalysis.maxPmDriftDays})`,
        })
        .from(driftAnalysis)
        .where(
          and(
            eq(driftAnalysis.baselineId, baselineId),
            eq(driftAnalysis.analysisDate, dateToUse)
          )
        );

      const stats = summary[0];
      if (!stats || stats.totalTrains === 0) {
        return null;
      }

      // Count trains with significant drift (>1%)
      const [{ driftCount }] = await this.db
        .select({ driftCount: count() })
        .from(driftAnalysis)
        .where(
          and(
            eq(driftAnalysis.baselineId, baselineId),
            eq(driftAnalysis.analysisDate, dateToUse),
            sql`ABS(${driftAnalysis.mileageDriftPct}) > 1.0`
          )
        );

      // Count trains requiring replan
      const [{ replanCount }] = await this.db
        .select({ replanCount: count() })
        .from(driftAnalysis)
        .where(
          and(
            eq(driftAnalysis.baselineId, baselineId),
            eq(driftAnalysis.analysisDate, dateToUse),
            eq(driftAnalysis.requiresReplan, true)
          )
        );

      return {
        totalTrains: stats.totalTrains,
        trainsWithDrift: driftCount,
        trainsRequiringReplan: replanCount,
        avgMileageDriftPct: parseFloat(stats.avgMileageDriftPct ?? '0'),
        maxMileageDriftPct: parseFloat(stats.maxMileageDriftPct ?? '0'),
        avgPmDriftDays: parseFloat(stats.avgPmDriftDays ?? '0'),
        maxPmDriftDays: stats.maxPmDriftDays ?? 0,
      };
    });
  }

  /**
   * Get current thresholds configuration
   */
  getThresholds(): DriftThresholds {
    return { ...this.thresholds };
  }

  // ===========================================================================
  // Private Helper Methods
  // ===========================================================================

  /**
   * Get the latest published baseline
   */
  private async getPublishedBaseline(): Promise<PlanBaseline | null> {
    const result = await this.db
      .select()
      .from(planBaselines)
      .where(eq(planBaselines.status, 'PUBLISHED'))
      .orderBy(desc(planBaselines.publishedAt))
      .limit(1);

    return result[0] ?? null;
  }

  /**
   * Analyze drift for a single train
   */
  private async analyzeTrainDrift(
    trainId: string,
    trainNumber: string,
    actualKm: number,
    baseline: PlanBaseline,
    analysisDate: Date
  ): Promise<TrainDriftAnalysis> {
    const dateStr = format(analysisDate, 'yyyy-MM-dd');

    // Get baseline mileage projection closest to analysis date
    const baselineProjection = await this.db
      .select()
      .from(baselineMileageProjection)
      .where(
        and(
          eq(baselineMileageProjection.baselineId, baseline.id),
          eq(baselineMileageProjection.trainId, trainId),
          lte(baselineMileageProjection.projectionDate, dateStr)
        )
      )
      .orderBy(desc(baselineMileageProjection.projectionDate))
      .limit(1);

    // Calculate mileage drift
    const baselineProjectedKm = baselineProjection[0]?.projectedCumulativeKm ?? actualKm;
    const mileageDriftKm = actualKm - baselineProjectedKm;
    const mileageDriftPct =
      baselineProjectedKm > 0
        ? (mileageDriftKm / baselineProjectedKm) * 100
        : 0;

    // Get baseline PM schedule for this train (future PMs from analysis date)
    const baselinePms = await this.db
      .select({
        pmTypeId: baselinePmSchedule.pmTypeId,
        projectedDate: baselinePmSchedule.projectedDate,
        pmCode: pmTypes.pmCode,
      })
      .from(baselinePmSchedule)
      .innerJoin(pmTypes, eq(baselinePmSchedule.pmTypeId, pmTypes.id))
      .where(
        and(
          eq(baselinePmSchedule.baselineId, baseline.id),
          eq(baselinePmSchedule.trainId, trainId),
          gte(baselinePmSchedule.projectedDate, dateStr)
        )
      )
      .orderBy(baselinePmSchedule.projectedDate);

    // Get current PM schedule for this train
    const currentPms = await this.db
      .select({
        pmTypeId: pmSchedule.pmTypeId,
        targetDate: pmSchedule.targetDate,
        pmCode: pmTypes.pmCode,
      })
      .from(pmSchedule)
      .innerJoin(pmTypes, eq(pmSchedule.pmTypeId, pmTypes.id))
      .where(
        and(
          eq(pmSchedule.trainId, trainId),
          isNull(pmSchedule.scenarioId),
          inArray(pmSchedule.status, ['SCHEDULED', 'IN_PROGRESS']),
          gte(pmSchedule.targetDate, dateStr)
        )
      )
      .orderBy(pmSchedule.targetDate);

    // Calculate PM drift by matching PM types
    const pmDrifts: PMDrift[] = [];

    for (const baselinePm of baselinePms) {
      // Find matching current PM by PM type (first occurrence)
      const matchingCurrent = currentPms.find(
        (cp) =>
          cp.pmTypeId === baselinePm.pmTypeId &&
          !pmDrifts.some((d) => d.currentDate === cp.targetDate && d.pmTypeId === cp.pmTypeId)
      );

      if (matchingCurrent) {
        const baselineDate = parseISO(baselinePm.projectedDate);
        const currentDate = parseISO(matchingCurrent.targetDate);
        const driftDays = differenceInDays(currentDate, baselineDate);

        let direction: DriftDirection = 'ON_TRACK';
        if (driftDays > 0) direction = 'LATER';
        else if (driftDays < 0) direction = 'EARLIER';

        pmDrifts.push({
          pmTypeId: baselinePm.pmTypeId,
          pmCode: baselinePm.pmCode,
          baselineDate: baselinePm.projectedDate,
          currentDate: matchingCurrent.targetDate,
          driftDays,
          direction,
        });
      }
    }

    // Calculate PM drift statistics
    const avgPmDriftDays =
      pmDrifts.length > 0
        ? pmDrifts.reduce((sum, d) => sum + Math.abs(d.driftDays), 0) / pmDrifts.length
        : 0;
    const maxPmDriftDays =
      pmDrifts.length > 0
        ? Math.max(...pmDrifts.map((d) => Math.abs(d.driftDays)))
        : 0;

    // Determine if replan is required
    const mileageExceedsThreshold = Math.abs(mileageDriftPct) > this.thresholds.mileageDriftPct;
    const scheduleExceedsThreshold = maxPmDriftDays > this.thresholds.scheduleDriftDays;
    const requiresReplan = mileageExceedsThreshold || scheduleExceedsThreshold;

    // Build replan reason
    let replanReason: string | undefined;
    if (requiresReplan) {
      const reasons: string[] = [];
      if (mileageExceedsThreshold) {
        reasons.push(
          `Mileage drift ${mileageDriftPct.toFixed(1)}% exceeds ${this.thresholds.mileageDriftPct}% threshold`
        );
      }
      if (scheduleExceedsThreshold) {
        reasons.push(
          `PM schedule drift ${maxPmDriftDays} days exceeds ${this.thresholds.scheduleDriftDays} day threshold`
        );
      }
      replanReason = reasons.join('; ');
    }

    return {
      trainId,
      trainNumber,
      baselineProjectedKm,
      actualKm,
      mileageDriftKm,
      mileageDriftPct: Math.round(mileageDriftPct * 100) / 100,
      pmDrifts,
      avgPmDriftDays: Math.round(avgPmDriftDays * 10) / 10,
      maxPmDriftDays,
      requiresReplan,
      replanReason,
    };
  }

  /**
   * Generate alerts based on drift analysis results
   */
  private generateAlerts(trainAnalyses: TrainDriftAnalysis[]): DriftAlert[] {
    const alerts: DriftAlert[] = [];
    const trainsRequiringReplan = trainAnalyses.filter((a) => a.requiresReplan);

    // Individual train alerts
    for (const analysis of trainAnalyses) {
      if (analysis.requiresReplan) {
        // HIGH severity: Train requires immediate replan
        alerts.push({
          trainId: analysis.trainId,
          trainNumber: analysis.trainNumber,
          severity: 'HIGH',
          type: 'REPLAN_REQUIRED',
          message: analysis.replanReason ?? 'Train requires schedule replan',
          metrics: {
            mileageDriftPct: analysis.mileageDriftPct,
            avgPmDriftDays: analysis.avgPmDriftDays,
          },
        });
      } else if (
        Math.abs(analysis.mileageDriftPct) > this.thresholds.mileageDriftPct * 0.7
      ) {
        // MEDIUM severity: Approaching threshold (>70% of threshold)
        alerts.push({
          trainId: analysis.trainId,
          trainNumber: analysis.trainNumber,
          severity: 'MEDIUM',
          type: 'APPROACHING_THRESHOLD',
          message: `Mileage drift ${analysis.mileageDriftPct.toFixed(1)}% approaching ${this.thresholds.mileageDriftPct}% threshold`,
          metrics: {
            mileageDriftPct: analysis.mileageDriftPct,
          },
        });
      }
    }

    // Fleet-level alert
    if (trainsRequiringReplan.length >= this.thresholds.fleetDriftTrainCount) {
      alerts.push({
        severity: 'CRITICAL',
        type: 'FLEET_REPLAN_RECOMMENDED',
        message: `${trainsRequiringReplan.length} trains require schedule replan - fleet-level action recommended`,
        metrics: {
          affectedTrains: trainsRequiringReplan.length,
        },
      });
    }

    return alerts;
  }

  /**
   * Persist drift analysis results to database
   */
  private async persistDriftAnalysis(
    analyses: TrainDriftAnalysis[],
    baselineId: string,
    analysisDate: string
  ): Promise<void> {
    return this.inTransaction('persistDriftAnalysis', async (tx, span) => {
      span.setAttribute('drift.recordCount', analyses.length);

      // Delete existing records for this baseline + date (upsert behavior)
      await tx
        .delete(driftAnalysis)
        .where(
          and(
            eq(driftAnalysis.baselineId, baselineId),
            eq(driftAnalysis.analysisDate, analysisDate)
          )
        );

      // Insert new records in batches
      const BATCH_SIZE = 100;
      for (let i = 0; i < analyses.length; i += BATCH_SIZE) {
        const batch = analyses.slice(i, i + BATCH_SIZE);
        await tx.insert(driftAnalysis).values(
          batch.map((a) => ({
            baselineId,
            analysisDate,
            trainId: a.trainId,
            baselineProjectedKm: a.baselineProjectedKm,
            actualKm: a.actualKm,
            mileageDriftPct: a.mileageDriftPct.toFixed(2),
            avgPmDriftDays: a.avgPmDriftDays.toFixed(1),
            maxPmDriftDays: a.maxPmDriftDays,
            requiresReplan: a.requiresReplan,
            replanReason: a.replanReason ?? null,
          }))
        );
      }

      // Note: Drift analysis is a system job, not a user-initiated action.
      // Audit trail is maintained through:
      // 1. drift_analysis table records with timestamps
      // 2. OpenTelemetry distributed tracing
      // 3. Prometheus metrics (mms_drift_analysis_total)
      // 4. Application logs below

      const replanCount = analyses.filter((a) => a.requiresReplan).length;
      this.log.info(
        { baselineId, analysisDate, recordCount: analyses.length, replanCount },
        'Persisted drift analysis results'
      );
    });
  }

  /**
   * Update Prometheus metrics
   */
  private updateMetrics(analyses: TrainDriftAnalysis[], baselineId: string): void {
    const trainsRequiringReplan = analyses.filter((a) => a.requiresReplan).length;

    // Update gauge for trains requiring replan
    driftTrainsRequiringReplan.set({ baseline_id: baselineId }, trainsRequiringReplan);

    // Update per-train mileage drift
    for (const analysis of analyses) {
      driftMileagePercent.set(
        { train_id: analysis.trainId, baseline_id: baselineId },
        analysis.mileageDriftPct
      );
    }

    this.log.debug(
      { trainsRequiringReplan, baselineId },
      'Updated drift metrics'
    );
  }
}

