   506→    });
   507→  }
   508→
   509→  /**
   510→   * Get a single reservation by ID
   511→   *
   512→   * @param id - Reservation ID
   513→   * @returns Reservation with details
   514→   * @throws NotFoundError if not found
   515→   */
   516→  async getReservationById(id: string): Promise<ReservationWithDetails> {
   517→    return this.traced('getReservationById', async (span) => {
   518→      span.setAttribute('reservation.id', id);
   519→
