   533→          fulfilledAt: materialReservations.fulfilledAt,
   534→          fulfilledQuantity: materialReservations.fulfilledQuantity,
   535→          pmTargetDate: pmSchedule.targetDate,
   536→          trainId: pmSchedule.trainId,
   537→          trainNumber: trains.trainNumber,
   538→          pmTypeId: pmSchedule.pmTypeId,
   539→          pmCode: pmTypes.pmCode,
   540→          depotId: pmSchedule.assignedDepotId,
   541→          depotCode: depots.code,
   542→          depotName: depots.name,
   543→          reservedByFirstName: users.firstName,
   544→          reservedByLastName: users.lastName,
   545→        })
   546→        .from(materialReservations)
   547→        .innerJoin(pmSchedule, eq(materialReservations.pmScheduleId, pmSchedule.id))
   548→        .innerJoin(pmTypes, eq(pmSchedule.pmTypeId, pmTypes.id))
   549→        .innerJoin(trains, eq(pmSchedule.trainId, trains.id))
   550→        .leftJoin(depots, eq(pmSchedule.assignedDepotId, depots.id))
   551→        .leftJoin(users, eq(materialReservations.reservedBy, users.id))
   552→        .where(eq(materialReservations.id, id))
   553→        .limit(1);
   554→
   555→      if (results.length === 0) {
   556→        throw new NotFoundError(`Reservation not found: ${id}`);
   557→      }
   558→
   559→      const row = results[0];
   560→
   561→      let status: ReservationStatus;
   562→      if (row.fulfilledAt) {
   563→        status = 'FULFILLED';
   564→      } else if (row.expiresAt && new Date(row.expiresAt) < now) {
   565→        status = 'EXPIRED';
   566→      } else {
   567→        status = 'PENDING';
   568→      }
   569→
   570→      return {
   571→        id: row.id,
   572→        pmScheduleId: row.pmScheduleId,
   573→        inventoryPositionId: row.inventoryPositionId,
   574→        partNumber: row.partNumber,
   575→        quantityReserved: row.quantityReserved,
   576→        reservationType: row.reservationType as 'SOFT' | 'HARD',
   577→        reservedAt: row.reservedAt?.toISOString() || '',
   578→        reservedBy: row.reservedBy,
   579→        reservedByName:
