   581→            ? `${row.reservedByFirstName} ${row.reservedByLastName}`
   582→            : null,
   583→        expiresAt: row.expiresAt?.toISOString() || null,
   584→        fulfilledAt: row.fulfilledAt?.toISOString() || null,
   585→        fulfilledQuantity: row.fulfilledQuantity,
   586→        status,
   587→        pm: {
