   146→/** Maximo work order response */
   147→export interface MaximoWorkOrder {
   148→  wonum: string;
   149→  status: MaximoWoStatus;
   150→  schedstart?: string;
   151→  schedfinish?: string;
   152→  actstart?: string;
   153→  actfinish?: string;
   154→  actlabhrs?: number;
