/**
 * MMS Maximo Sync Service
 *
 * Implements bidirectional synchronization between MMS and IBM Maximo CMMS.
 * Uses the shadow record pattern to enable offline operation and conflict resolution.
 *
 * Key responsibilities:
 * - Create and manage shadow records for PM schedules
 * - Push MMS changes to Maximo (create/update work orders)
 * - Pull Maximo status changes to MMS
 * - Detect and resolve conflicts
 * - Validate edit operations against Maximo status locks
 *
 * Integration flow:
 * 1. When a PM is scheduled in MMS, a shadow record is created (status: PENDING)
 * 2. Sync job pushes shadow records to Maximo (creates work orders)
 * 3. Maximo status changes (via polling or webhook) update shadow records
 * 4. INPRG/COMP/CLOSE/CAN status locks PM in MMS (read-only)
 *
 * @see specs/007-integration.md Section 7.4
 */

import { eq, and, desc, sql, inArray, lt, isNull, or, count, type SQL } from 'drizzle-orm';
import { addDays, addSeconds } from 'date-fns';
import { BaseService, MmsAttributes } from '../lib/services/base';
import {
  maximoShadowRecords,
  maximoSyncHistory,
  pmSchedule,
  type MaximoShadowRecord,
  type PmScheduleRecord,
} from '../lib/db/schema';
import {
  MaximoConnectionError,
  NotFoundError,
  ValidationError,
} from '../lib/errors';
import { CircuitBreaker } from '../lib/utils/resilience';
import { getMaximoClient, type MaximoClient } from './maximo-client';

// =============================================================================
// Types
// =============================================================================

/** Maximo work order status values */
export type MaximoWoStatus = 'WAPPR' | 'APPR' | 'INPRG' | 'COMP' | 'CLOSE' | 'CAN';

/** MMS sync status values */
export type SyncStatus = 'PENDING' | 'SYNCED' | 'CONFLICT' | 'ERROR';

/** Sync operation type */
export type SyncOperation = 'PUSH' | 'PULL' | 'CONFLICT_RESOLVE';

/** MMS PM status type */
export type MmsPmStatus = 'SCHEDULED' | 'IN_PROGRESS' | 'COMPLETED' | 'CANCELLED' | 'DEFERRED';

/** Status mapping from Maximo to MMS */
export const MAXIMO_TO_MMS_STATUS: Record<MaximoWoStatus, MmsPmStatus> = {
  WAPPR: 'SCHEDULED',
  APPR: 'SCHEDULED',
  INPRG: 'IN_PROGRESS',
  COMP: 'COMPLETED',
  CLOSE: 'COMPLETED',
  CAN: 'CANCELLED',
};

/** Locked Maximo statuses (PM cannot be edited in MMS) */
export const LOCKED_MAXIMO_STATUSES: MaximoWoStatus[] = ['INPRG', 'COMP', 'CLOSE', 'CAN'];

/** Human-readable status labels */
export const MAXIMO_STATUS_LABELS: Record<MaximoWoStatus, string> = {
  WAPPR: 'Waiting Approval',
  APPR: 'Approved',
  INPRG: 'In Progress',
  COMP: 'Completed',
  CLOSE: 'Closed',
  CAN: 'Cancelled',
};

/** Edit validation result */
export interface EditValidationResult {
  valid: boolean;
  reason?: 'MAXIMO_STATUS_LOCK' | 'SYNC_CONFLICT' | 'BASELINE_LOCK' | 'NOT_FOUND';
  message?: string;
  maximoStatus?: string;
  maximoWoNum?: string;
  suggestion?: string;
}

/** Push sync result */
export interface PushResult {
  action: 'CREATED' | 'UPDATED' | 'SKIPPED' | 'CONFLICT' | 'ERROR';
  woNum?: string;
  reason?: string;
  error?: string;
}

/** Pull sync result */
export interface PullResult {
  processed: number;
  updated: number;
  conflicts: number;
  errors: number;
  details: PullDetail[];
}

export interface PullDetail {
  pmScheduleId: string;
  maximoWoNum: string;
  previousStatus?: string;
  newStatus?: string;
  action: 'UPDATED' | 'CONFLICT' | 'ERROR' | 'SKIPPED';
  error?: string;
}

/** Conflict resolution strategy */
export type ConflictResolution = 'USE_MMS' | 'USE_MAXIMO';

/** Shadow record with related data */
export interface ShadowRecordWithPm {
  shadowRecord: MaximoShadowRecord;
  pmSchedule: PmScheduleRecord & {
    train?: { id: string; trainNumber: string };
    pmType?: { id: string; pmCode: string; pmName: string };
    depot?: { id: string; code: string };
  };
}

/** Maximo work order create payload */
export interface MaximoWorkOrderCreate {
  siteid: string;
  woclass: string;
  worktype: string;
  assetnum: string;
  description: string;
  schedstart: string;
  schedfinish: string;
  location?: string;
  estlabhrs?: number;
  pmnum?: string;
  mms_schedule_id: string;
  mms_constraint_start: string;
  mms_constraint_end: string;
}

/** Maximo work order response */
export interface MaximoWorkOrder {
  wonum: string;
  status: MaximoWoStatus;
  schedstart?: string;
  schedfinish?: string;
  actstart?: string;
  actfinish?: string;
  actlabhrs?: number;
  changedate?: string;
}

/** Sync statistics */
export interface SyncStats {
  pendingRecords: number;
  syncedRecords: number;
  conflictRecords: number;
  errorRecords: number;
  lastSyncAt?: Date;
  lastPullAt?: Date;
  circuitBreakerState: 'CLOSED' | 'OPEN' | 'HALF_OPEN';
}

/** Query filters for shadow records */
export interface ShadowRecordFilters {
  syncStatus?: SyncStatus | SyncStatus[];
  pmScheduleId?: string;
  maximoWoNum?: string;
  hasConflict?: boolean;
  needsSync?: boolean;
}

/** Pagination options */
export interface PaginationOptions {
  page?: number;
  pageSize?: number;
}

/** Paginated result */
export interface PaginatedShadowRecords {
  data: ShadowRecordWithPm[];
  total: number;
  page: number;
  pageSize: number;
  totalPages: number;
}

// =============================================================================
// Singleton instance
// =============================================================================

let instance: MaximoSyncService | null = null;

/**
 * Get the singleton MaximoSyncService instance
 */
export function getMaximoSyncService(): MaximoSyncService {
  if (!instance) {
    instance = new MaximoSyncService();
  }
  return instance;
}

// =============================================================================
// MaximoSyncService Implementation
// =============================================================================

/**
 * Maximo Sync Service for bidirectional PM synchronization
 *
 * Implements the shadow record pattern from spec 007.4.2:
 * - MMS is source of truth for scheduling
 * - Shadow records track sync state with Maximo
 * - Status-based locking prevents conflicts
 *
 * @example
 * ```typescript
 * const maximoSync = getMaximoSyncService();
 *
 * // Validate before editing a PM
 * const validation = await maximoSync.validateEdit(pmId);
 * if (!validation.valid) {
 *   throw new MaximoLockError(validation.message);
 * }
 *
 * // Create shadow record for new PM
 * await maximoSync.createShadowRecord(pmId);
 *
 * // Push changes to Maximo
 * const result = await maximoSync.pushToMaximo(pmId);
 *
 * // Pull status updates from Maximo
 * await maximoSync.pullFromMaximo();
 * ```
 */
export class MaximoSyncService extends BaseService {
  private readonly circuitBreaker: CircuitBreaker;
  private lastPullTimestamp: Date | null = null;
  private maximoClient: MaximoClient;
  private clientInitialized = false;

  constructor() {
    super({ name: 'maximo-sync-service' });

    // Initialize Maximo client
    this.maximoClient = getMaximoClient();

    // Circuit breaker for Maximo API calls
    this.circuitBreaker = new CircuitBreaker(
      {
        failureThreshold: 5,
        successThreshold: 2,
        resetTimeoutMs: 60000, // 60 seconds in open state
        isFailure: (error) => {
          // Only count network/availability errors as circuit breaker failures
          if (error instanceof MaximoConnectionError) return true;
          if (error instanceof Error) {
            const msg = error.message.toLowerCase();
            return (
              msg.includes('econnrefused') ||
              msg.includes('etimedout') ||
              msg.includes('econnreset') ||
              msg.includes('503') ||
              msg.includes('504')
            );
          }
          return false;
        },
      },
      'maximo-sync'
    );
  }

  /**
   * Ensure the Maximo client is initialized before making API calls
   */
  private async ensureClientInitialized(): Promise<void> {
    if (!this.clientInitialized) {
      await this.maximoClient.initialize();
      this.clientInitialized = true;
    }
  }

  // ===========================================================================
  // Edit Validation
  // ===========================================================================

  /**
   * Validate PM edit request against Maximo status
   *
   * MUST be called before any PM schedule modification.
   * Prevents race conditions where a planner reschedules a PM that
   * technicians are actively working on.
   *
   * @see specs/007-integration.md Section 7.4.6
   */
  async validateEdit(pmScheduleId: string): Promise<EditValidationResult> {
    return this.traced('validateEdit', async (span) => {
      span.setAttribute(MmsAttributes.PM_SCHEDULE_ID, pmScheduleId);

      // Get PM with shadow record
      const pm = await this.getPmWithShadow(pmScheduleId);

      if (!pm) {
        return {
          valid: false,
          reason: 'NOT_FOUND',
          message: 'PM schedule not found',
        };
      }

      // Check 1: Maximo status lock
      if (pm.shadowRecord?.maximoData) {
        const maximoData = pm.shadowRecord.maximoData as { status?: string };
        const maximoStatus = maximoData.status as MaximoWoStatus | undefined;

        if (maximoStatus && LOCKED_MAXIMO_STATUSES.includes(maximoStatus)) {
          span.setAttribute('maximo.status', maximoStatus);
          span.setAttribute('maximo.locked', true);

          return {
            valid: false,
            reason: 'MAXIMO_STATUS_LOCK',
            message: `Cannot modify: Work order is ${MAXIMO_STATUS_LABELS[maximoStatus]} in Maximo`,
            maximoStatus,
            maximoWoNum: pm.shadowRecord.maximoWoNum ?? undefined,
            suggestion:
              maximoStatus === 'INPRG'
                ? 'Wait for technicians to complete work, or contact supervisor to cancel in Maximo first'
                : 'This PM has been completed/cancelled. Create a new PM if rescheduling is needed.',
          };
        }
      }

      // Check 2: Pending sync conflict
      if (pm.shadowRecord?.syncStatus === 'CONFLICT') {
        span.setAttribute('sync.conflict', true);

        return {
          valid: false,
          reason: 'SYNC_CONFLICT',
          message: 'Unresolved sync conflict exists. Resolve before editing.',
          suggestion: 'Go to Integration > Conflicts to resolve',
        };
      }

      // Check 3: Baseline lock (if PM is locked)
      if (pm.pmSchedule.isLocked) {
        span.setAttribute('baseline.locked', true);

        return {
          valid: false,
          reason: 'BASELINE_LOCK',
          message: 'PM is locked in published baseline',
          suggestion: 'Unlock in baseline editor or create scenario to test changes',
        };
      }

      span.setAttribute('edit.valid', true);
      return { valid: true };
    });
  }

  /**
   * Check if a PM is locked by Maximo status
   */
  async isMaximoLocked(pmScheduleId: string): Promise<boolean> {
    const validation = await this.validateEdit(pmScheduleId);
    return validation.reason === 'MAXIMO_STATUS_LOCK';
  }

  // ===========================================================================
  // Shadow Record Management
  // ===========================================================================

  /**
   * Create a shadow record for a PM schedule
   *
   * Called when a new PM is scheduled or when sync is first enabled.
   */
  async createShadowRecord(pmScheduleId: string): Promise<MaximoShadowRecord> {
    return this.traced('createShadowRecord', async (span) => {
      span.setAttribute(MmsAttributes.PM_SCHEDULE_ID, pmScheduleId);

      // Verify PM exists
      const pm = await this.db.query.pmSchedule.findFirst({
        where: eq(pmSchedule.id, pmScheduleId),
        with: {
          train: true,
          pmType: true,
        },
      });

      if (!pm) {
        throw new NotFoundError(`PM schedule not found: ${pmScheduleId}`, {
          entityType: 'PmSchedule',
          entityId: pmScheduleId,
        });
      }

      // Check if shadow record already exists
      const existing = await this.db.query.maximoShadowRecords.findFirst({
        where: eq(maximoShadowRecords.pmScheduleId, pmScheduleId),
      });

      if (existing) {
        this.log.info(
          { pmScheduleId, shadowRecordId: existing.id },
          'Shadow record already exists'
        );
        return existing;
      }

      // Create MMS data snapshot
      const mmsDataSnapshot = {
        trainId: pm.trainId,
        pmTypeCode: pm.pmType?.pmCode ?? 'UNKNOWN',
        targetDate: pm.targetDate,
        status: pm.status ?? 'SCHEDULED',
        assignedDepotId: pm.assignedDepotId ?? undefined,
        assignedHours: pm.assignedHours ?? undefined,
      };

      // Insert shadow record
      const [shadowRecord] = await this.db
        .insert(maximoShadowRecords)
        .values({
          pmScheduleId,
          syncStatus: 'PENDING',
          mmsDataSnapshot,
          syncAttempts: 0,
          nextSyncAt: new Date(), // Sync immediately
        })
        .returning();

      span.setAttribute('shadow.record.id', shadowRecord.id);
      this.log.info(
        { pmScheduleId, shadowRecordId: shadowRecord.id },
        'Created shadow record for PM schedule'
      );

      return shadowRecord;
    });
  }

  /**
   * Get shadow record by PM schedule ID
   */
  async getShadowRecord(pmScheduleId: string): Promise<MaximoShadowRecord | null> {
    return this.traced('getShadowRecord', async () => {
      const record = await this.db.query.maximoShadowRecords.findFirst({
        where: eq(maximoShadowRecords.pmScheduleId, pmScheduleId),
      });
      return record ?? null;
    });
  }

  /**
   * Get PM with shadow record and related data
   */
  async getPmWithShadow(pmScheduleId: string): Promise<ShadowRecordWithPm | null> {
    return this.traced('getPmWithShadow', async () => {
      const pm = await this.db.query.pmSchedule.findFirst({
        where: eq(pmSchedule.id, pmScheduleId),
        with: {
          train: true,
          pmType: true,
          assignedDepot: true,
        },
      });

      if (!pm) {
        return null;
      }

      const shadowRecord = await this.db.query.maximoShadowRecords.findFirst({
        where: eq(maximoShadowRecords.pmScheduleId, pmScheduleId),
      });

      return {
        pmSchedule: {
          ...pm,
          train: pm.train ? { id: pm.train.id, trainNumber: pm.train.trainNumber } : undefined,
          pmType: pm.pmType
            ? { id: pm.pmType.id, pmCode: pm.pmType.pmCode, pmName: pm.pmType.pmName }
            : undefined,
          depot: pm.assignedDepot
            ? { id: pm.assignedDepot.id, code: pm.assignedDepot.code }
            : undefined,
        },
        shadowRecord: shadowRecord ?? ({} as MaximoShadowRecord),
      };
    });
  }

  /**
   * List shadow records with filters
   */
  async listShadowRecords(
    filters: ShadowRecordFilters = {},
    pagination: PaginationOptions = {}
  ): Promise<PaginatedShadowRecords> {
    return this.traced('listShadowRecords', async (span) => {
      const { page = 1, pageSize = 50 } = pagination;
      const offset = (page - 1) * pageSize;

      // Build where conditions
      const conditions: SQL<unknown>[] = [];

      if (filters.syncStatus) {
        const statuses = Array.isArray(filters.syncStatus)
          ? filters.syncStatus
          : [filters.syncStatus];
        conditions.push(inArray(maximoShadowRecords.syncStatus, statuses));
      }

      if (filters.pmScheduleId) {
        conditions.push(eq(maximoShadowRecords.pmScheduleId, filters.pmScheduleId));
      }

      if (filters.maximoWoNum) {
        conditions.push(eq(maximoShadowRecords.maximoWoNum, filters.maximoWoNum));
      }

      if (filters.hasConflict) {
        conditions.push(eq(maximoShadowRecords.syncStatus, 'CONFLICT'));
      }

      if (filters.needsSync) {
        const needsSyncCondition = or(
          eq(maximoShadowRecords.syncStatus, 'PENDING'),
          and(
            eq(maximoShadowRecords.syncStatus, 'ERROR'),
            lt(maximoShadowRecords.syncAttempts, 5)
          )
        );
        if (needsSyncCondition) {
          conditions.push(needsSyncCondition);
        }
      }

      const whereClause = conditions.length > 0 ? and(...conditions) : undefined;

      // Get total count
      const [{ value: total }] = await this.db
        .select({ value: count() })
        .from(maximoShadowRecords)
        .where(whereClause);

      // Get records
      const records = await this.db.query.maximoShadowRecords.findMany({
        where: whereClause,
        orderBy: [desc(maximoShadowRecords.updatedAt)],
        limit: pageSize,
        offset,
        with: {
          pmScheduleEntry: {
            with: {
              train: true,
              pmType: true,
              assignedDepot: true,
            },
          },
        },
      });

      // Transform to ShadowRecordWithPm
      const data: ShadowRecordWithPm[] = records.map((r) => ({
        shadowRecord: r,
        pmSchedule: {
          ...r.pmScheduleEntry,
          train: r.pmScheduleEntry.train
            ? {
                id: r.pmScheduleEntry.train.id,
                trainNumber: r.pmScheduleEntry.train.trainNumber,
              }
            : undefined,
          pmType: r.pmScheduleEntry.pmType
            ? {
                id: r.pmScheduleEntry.pmType.id,
                pmCode: r.pmScheduleEntry.pmType.pmCode,
                pmName: r.pmScheduleEntry.pmType.pmName,
              }
            : undefined,
          depot: r.pmScheduleEntry.assignedDepot
            ? {
                id: r.pmScheduleEntry.assignedDepot.id,
                code: r.pmScheduleEntry.assignedDepot.code,
              }
            : undefined,
        },
      }));

      span.setAttribute('query.total', total);
      span.setAttribute('query.returned', data.length);

      return {
        data,
        total,
        page,
        pageSize,
        totalPages: Math.ceil(total / pageSize),
      };
    });
  }

  // ===========================================================================
  // Push Sync (MMS → Maximo)
  // ===========================================================================

  /**
   * Push MMS changes to Maximo for a specific PM
   *
   * Creates or updates the Maximo work order based on shadow record state.
   *
   * @see specs/007-integration.md Section 7.4.7
   */
  async pushToMaximo(pmScheduleId: string): Promise<PushResult> {
    return this.traced('pushToMaximo', async (span) => {
      span.setAttribute(MmsAttributes.PM_SCHEDULE_ID, pmScheduleId);

      const pmWithShadow = await this.getPmWithShadow(pmScheduleId);

      if (!pmWithShadow) {
        return { action: 'ERROR', error: 'PM schedule not found' };
      }

      const { pmSchedule: pm, shadowRecord } = pmWithShadow;

      // Create shadow record if doesn't exist
      let shadow = shadowRecord;
      if (!shadow?.id) {
        shadow = await this.createShadowRecord(pmScheduleId);
      }

      // Check circuit breaker state
      if (this.circuitBreaker.getState() === 'OPEN') {
        this.log.warn({ pmScheduleId }, 'Circuit breaker is open, skipping push');
        return { action: 'SKIPPED', reason: 'Circuit breaker open' };
      }

      const syncAttempts = shadow.syncAttempts ?? 0;

      try {
        // No Maximo WO yet - create new
        if (!shadow.maximoWoNum) {
          // Use circuit breaker for Maximo API call
          const woNum = await this.circuitBreaker.execute(() =>
            this.createMaximoWorkOrder(pm)
          );

          await this.updateShadowRecord(shadow.id, {
            maximoWoNum: woNum,
            syncStatus: 'SYNCED',
            lastSyncAt: new Date(),
            lastSyncError: null,
            syncAttempts: syncAttempts + 1,
            mmsDataSnapshot: this.createMmsSnapshot(pm),
          });

          await this.recordSyncHistory(shadow.id, 'PUSH', {
            previousStatus: shadow.syncStatus,
            newStatus: 'SYNCED',
            success: true,
          });

          span.setAttribute('maximo.wo.created', woNum);

          return { action: 'CREATED', woNum };
        }

        // Check if Maximo WO is in locked state
        const maximoWo = await this.circuitBreaker.execute(() =>
          this.fetchMaximoWorkOrder(shadow.maximoWoNum!)
        );

        if (maximoWo && LOCKED_MAXIMO_STATUSES.includes(maximoWo.status)) {
          return {
            action: 'SKIPPED',
            reason: `Work order is ${MAXIMO_STATUS_LABELS[maximoWo.status]}`,
            woNum: shadow.maximoWoNum,
          };
        }

        // Check for conflicts
        if (maximoWo?.changedate && shadow.lastSyncAt) {
          const maximoChangeDate = new Date(maximoWo.changedate);
          if (maximoChangeDate > shadow.lastSyncAt) {
            await this.updateShadowRecord(shadow.id, {
              syncStatus: 'CONFLICT',
              maximoData: {
                status: maximoWo.status,
                schedStart: maximoWo.schedstart,
                schedFinish: maximoWo.schedfinish,
                actualStart: maximoWo.actstart,
                actualFinish: maximoWo.actfinish,
                actualLabor: maximoWo.actlabhrs,
                changeDate: maximoWo.changedate,
              },
            });

            await this.recordSyncHistory(shadow.id, 'PUSH', {
              previousStatus: shadow.syncStatus,
              newStatus: 'CONFLICT',
              success: false,
              errorMessage: 'Conflict detected - Maximo changed after last sync',
            });

            return { action: 'CONFLICT', woNum: shadow.maximoWoNum };
          }
        }

        // Update existing work order
        await this.circuitBreaker.execute(() =>
          this.updateMaximoWorkOrder(shadow.maximoWoNum!, pm)
        );

        await this.updateShadowRecord(shadow.id, {
          syncStatus: 'SYNCED',
          lastSyncAt: new Date(),
          lastSyncError: null,
          syncAttempts: syncAttempts + 1,
          mmsDataSnapshot: this.createMmsSnapshot(pm),
          pendingChanges: null,
        });

        await this.recordSyncHistory(shadow.id, 'PUSH', {
          previousStatus: shadow.syncStatus,
          newStatus: 'SYNCED',
          success: true,
        });

        span.setAttribute('maximo.wo.updated', shadow.maximoWoNum);

        return { action: 'UPDATED', woNum: shadow.maximoWoNum };
      } catch (error) {
        const errorMessage = error instanceof Error ? error.message : String(error);

        await this.updateShadowRecord(shadow.id, {
          syncStatus: 'ERROR',
          lastSyncError: errorMessage,
          syncAttempts: syncAttempts + 1,
          nextSyncAt: this.calculateNextRetry(syncAttempts + 1),
        });

        await this.recordSyncHistory(shadow.id, 'PUSH', {
          previousStatus: shadow.syncStatus,
          newStatus: 'ERROR',
          success: false,
          errorMessage,
        });

        span.setAttribute('error', true);
        span.setAttribute('error.message', errorMessage);

        return { action: 'ERROR', error: errorMessage };
      }
    });
  }

  /**
   * Push all pending changes to Maximo (batch sync)
   */
  async pushAllPending(): Promise<{ pushed: number; errors: number }> {
    return this.traced('pushAllPending', async (span) => {
      // Get all pending shadow records
      const pending = await this.db.query.maximoShadowRecords.findMany({
        where: or(
          eq(maximoShadowRecords.syncStatus, 'PENDING'),
          and(
            eq(maximoShadowRecords.syncStatus, 'ERROR'),
            lt(maximoShadowRecords.syncAttempts, 5),
            or(
              isNull(maximoShadowRecords.nextSyncAt),
              lt(maximoShadowRecords.nextSyncAt, new Date())
            )
          )
        ),
        limit: 100, // Process in batches
      });

      span.setAttribute('pending.count', pending.length);

      let pushed = 0;
      let errors = 0;

      for (const record of pending) {
        try {
          const result = await this.pushToMaximo(record.pmScheduleId);
          if (result.action === 'CREATED' || result.action === 'UPDATED') {
            pushed++;
          } else if (result.action === 'ERROR') {
            errors++;
          }
        } catch (error) {
          errors++;
          this.log.error(
            { pmScheduleId: record.pmScheduleId, error },
            'Failed to push to Maximo'
          );
        }
      }

      span.setAttribute('pushed.count', pushed);
      span.setAttribute('errors.count', errors);

      return { pushed, errors };
    });
  }

  // ===========================================================================
  // Pull Sync (Maximo → MMS)
  // ===========================================================================

  /**
   * Pull Maximo status changes to MMS
   *
   * Queries Maximo for work orders modified since last pull and updates
   * MMS PM statuses accordingly.
   *
   * @see specs/007-integration.md Section 7.4.7
   */
  async pullFromMaximo(): Promise<PullResult> {
    return this.traced('pullFromMaximo', async (span) => {
      const result: PullResult = {
        processed: 0,
        updated: 0,
        conflicts: 0,
        errors: 0,
        details: [],
      };

      // Check circuit breaker state
      if (this.circuitBreaker.getState() === 'OPEN') {
        this.log.warn('Circuit breaker is open, skipping pull');
        return result;
      }

      // Get all synced shadow records
      const syncedRecords = await this.db.query.maximoShadowRecords.findMany({
        where: and(
          eq(maximoShadowRecords.syncStatus, 'SYNCED'),
          sql`${maximoShadowRecords.maximoWoNum} IS NOT NULL`
        ),
      });

      span.setAttribute('synced.records', syncedRecords.length);

      for (const record of syncedRecords) {
        result.processed++;

        try {
          if (!record.maximoWoNum) continue;

          // Use circuit breaker for Maximo API call
          const maximoWo = await this.circuitBreaker.execute(() =>
            this.fetchMaximoWorkOrder(record.maximoWoNum!)
          );

          if (!maximoWo) {
            result.details.push({
              pmScheduleId: record.pmScheduleId,
              maximoWoNum: record.maximoWoNum,
              action: 'SKIPPED',
              error: 'Work order not found in Maximo',
            });
            continue;
          }

          const currentMaximoData = record.maximoData as { status?: string } | null;
          const previousStatus = currentMaximoData?.status;

          // Status changed
          if (maximoWo.status !== previousStatus) {
            await this.handleStatusChange(record, maximoWo);
            result.updated++;
            result.details.push({
              pmScheduleId: record.pmScheduleId,
              maximoWoNum: record.maximoWoNum,
              previousStatus,
              newStatus: maximoWo.status,
              action: 'UPDATED',
            });
          }

          // Record actuals if completed
          if (
            (maximoWo.status === 'COMP' || maximoWo.status === 'CLOSE') &&
            maximoWo.actlabhrs
          ) {
            await this.recordActuals(record.pmScheduleId, maximoWo);
          }
        } catch (error) {
          result.errors++;
          result.details.push({
            pmScheduleId: record.pmScheduleId,
            maximoWoNum: record.maximoWoNum ?? '',
            action: 'ERROR',
            error: error instanceof Error ? error.message : String(error),
          });
        }
      }

      this.lastPullTimestamp = new Date();
      span.setAttribute('pull.updated', result.updated);
      span.setAttribute('pull.errors', result.errors);

      return result;
    });
  }

  // ===========================================================================
  // Conflict Resolution
  // ===========================================================================

  /**
   * Resolve sync conflict
   *
   * @param pmScheduleId - PM schedule ID with conflict
   * @param resolution - Strategy: USE_MMS (force push) or USE_MAXIMO (apply Maximo data)
   * @param userId - User resolving the conflict
   */
  async resolveConflict(
    pmScheduleId: string,
    resolution: ConflictResolution,
    userId?: string
  ): Promise<void> {
    return this.traced('resolveConflict', async (span) => {
      span.setAttribute(MmsAttributes.PM_SCHEDULE_ID, pmScheduleId);
      span.setAttribute('resolution', resolution);

      const shadow = await this.db.query.maximoShadowRecords.findFirst({
        where: eq(maximoShadowRecords.pmScheduleId, pmScheduleId),
      });

      if (!shadow) {
        throw new NotFoundError(`Shadow record not found for PM: ${pmScheduleId}`, {
          entityType: 'MaximoShadowRecord',
          entityId: pmScheduleId,
        });
      }

      if (shadow.syncStatus !== 'CONFLICT') {
        throw new ValidationError('Shadow record is not in conflict state');
      }

      if (!shadow.maximoWoNum) {
        throw new ValidationError('Shadow record has no Maximo work order');
      }

      if (resolution === 'USE_MMS') {
        // Force push MMS data to Maximo
        const pm = await this.db.query.pmSchedule.findFirst({
          where: eq(pmSchedule.id, pmScheduleId),
          with: { train: true, pmType: true, assignedDepot: true },
        });

        if (!pm) {
          throw new NotFoundError(`PM schedule not found: ${pmScheduleId}`, {
            entityType: 'PmSchedule',
            entityId: pmScheduleId,
          });
        }

        await this.updateMaximoWorkOrder(shadow.maximoWoNum, pm, { force: true });
      } else {
        // Apply Maximo data to MMS
        const maximoWo = await this.fetchMaximoWorkOrder(shadow.maximoWoNum);

        if (!maximoWo) {
          throw new MaximoConnectionError('Failed to fetch Maximo work order');
        }

        await this.applyMaximoDataToMms(pmScheduleId, maximoWo);
      }

      // Update shadow record
      await this.updateShadowRecord(shadow.id, {
        syncStatus: 'SYNCED',
        lastSyncAt: new Date(),
        conflictResolvedAt: new Date(),
        conflictResolvedBy: userId ?? undefined,
        conflictResolution: resolution,
      });

      await this.recordSyncHistory(shadow.id, 'CONFLICT_RESOLVE', {
        previousStatus: 'CONFLICT',
        newStatus: 'SYNCED',
        success: true,
      });

      this.log.info(
        { pmScheduleId, resolution, userId },
        'Conflict resolved'
      );
    });
  }

  /**
   * Get all records with conflicts
   */
  async getConflicts(): Promise<ShadowRecordWithPm[]> {
    const result = await this.listShadowRecords({ syncStatus: 'CONFLICT' });
    return result.data;
  }

  // ===========================================================================
  // Statistics
  // ===========================================================================

  /**
   * Get sync statistics
   */
  async getSyncStats(): Promise<SyncStats> {
    return this.traced('getSyncStats', async () => {
      const stats = await this.db
        .select({
          status: maximoShadowRecords.syncStatus,
          count: count(),
        })
        .from(maximoShadowRecords)
        .groupBy(maximoShadowRecords.syncStatus);

      const statusCounts = stats.reduce(
        (acc, s) => {
          acc[s.status] = s.count;
          return acc;
        },
        {} as Record<string, number>
      );

      // Get last sync timestamp
      const lastSync = await this.db.query.maximoShadowRecords.findFirst({
        where: eq(maximoShadowRecords.syncStatus, 'SYNCED'),
        orderBy: [desc(maximoShadowRecords.lastSyncAt)],
      });

      return {
        pendingRecords: statusCounts['PENDING'] ?? 0,
        syncedRecords: statusCounts['SYNCED'] ?? 0,
        conflictRecords: statusCounts['CONFLICT'] ?? 0,
        errorRecords: statusCounts['ERROR'] ?? 0,
        lastSyncAt: lastSync?.lastSyncAt ?? undefined,
        lastPullAt: this.lastPullTimestamp ?? undefined,
        circuitBreakerState: this.circuitBreaker.getState(),
      };
    });
  }

  // ===========================================================================
  // Private Methods - Maximo API Integration
  // ===========================================================================

  /**
   * Create a Maximo work order via REST API
   *
   * Uses MaximoClient for actual API calls. Falls back to simulation
   * if client is not configured (no MAXIMO_API_PASSWORD or config).
   *
   * @see specs/007-integration.md Section 7.4.4
   */
  private async createMaximoWorkOrder(
    pm: PmScheduleRecord & {
      train?: { id: string; trainNumber: string };
      pmType?: { id: string; pmCode: string; pmName: string };
      depot?: { id: string; code: string };
    }
  ): Promise<string> {
    return this.traced('createMaximoWorkOrder', async (span) => {
      await this.ensureClientInitialized();

      span.setAttribute('train.number', pm.train?.trainNumber ?? 'unknown');
      span.setAttribute('pm.code', pm.pmType?.pmCode ?? 'unknown');
      span.setAttribute('maximo.configured', this.maximoClient.isConfigured());

      const payload = {
        siteid: 'METRO',
        woclass: 'WORKORDER',
        worktype: 'PM',
        assetnum: pm.train?.trainNumber ?? '',
        description: `${pm.pmType?.pmCode ?? 'PM'} - ${pm.pmType?.pmName ?? 'Maintenance'}`,
        schedstart: pm.targetDate,
        schedfinish: addDays(new Date(pm.targetDate), 1).toISOString(),
        location: pm.depot?.code,
        estlabhrs: pm.assignedHours ? parseFloat(pm.assignedHours) : undefined,
        pmnum: pm.pmType?.pmCode,
        mms_schedule_id: pm.id,
        mms_constraint_start: pm.constraintStart ?? pm.targetDate,
        mms_constraint_end: pm.constraintEnd ?? addDays(new Date(pm.targetDate), 30).toISOString(),
      };

      const woNum = await this.maximoClient.createWorkOrder(payload);

      span.setAttribute('maximo.wo.num', woNum);
      this.log.info(
        {
          woNum,
          pmScheduleId: pm.id,
          trainNumber: pm.train?.trainNumber,
          pmCode: pm.pmType?.pmCode,
          configured: this.maximoClient.isConfigured(),
        },
        this.maximoClient.isConfigured()
          ? 'Created Maximo work order'
          : 'Created Maximo work order (simulated)'
      );

      return woNum;
    });
  }

  /**
   * Update a Maximo work order via REST API
   */
  private async updateMaximoWorkOrder(
    woNum: string,
    pm: PmScheduleRecord & {
      train?: { id: string; trainNumber: string };
      pmType?: { id: string; pmCode: string; pmName: string };
      depot?: { id: string; code: string };
    },
    options?: { force?: boolean }
  ): Promise<void> {
    return this.traced('updateMaximoWorkOrder', async (span) => {
      await this.ensureClientInitialized();

      span.setAttribute('maximo.wo.num', woNum);
      span.setAttribute('force', options?.force ?? false);

      const payload = {
        schedstart: pm.targetDate,
        schedfinish: addDays(new Date(pm.targetDate), 1).toISOString(),
        location: pm.depot?.code,
        estlabhrs: pm.assignedHours ? parseFloat(pm.assignedHours) : undefined,
      };

      await this.maximoClient.updateWorkOrder(woNum, payload, options);

      this.log.info(
        {
          woNum,
          pmScheduleId: pm.id,
          targetDate: pm.targetDate,
          force: options?.force,
          configured: this.maximoClient.isConfigured(),
        },
        this.maximoClient.isConfigured()
          ? 'Updated Maximo work order'
          : 'Updated Maximo work order (simulated)'
      );
    });
  }

  /**
   * Fetch a Maximo work order via REST API
   */
  private async fetchMaximoWorkOrder(woNum: string): Promise<MaximoWorkOrder | null> {
    return this.traced('fetchMaximoWorkOrder', async (span) => {
      await this.ensureClientInitialized();

      span.setAttribute('maximo.wo.num', woNum);

      const wo = await this.maximoClient.getWorkOrder(woNum);

      if (!wo) {
        return null;
      }

      // Convert MaximoClientWorkOrder to local MaximoWorkOrder type
      return {
        wonum: wo.wonum,
        status: wo.status,
        schedstart: wo.schedstart,
        schedfinish: wo.schedfinish,
        actstart: wo.actstart,
        actfinish: wo.actfinish,
        actlabhrs: wo.actlabhrs,
        changedate: wo.changedate,
      };
    });
  }

  // ===========================================================================
  // Private Helper Methods
  // ===========================================================================

  private async updateShadowRecord(
    shadowRecordId: string,
    updates: Partial<{
      maximoWoNum: string;
      syncStatus: SyncStatus;
      lastSyncAt: Date;
      lastSyncError: string | null;
      syncAttempts: number;
      nextSyncAt: Date;
      mmsDataSnapshot: {
        trainId: string;
        pmTypeCode: string;
        targetDate: string;
        status: string;
        assignedDepotId?: string;
        assignedHours?: string;
      };
      maximoData: {
        status: string;
        schedStart?: string;
        schedFinish?: string;
        actualStart?: string;
        actualFinish?: string;
        actualLabor?: number;
        changeDate?: string;
      };
      pendingChanges: {
        targetDate?: string;
        assignedDepotId?: string;
        assignedHours?: number;
      } | null;
      conflictResolvedAt: Date;
      conflictResolvedBy: string;
      conflictResolution: string;
    }>
  ): Promise<void> {
    await this.db
      .update(maximoShadowRecords)
      .set({
        ...updates,
        updatedAt: new Date(),
      })
      .where(eq(maximoShadowRecords.id, shadowRecordId));
  }

  private async recordSyncHistory(
    shadowRecordId: string,
    operation: SyncOperation,
    details: {
      previousStatus?: SyncStatus | null;
      newStatus?: SyncStatus;
      maximoStatus?: MaximoWoStatus;
      success: boolean;
      errorCode?: string;
      errorMessage?: string;
      requestData?: object;
      responseData?: object;
    }
  ): Promise<void> {
    const startedAt = new Date();

    await this.db.insert(maximoSyncHistory).values({
      shadowRecordId,
      operation,
      previousStatus: details.previousStatus ?? undefined,
      newStatus: details.newStatus,
      maximoStatus: details.maximoStatus,
      success: details.success,
      errorCode: details.errorCode,
      errorMessage: details.errorMessage,
      requestData: details.requestData,
      responseData: details.responseData,
      startedAt,
      completedAt: new Date(),
      durationMs: Date.now() - startedAt.getTime(),
      triggeredBy: 'SCHEDULER',
    });
  }

  private createMmsSnapshot(
    pm: PmScheduleRecord & {
      train?: { id: string; trainNumber: string };
      pmType?: { id: string; pmCode: string; pmName: string };
    }
  ): {
    trainId: string;
    pmTypeCode: string;
    targetDate: string;
    status: string;
    assignedDepotId?: string;
    assignedHours?: string;
  } {
    return {
      trainId: pm.trainId,
      pmTypeCode: pm.pmType?.pmCode ?? 'UNKNOWN',
      targetDate: pm.targetDate,
      status: pm.status ?? 'SCHEDULED',
      assignedDepotId: pm.assignedDepotId ?? undefined,
      assignedHours: pm.assignedHours ?? undefined,
    };
  }

  private calculateNextRetry(attempts: number): Date {
    // Exponential backoff with max delay
    const initialDelayMs = 1000;
    const backoffMultiplier = 2;
    const maxDelayMs = 60000;

    const delay = Math.min(
      initialDelayMs * Math.pow(backoffMultiplier, attempts - 1),
      maxDelayMs
    );
    return addSeconds(new Date(), delay / 1000);
  }

  private async handleStatusChange(
    shadowRecord: MaximoShadowRecord,
    maximoWo: MaximoWorkOrder
  ): Promise<void> {
    // Update shadow record with new Maximo data
    await this.updateShadowRecord(shadowRecord.id, {
      maximoData: {
        status: maximoWo.status,
        schedStart: maximoWo.schedstart,
        schedFinish: maximoWo.schedfinish,
        actualStart: maximoWo.actstart,
        actualFinish: maximoWo.actfinish,
        actualLabor: maximoWo.actlabhrs,
        changeDate: maximoWo.changedate,
      },
    });

    // Update MMS PM status based on Maximo status
    const mmsStatus = MAXIMO_TO_MMS_STATUS[maximoWo.status];

    await this.db
      .update(pmSchedule)
      .set({
        status: mmsStatus,
        updatedAt: new Date(),
        // Lock PM if Maximo status is in progress or completed
        isLocked: LOCKED_MAXIMO_STATUSES.includes(maximoWo.status),
        lockedReason: LOCKED_MAXIMO_STATUSES.includes(maximoWo.status)
          ? `Maximo status: ${MAXIMO_STATUS_LABELS[maximoWo.status]}`
          : undefined,
      })
      .where(eq(pmSchedule.id, shadowRecord.pmScheduleId));

    await this.recordSyncHistory(shadowRecord.id, 'PULL', {
      previousStatus: shadowRecord.syncStatus,
      newStatus: 'SYNCED',
      maximoStatus: maximoWo.status,
      success: true,
    });
  }

  private async recordActuals(
    pmScheduleId: string,
    maximoWo: MaximoWorkOrder
  ): Promise<void> {
    const updates: Partial<PmScheduleRecord> = {
      updatedAt: new Date(),
    };

    if (maximoWo.actlabhrs) {
      updates.actualHours = String(maximoWo.actlabhrs);
    }

    if (maximoWo.actstart) {
      updates.actualStartDate = maximoWo.actstart;
    }

    if (maximoWo.actfinish) {
      updates.actualEndDate = maximoWo.actfinish;
      updates.completedAt = new Date(maximoWo.actfinish);
    }

    await this.db
      .update(pmSchedule)
      .set(updates)
      .where(eq(pmSchedule.id, pmScheduleId));
  }

  private async applyMaximoDataToMms(
    pmScheduleId: string,
    maximoWo: MaximoWorkOrder
  ): Promise<void> {
    const updates: Partial<PmScheduleRecord> = {
      status: MAXIMO_TO_MMS_STATUS[maximoWo.status],
      updatedAt: new Date(),
    };

    if (maximoWo.schedstart) {
      updates.targetDate = maximoWo.schedstart.split('T')[0];
    }

    if (maximoWo.actlabhrs) {
      updates.actualHours = String(maximoWo.actlabhrs);
    }

    if (maximoWo.actstart) {
      updates.actualStartDate = maximoWo.actstart;
    }

    if (maximoWo.actfinish) {
      updates.actualEndDate = maximoWo.actfinish;
      updates.completedAt = new Date(maximoWo.actfinish);
    }

    // Lock if in locked status
    if (LOCKED_MAXIMO_STATUSES.includes(maximoWo.status)) {
      updates.isLocked = true;
      updates.lockedReason = `Maximo status: ${MAXIMO_STATUS_LABELS[maximoWo.status]}`;
    }

    await this.db
      .update(pmSchedule)
      .set(updates)
      .where(eq(pmSchedule.id, pmScheduleId));
  }
}

