   574→  ): Promise<ManhourAdjustment> {
   575→    return this.inTransaction('rejectAdjustment', async (tx, span) => {
   576→      span.setAttribute('adjustmentId', adjustmentId);
   577→      span.setAttribute('userId', userId);
   578→
   579→      // Get adjustment
   580→      const adjustment = await tx.query.manhourAdjustments.findFirst({
   581→        where: eq(manhourAdjustments.id, adjustmentId),
   582→      });
   583→
   584→      if (!adjustment) {
   585→        throw new NotFoundError(`Adjustment ${adjustmentId} not found`);
   586→      }
   587→
   588→      if (adjustment.status !== 'PROPOSED') {
   589→        throw new ConflictError(
   590→          `Cannot reject adjustment in ${adjustment.status} status`,
   591→          { errorCode: 'ADJUSTMENT_STATUS_INVALID', currentStatus: adjustment.status }
   592→        );
   593→      }
   594→
   595→      // Update status
   596→      const [updated] = await tx
   597→        .update(manhourAdjustments)
   598→        .set({
   599→          status: 'REJECTED',
   600→          approvedBy: userId,
   601→          approvedAt: new Date(),
   602→          rejectionReason: reason,
   603→        })
   604→        .where(eq(manhourAdjustments.id, adjustmentId))
   605→        .returning();
   606→
   607→      this.log.info(
   608→        { adjustmentId, userId, type: adjustment.adjustmentType, reason },
   609→        'Adjustment rejected'
   610→      );
   611→
   612→      return updated;
   613→    });
   614→  }
   615→
   616→  // ===========================================================================
   617→  // Capacity Management
   618→  // ===========================================================================
   619→
   620→  /**
   621→   * Get capacity configuration for a depot
   622→   */
   623→  async getCapacity(depotId: string, asOfDate?: Date): Promise<ManhourCapacity | null> {
   624→    return this.traced('getCapacity', async (span) => {
   625→      span.setAttribute('mms.depot.id', depotId);
   626→
   627→      const dateStr = format(asOfDate ?? new Date(), 'yyyy-MM-dd');
   628→
   629→      const capacity = await this.db.query.manhourCapacity.findFirst({
   630→        where: and(
   631→          eq(manhourCapacity.depotId, depotId),
   632→          lte(manhourCapacity.effectiveFrom, dateStr),
   633→          or(isNull(manhourCapacity.effectiveTo), gte(manhourCapacity.effectiveTo, dateStr))
   634→        ),
   635→        orderBy: [desc(manhourCapacity.effectiveFrom)],
   636→      });
   637→
   638→      return capacity ?? null;
