   790→  private async resolveDepotIds(requestedIds?: string[]): Promise<string[]> {
   791→    if (requestedIds && requestedIds.length > 0) {
   792→      return requestedIds;
   793→    }
   794→
   795→    // Get all active depots
   796→    const allDepots = await this.db.query.depots.findMany({
