   954→  /**
   955→   * Identify overloaded and underutilized weeks
   956→   */
   957→  private identifyImbalances(projections: ProjectionData[]): {
   958→    overloaded: ProjectionData[];
   959→    underutilized: ProjectionData[];
   960→  } {
   961→    return {
   962→      overloaded: projections.filter((p) => p.isOverloaded),
