/**
 * Export Service
 *
 * Manages export jobs for PM schedules (Excel) and reports (PDF).
 * Uses BullMQ for async job processing with status tracking.
 *
 * Key features:
 * - Queue Excel exports with filters and column selection
 * - Queue PDF report generation with templates
 * - Track job status and provide download URLs
 * - Automatic file cleanup after expiration
 *
 * @see specs/005-api.md Section 5.15
 */

import { addJob, getJob, QUEUE_NAMES, type ReportJobData } from '../lib/queue';
import { logger } from '../lib/logging/logger';
import { withSpan } from '../lib/tracing';
import { ValidationError, NotFoundError } from '../lib/errors';
import { v4 as uuid } from 'uuid';

// =============================================================================
// Types
// =============================================================================

/**
 * Export format types
 */
export type ExportFormat = 'xlsx' | 'csv' | 'pdf';

/**
 * Export job status
 */
export type ExportJobStatus = 'QUEUED' | 'PROCESSING' | 'COMPLETED' | 'FAILED' | 'EXPIRED';

/**
 * PM schedule export request
 */
export interface PmScheduleExportRequest {
  format: 'xlsx' | 'csv';
  filters?: {
    depotId?: string;
    fleetId?: string;
    trainId?: string;
    fromDate?: string;
    toDate?: string;
    status?: string[];
    pmTypeId?: string;
    scenarioId?: string;
  };
  columns?: string[];
  requestedBy: string;
}

/**
 * Report type for PDF generation
 */
export type ReportType =
  | 'WEEKLY_COMPLIANCE'
  | 'MONTHLY_SUMMARY'
  | 'FLEET_STATUS'
  | 'DRIFT_REPORT'
  | 'TCO_PROJECTION'
  | 'BOW_WAVE_ANALYSIS'
  | 'MANHOUR_UTILIZATION';

/**
 * Report export request
 */
export interface ReportExportRequest {
  reportType: ReportType;
  parameters: Record<string, unknown>;
  requestedBy: string;
}

/**
 * Export job metadata stored in-memory (would be in DB in production)
 */
interface ExportJobMeta {
  id: string;
  type: 'pm_schedule' | 'report';
  status: ExportJobStatus;
  format: ExportFormat;
  createdAt: Date;
  startedAt?: Date;
  completedAt?: Date;
  estimatedSizeBytes?: number;
  fileSizeBytes?: number;
  downloadUrl?: string;
  expiresAt?: Date;
  errorMessage?: string;
  requestedBy: string;
  filters?: Record<string, unknown>;
  reportType?: ReportType;
}

// =============================================================================
// In-Memory Storage (would be database in production)
// =============================================================================

/**
 * Export job metadata storage
 * In production, this would be stored in the database
 */
const exportJobs: Map<string, ExportJobMeta> = new Map();

/**
 * Default column list for PM schedule exports
 */
const DEFAULT_PM_SCHEDULE_COLUMNS = [
  'trainNumber',
  'fleetCode',
  'pmCode',
  'targetDate',
  'status',
  'constraintStart',
  'constraintEnd',
  'assignedTrack',
  'assignedDepot',
  'estimatedHours',
  'notes',
];

/**
 * Valid column names for PM schedule exports
 */
const VALID_PM_SCHEDULE_COLUMNS = new Set([
  'id',
  'trainId',
  'trainNumber',
  'fleetCode',
  'pmCode',
  'pmTypeId',
  'targetDate',
  'status',
  'constraintStart',
  'constraintEnd',
  'assignedTrack',
  'assignedDepot',
  'estimatedHours',
  'actualHours',
  'completedDate',
  'completedMileageKm',
  'notes',
  'isLocked',
  'maximoWoId',
  'createdAt',
  'updatedAt',
]);

// =============================================================================
// Service Implementation
// =============================================================================

/**
 * Queue a PM schedule export job
 *
 * @param request - Export request with format, filters, and columns
 * @returns Job metadata including ID and estimated size
 */
export async function queuePmScheduleExport(
  request: PmScheduleExportRequest
): Promise<{ jobId: string; status: ExportJobStatus; estimatedSizeBytes: number }> {
  return withSpan('export.queuePmScheduleExport', async (span) => {
    // Validate format
    if (!['xlsx', 'csv'].includes(request.format)) {
      throw new ValidationError(`Invalid export format: ${request.format}`, {
        field: 'format',
        context: {
          expected: ['xlsx', 'csv'],
          received: request.format,
        },
      });
    }

    // Validate columns if provided
    const columns = request.columns ?? DEFAULT_PM_SCHEDULE_COLUMNS;
    const invalidColumns = columns.filter((col) => !VALID_PM_SCHEDULE_COLUMNS.has(col));
    if (invalidColumns.length > 0) {
      throw new ValidationError(`Invalid column names: ${invalidColumns.join(', ')}`, {
        field: 'columns',
        context: {
          invalidColumns,
          validColumns: Array.from(VALID_PM_SCHEDULE_COLUMNS),
        },
      });
    }

    // Generate job ID
    const jobId = `export-${uuid()}`;

    // Estimate file size based on filters
    const estimatedSizeBytes = estimateExportSize(request.filters, columns.length, request.format);

    // Create job metadata
    const jobMeta: ExportJobMeta = {
      id: jobId,
      type: 'pm_schedule',
      status: 'QUEUED',
      format: request.format,
      createdAt: new Date(),
      estimatedSizeBytes,
      requestedBy: request.requestedBy,
      filters: request.filters,
    };
    exportJobs.set(jobId, jobMeta);

    // Queue the job
    const jobData: ReportJobData = {
      type: 'pm_schedule',
      format: request.format === 'xlsx' ? 'excel' : 'pdf',
      filters: {
        ...request.filters,
        columns,
        exportJobId: jobId,
      },
      requestedBy: request.requestedBy,
    };

    await addJob(QUEUE_NAMES.REPORT, 'pm-schedule-export', jobData);

    span?.setAttribute('export.jobId', jobId);
    span?.setAttribute('export.format', request.format);
    span?.setAttribute('export.estimatedSize', estimatedSizeBytes);

    logger.info(
      { jobId, format: request.format, filters: request.filters },
      'PM schedule export job queued'
    );

    return {
      jobId,
      status: 'QUEUED' as ExportJobStatus,
      estimatedSizeBytes,
    };
  });
}

/**
 * Queue a report generation job
 *
 * @param request - Report request with type and parameters
 * @returns Job metadata including ID and status
 */
export async function queueReportExport(
  request: ReportExportRequest
): Promise<{ jobId: string; status: ExportJobStatus; estimatedSizeBytes: number }> {
  return withSpan('export.queueReportExport', async (span) => {
    // Validate report type
    const validTypes: ReportType[] = [
      'WEEKLY_COMPLIANCE',
      'MONTHLY_SUMMARY',
      'FLEET_STATUS',
      'DRIFT_REPORT',
      'TCO_PROJECTION',
      'BOW_WAVE_ANALYSIS',
      'MANHOUR_UTILIZATION',
    ];

    if (!validTypes.includes(request.reportType)) {
      throw new ValidationError(`Invalid report type: ${request.reportType}`, {
        field: 'reportType',
        context: {
          expected: validTypes,
          received: request.reportType,
        },
      });
    }

    // Generate job ID
    const jobId = `report-${uuid()}`;

    // Estimate PDF size based on report type
    const estimatedSizeBytes = estimateReportSize(request.reportType);

    // Create job metadata
    const jobMeta: ExportJobMeta = {
      id: jobId,
      type: 'report',
      status: 'QUEUED',
      format: 'pdf',
      createdAt: new Date(),
      estimatedSizeBytes,
      requestedBy: request.requestedBy,
      reportType: request.reportType,
      filters: request.parameters,
    };
    exportJobs.set(jobId, jobMeta);

    // Queue the job
    const jobData: ReportJobData = {
      type: mapReportTypeToJobType(request.reportType),
      format: 'pdf',
      filters: {
        ...request.parameters,
        exportJobId: jobId,
        reportType: request.reportType,
      },
      requestedBy: request.requestedBy,
    };

    await addJob(QUEUE_NAMES.REPORT, 'report-generation', jobData);

    span?.setAttribute('export.jobId', jobId);
    span?.setAttribute('export.reportType', request.reportType);

    logger.info(
      { jobId, reportType: request.reportType, parameters: request.parameters },
      'Report generation job queued'
    );

    return {
      jobId,
      status: 'QUEUED' as ExportJobStatus,
      estimatedSizeBytes,
    };
  });
}

/**
 * Get export job status
 *
 * @param jobId - Export job ID
 * @returns Job status and download URL if completed
 */
export async function getExportJobStatus(jobId: string): Promise<{
  jobId: string;
  status: ExportJobStatus;
  downloadUrl?: string;
  expiresAt?: string;
  fileSizeBytes?: number;
  errorMessage?: string;
  progress?: number;
}> {
  return withSpan('export.getJobStatus', async (span) => {
    span?.setAttribute('export.jobId', jobId);

    // Check in-memory storage first
    const jobMeta = exportJobs.get(jobId);
    if (!jobMeta) {
      throw new NotFoundError(`Export job not found: ${jobId}`, {
        entityType: 'exportJob',
        entityId: jobId,
      });
    }

    // Check BullMQ job status for progress updates
    const queueJob = await getJob(QUEUE_NAMES.REPORT, jobId);
    let progress: number | undefined;

    if (queueJob) {
      // Update status from queue if job is still processing
      if (queueJob.status === 'active') {
        jobMeta.status = 'PROCESSING';
        if (!jobMeta.startedAt) {
          jobMeta.startedAt = new Date();
        }
      } else if (queueJob.status === 'completed' && jobMeta.status !== 'COMPLETED') {
        jobMeta.status = 'COMPLETED';
        jobMeta.completedAt = new Date();
        // In production, the worker would set the download URL
        if (!jobMeta.downloadUrl) {
          jobMeta.downloadUrl = generateDownloadUrl(jobId, jobMeta.format);
          jobMeta.expiresAt = new Date(Date.now() + 24 * 60 * 60 * 1000); // 24 hours
          jobMeta.fileSizeBytes = jobMeta.estimatedSizeBytes;
        }
      } else if (queueJob.status === 'failed') {
        jobMeta.status = 'FAILED';
        jobMeta.errorMessage = 'Export job failed';
      }
    }

    // Check expiration
    if (jobMeta.expiresAt && new Date() > jobMeta.expiresAt) {
      jobMeta.status = 'EXPIRED';
      jobMeta.downloadUrl = undefined;
    }

    logger.debug({ jobId, status: jobMeta.status }, 'Export job status retrieved');

    return {
      jobId: jobMeta.id,
      status: jobMeta.status,
      downloadUrl: jobMeta.downloadUrl,
      expiresAt: jobMeta.expiresAt?.toISOString(),
      fileSizeBytes: jobMeta.fileSizeBytes,
      errorMessage: jobMeta.errorMessage,
      progress,
    };
  });
}

/**
 * Update export job status (called by worker)
 *
 * @param jobId - Export job ID
 * @param update - Status update
 */
export function updateExportJobStatus(
  jobId: string,
  update: {
    status?: ExportJobStatus;
    downloadUrl?: string;
    fileSizeBytes?: number;
    errorMessage?: string;
  }
): void {
  const jobMeta = exportJobs.get(jobId);
  if (!jobMeta) {
    logger.warn({ jobId }, 'Attempted to update non-existent export job');
    return;
  }

  if (update.status) {
    jobMeta.status = update.status;
    if (update.status === 'PROCESSING' && !jobMeta.startedAt) {
      jobMeta.startedAt = new Date();
    } else if (update.status === 'COMPLETED') {
      jobMeta.completedAt = new Date();
      jobMeta.expiresAt = new Date(Date.now() + 24 * 60 * 60 * 1000); // 24 hours
    }
  }

  if (update.downloadUrl) {
    jobMeta.downloadUrl = update.downloadUrl;
  }

  if (update.fileSizeBytes) {
    jobMeta.fileSizeBytes = update.fileSizeBytes;
  }

  if (update.errorMessage) {
    jobMeta.errorMessage = update.errorMessage;
  }

  exportJobs.set(jobId, jobMeta);
  logger.debug({ jobId, update }, 'Export job status updated');
}

/**
 * List export jobs for a user
 *
 * @param userId - User ID to filter by
 * @param options - Pagination and filter options
 * @returns List of export jobs
 */
export function listExportJobs(
  userId: string,
  options: {
    page?: number;
    pageSize?: number;
    status?: ExportJobStatus[];
    type?: 'pm_schedule' | 'report';
  } = {}
): { jobs: ExportJobMeta[]; total: number } {
  const { page = 1, pageSize = 20, status, type } = options;

  let jobs = Array.from(exportJobs.values()).filter((job) => job.requestedBy === userId);

  if (status && status.length > 0) {
    jobs = jobs.filter((job) => status.includes(job.status));
  }

  if (type) {
    jobs = jobs.filter((job) => job.type === type);
  }

  // Sort by creation date descending
  jobs.sort((a, b) => b.createdAt.getTime() - a.createdAt.getTime());

  const total = jobs.length;
  const offset = (page - 1) * pageSize;
  const paginatedJobs = jobs.slice(offset, offset + pageSize);

  return { jobs: paginatedJobs, total };
}

/**
 * Clean up expired export jobs
 */
export function cleanupExpiredExports(): number {
  const now = new Date();
  let cleanedCount = 0;

  for (const [jobId, jobMeta] of exportJobs.entries()) {
    // Remove jobs older than 7 days regardless of status
    const sevenDaysAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
    if (jobMeta.createdAt < sevenDaysAgo) {
      exportJobs.delete(jobId);
      cleanedCount++;
      continue;
    }

    // Mark expired completed jobs
    if (jobMeta.status === 'COMPLETED' && jobMeta.expiresAt && now > jobMeta.expiresAt) {
      jobMeta.status = 'EXPIRED';
      jobMeta.downloadUrl = undefined;
    }
  }

  if (cleanedCount > 0) {
    logger.info({ cleanedCount }, 'Cleaned up expired export jobs');
  }

  return cleanedCount;
}

// =============================================================================
// Helper Functions
// =============================================================================

/**
 * Estimate export file size based on filters
 */
function estimateExportSize(
  filters: PmScheduleExportRequest['filters'],
  columnCount: number,
  format: 'xlsx' | 'csv'
): number {
  // Base estimate: 100 rows with average data
  let estimatedRows = 1000;

  // Reduce estimate if date range is narrow
  if (filters?.fromDate && filters?.toDate) {
    const from = new Date(filters.fromDate);
    const to = new Date(filters.toDate);
    const days = Math.ceil((to.getTime() - from.getTime()) / (1000 * 60 * 60 * 24));
    estimatedRows = Math.min(estimatedRows, days * 5); // ~5 PMs per day
  }

  // Reduce if filtering by single train
  if (filters?.trainId) {
    estimatedRows = Math.min(estimatedRows, 50);
  }

  // Bytes per row depends on format and columns
  const bytesPerRow = format === 'xlsx' ? columnCount * 50 : columnCount * 30;

  // Add overhead for headers and format structure
  const overhead = format === 'xlsx' ? 10000 : 500;

  return estimatedRows * bytesPerRow + overhead;
}

/**
 * Estimate report file size based on type
 */
function estimateReportSize(reportType: ReportType): number {
  const estimates: Record<ReportType, number> = {
    WEEKLY_COMPLIANCE: 150000, // 150KB
    MONTHLY_SUMMARY: 300000, // 300KB
    FLEET_STATUS: 200000, // 200KB
    DRIFT_REPORT: 250000, // 250KB
    TCO_PROJECTION: 500000, // 500KB
    BOW_WAVE_ANALYSIS: 400000, // 400KB
    MANHOUR_UTILIZATION: 350000, // 350KB
  };

  return estimates[reportType] ?? 200000;
}

/**
 * Map report type to job queue type
 */
function mapReportTypeToJobType(
  reportType: ReportType
): 'pm_schedule' | 'fleet_status' | 'drift_report' | 'tco_projection' {
  const mapping: Record<ReportType, 'pm_schedule' | 'fleet_status' | 'drift_report' | 'tco_projection'> = {
    WEEKLY_COMPLIANCE: 'pm_schedule',
    MONTHLY_SUMMARY: 'pm_schedule',
    FLEET_STATUS: 'fleet_status',
    DRIFT_REPORT: 'drift_report',
    TCO_PROJECTION: 'tco_projection',
    BOW_WAVE_ANALYSIS: 'pm_schedule',
    MANHOUR_UTILIZATION: 'pm_schedule',
  };

  return mapping[reportType] ?? 'pm_schedule';
}

/**
 * Generate download URL for completed export
 */
function generateDownloadUrl(jobId: string, format: ExportFormat): string {
  // In production, this would be a signed URL to MinIO/S3
  const baseUrl = process.env['MINIO_PUBLIC_URL'] ?? 'http://localhost:9000';
  const bucket = process.env['MINIO_EXPORT_BUCKET'] ?? 'mms-exports';
  const extension = format === 'xlsx' ? 'xlsx' : format === 'csv' ? 'csv' : 'pdf';

  return `${baseUrl}/${bucket}/${jobId}.${extension}`;
}

// =============================================================================
// Service Singleton
// =============================================================================

/**
 * Export service interface
 */
export interface ExportService {
  queuePmScheduleExport: typeof queuePmScheduleExport;
  queueReportExport: typeof queueReportExport;
  getExportJobStatus: typeof getExportJobStatus;
  updateExportJobStatus: typeof updateExportJobStatus;
  listExportJobs: typeof listExportJobs;
  cleanupExpiredExports: typeof cleanupExpiredExports;
}

let serviceInstance: ExportService | null = null;

/**
 * Get or create the export service singleton
 */
export function getExportService(): ExportService {
  if (!serviceInstance) {
    serviceInstance = {
      queuePmScheduleExport,
      queueReportExport,
      getExportJobStatus,
      updateExportJobStatus,
      listExportJobs,
      cleanupExpiredExports,
    };
    logger.info('ExportService initialized');
  }
  return serviceInstance;
}

