    71→  fleetId: string;
    72→  date: string;
    73→  dayType: DayType;
    74→  totalTrains: number;
    75→  fitTrains: number;
    76→  unavailableTrains: number;
    77→  inMaintenanceTrains: number;
    78→  additionalUnavailable: number;
    79→  availableTrains: number;
    80→  required: number;
    81→  surplus: number; // Positive = OK, Negative = VIOLATION
