   447→  /**
   448→   * Check if a specific train can be scheduled for maintenance on a date
   449→   * without violating service demand.
   450→   *
   451→   * @param trainId - Train to check
   452→   * @param targetDate - Proposed PM date
   453→   * @param holidays - Optional array of holiday dates
   454→   * @returns true if scheduling this train would NOT violate demand
   455→   */
   456→  async canScheduleTrainForMaintenance(
   457→    trainId: string,
   458→    targetDate: string,
   459→    holidays?: string[]
   460→  ): Promise<{ canSchedule: boolean; validation: AvailabilityValidation }> {
   461→    return this.traced('canScheduleTrainForMaintenance', async (span) => {
   462→      span.setAttribute(MmsAttributes.TRAIN_ID, trainId);
   463→      span.setAttribute('pm.targetDate', targetDate);
   464→
   465→      // Get train's fleet
   466→      const train = await this.db.query.trains.findFirst({
   467→        where: eq(trains.id, trainId),
   468→      });
   469→
   470→      if (!train) {
   471→        throw new NotFoundError(`Train not found: ${trainId}`, {
   472→          entityType: 'train',
   473→          entityId: trainId,
   474→        });
   475→      }
   476→
   477→      // Validate with this train as additional unavailable
   478→      const validation = await this.validateAvailability(
