   830→  /**
   831→   * List demand configurations with filtering.
   832→   */
   833→  async listDemand(filters?: DemandListFilters): Promise<ServiceDemand[]> {
   834→    return this.traced('listDemand', async (span) => {
   835→      const conditions: SQL<unknown>[] = [];
