  /**
   * Find all service demand violations for a set of proposed PMs.
   *
   * Used by the optimizer to validate a proposed schedule before committing.
   * Returns detailed violation information for each date/train combination.
   *
   * @param fleetId - Fleet to check
   * @param proposedPMs - Array of proposed PM schedules
   * @param holidays - Optional array of holiday dates
   * @returns Array of violations (empty if no violations)
   */
  async findViolations(
    fleetId: string,
    proposedPMs: ProposedPM[],
    holidays?: string[]
  ): Promise<DemandViolation[]> {
    return this.traced('findViolations', async (span) => {
      span.setAttribute(MmsAttributes.FLEET_ID, fleetId);
      span.setAttribute('violations.proposedCount', proposedPMs.length);

      if (proposedPMs.length === 0) {
        return [];
      }

      // Group proposed PMs by date
      const pmsByDate = new Map<string, ProposedPM[]>();
      for (const pm of proposedPMs) {
        const existing = pmsByDate.get(pm.targetDate) ?? [];
        existing.push(pm);
        pmsByDate.set(pm.targetDate, existing);
      }

      // Get train details for error messages
      const trainIds = [...new Set(proposedPMs.map((p) => p.trainId))];
      const trainMap = new Map<string, { trainNumber: string }>();

      if (trainIds.length > 0) {
        const trainRecords = await this.db.query.trains.findMany({
          where: inArray(trains.id, trainIds),
          columns: { id: true, trainNumber: true },
        });
        for (const t of trainRecords) {
          trainMap.set(t.id, { trainNumber: t.trainNumber });
        }
      }

      // Check each date
      const violations: DemandViolation[] = [];

      for (const [date, pms] of pmsByDate) {
        const validation = await this.validateAvailability(
          fleetId,
          date,
          pms.length, // All proposed PMs on this date
          holidays
        );

        if (!validation.isValid) {
          // Create violation for each PM on this date
          for (const pm of pms) {
            const trainInfo = trainMap.get(pm.trainId);
            violations.push({
              date,
              dayType: validation.dayType,
              trainId: pm.trainId,
              trainNumber: trainInfo?.trainNumber ?? 'unknown',
              pmCode: pm.pmCode ?? 'unknown',
              required: validation.required,
              available: validation.availableTrains + pms.length, // What would be available without these PMs
              shortfall: Math.abs(validation.surplus),
              severity: 'HARD',
              message: `Scheduling ${pm.pmCode ?? 'PM'} for train ${trainInfo?.trainNumber ?? pm.trainId} on ${date} would violate service demand (need ${validation.required}, would have ${validation.availableTrains})`,
            });
          }
        }
      }

      span.setAttribute('violations.count', violations.length);

      if (violations.length > 0) {
        this.log.warn(
          {
            fleetId,
            proposedPMs: proposedPMs.length,
            violations: violations.length,
            violatedDates: [...new Set(violations.map((v) => v.date))],
          },
          `Found ${violations.length} service demand violations for proposed PM schedule`
        );
      }

      return violations;
    });
  }

  /**
   * Find violations for a date range (horizon planning).
   *
   * Checks existing scheduled PMs against service demand for an entire
   * horizon period. Used for drift monitoring and planning validation.
   *
   * @param fleetId - Fleet to check
   * @param startDate - Start of range (YYYY-MM-DD)
   * @param horizonDays - Number of days to check
   * @param holidays - Optional array of holiday dates
   * @returns Array of dates with violations
   */
  async findViolationsInHorizon(
    fleetId: string,
    startDate: string,
    horizonDays: number,
    holidays?: string[]
  ): Promise<{ date: string; validation: AvailabilityValidation }[]> {
    return this.traced('findViolationsInHorizon', async (span) => {
      span.setAttribute(MmsAttributes.FLEET_ID, fleetId);
      span.setAttribute('horizon.startDate', startDate);
      span.setAttribute('horizon.days', horizonDays);

      const violations: { date: string; validation: AvailabilityValidation }[] = [];
      const start = new Date(startDate);

      for (let i = 0; i < horizonDays; i++) {
        const checkDate = new Date(start);
        checkDate.setDate(checkDate.getDate() + i);
        const dateStr = checkDate.toISOString().split('T')[0];

        const validation = await this.validateAvailability(
          fleetId,
          dateStr,
          0, // Check existing schedule only
          holidays
        );

        if (!validation.isValid) {
          violations.push({ date: dateStr, validation });
        }
      }

      span.setAttribute('horizon.violations', violations.length);
      return violations;
    });
  }

