        });
      }

      return result;
    });
  }

  /**
   * List demand configurations with filtering.
   */
  async listDemand(filters?: DemandListFilters): Promise<ServiceDemand[]> {
    return this.traced('listDemand', async (span) => {
      const conditions: SQL<unknown>[] = [];

      if (filters?.fleetId) {
        conditions.push(eq(serviceDemand.fleetId, filters.fleetId));
      }
      if (filters?.dayType) {
        if (Array.isArray(filters.dayType)) {
          conditions.push(inArray(serviceDemand.dayType, filters.dayType));
        } else {
          conditions.push(eq(serviceDemand.dayType, filters.dayType));
        }
      }
      if (filters?.effectiveDateFrom) {
        conditions.push(gte(serviceDemand.effectiveDate, filters.effectiveDateFrom));
      }
      if (filters?.effectiveDateTo) {
        conditions.push(lte(serviceDemand.effectiveDate, filters.effectiveDateTo));
      }

      const result = await this.db.query.serviceDemand.findMany({
        where: conditions.length > 0 ? and(...conditions) : undefined,
        orderBy: [desc(serviceDemand.effectiveDate), desc(serviceDemand.dayType)],
      });

      span.setAttribute('result.count', result.length);
      return result;
    });
  }

  /**
   * Delete a demand configuration.
   */
  async deleteDemand(id: string): Promise<void> {
    return this.inTransaction('deleteDemand', async (tx, span) => {
      span.setAttribute('demand.id', id);

      const existing = await tx.query.serviceDemand.findFirst({
        where: eq(serviceDemand.id, id),
      });

      if (!existing) {
        throw new NotFoundError(`Service demand not found: ${id}`, {
          entityType: 'service_demand',
          entityId: id,
        });
      }

      await tx.delete(serviceDemand).where(eq(serviceDemand.id, id));

      this.log.info(
        { demandId: id, fleetId: existing.fleetId, dayType: existing.dayType },
        'Service demand deleted'
      );
    });
  }

