   844→  // Typical Route Assignment Lookup
   845→  // ===========================================================================
   846→
   847→  /**
   848→   * Find the typical route assignment for a train based on recent history.
   849→   *
   850→   * Queries the run_assignments table to find the most frequently assigned
   851→   * route for the train in the last 30 days. This enables more accurate
   852→   * mileage projections when the train doesn't have a fixed route assignment.
   853→   *
   854→   * @param trainId - Train UUID
   855→   * @returns Most common route info if found, null otherwise
   856→   */
   857→  private async getTypicalRouteAssignment(
   858→    trainId: string
   859→  ): Promise<{ routeId: string; routeCode: string; assignmentCount: number } | null> {
   860→    return this.traced('getTypicalRouteAssignment', async (span) => {
   861→      span.setAttribute(MmsAttributes.TRAIN_ID, trainId);
   862→
   863→      const thirtyDaysAgo = addDays(new Date(), -30).toISOString().split('T')[0];
   864→      span.setAttribute('lookback.startDate', thirtyDaysAgo);
   865→
   866→      // Find the most frequently assigned route in the last 30 days
   867→      const result = await this.db
   868→        .select({
   869→          routeId: runAssignments.routeId,
   870→          routeCode: routes.routeCode,
   871→          assignmentCount: sql<number>`COUNT(*)::int`,
   872→        })
   873→        .from(runAssignments)
   874→        .innerJoin(routes, eq(runAssignments.routeId, routes.id))
   875→        .where(
   876→          and(
   877→            eq(runAssignments.trainId, trainId),
   878→            gte(runAssignments.assignmentDate, thirtyDaysAgo)
   879→          )
   880→        )
   881→        .groupBy(runAssignments.routeId, routes.routeCode)
   882→        .orderBy(desc(sql`COUNT(*)`))
   883→        .limit(1);
   884→
   885→      if (result.length === 0 || !result[0]) {
   886→        span.setAttribute('typicalRoute.found', false);
   887→        return null;
   888→      }
   889→
   890→      const { routeId, routeCode, assignmentCount } = result[0];
   891→
   892→      span.setAttribute('typicalRoute.found', true);
   893→      span.setAttribute('typicalRoute.routeId', routeId);
   894→      span.setAttribute('typicalRoute.routeCode', routeCode ?? 'UNKNOWN');
   895→      span.setAttribute('typicalRoute.assignmentCount', assignmentCount);
   896→
   897→      this.log.debug(
   898→        {
   899→          trainId,
   900→          routeId,
   901→          routeCode,
   902→          assignmentCount,
   903→        },
   904→        `Found typical route ${routeCode} for train with ${assignmentCount} assignments in last 30 days`
   905→      );
   906→
   907→      return { routeId, routeCode: routeCode ?? 'UNKNOWN', assignmentCount };
   908→    });
   909→  }
