   915→  /**
   916→   * Create a new route utilization profile.
   917→   */
   918→  async createProfile(request: CreateProfileRequest): Promise<RouteUtilizationProfile> {
   919→    return this.inTransaction('createProfile', async (tx, span) => {
   920→      const {
   921→        routeId,
   922→        effectiveDate = new Date().toISOString().split('T')[0],
   923→        weekdayKm,
   924→        saturdayKm,
   925→        sundayKm,
   926→        holidayKm,
   927→        peakSeasonMultiplier = 1.0,
   928→        offPeakMultiplier = 1.0,
   929→        serviceHoursPerDay,
   930→        roundTripKm,
   931→        tripsPerDay,
   932→        source,
   933→        confidence = 'MEDIUM',
   934→        notes,
   935→      } = request;
   936→
   937→      span.setAttribute('route.id', routeId);
   938→      span.setAttribute('profile.effectiveDate', effectiveDate);
   939→
   940→      // Verify route exists
   941→      const route = await tx.query.routes.findFirst({
   942→        where: eq(routes.id, routeId),
   943→      });
   944→
   945→      if (!route) {
   946→        throw new NotFoundError(`Route not found: ${routeId}`, {
   947→          entityType: 'route',
   948→          entityId: routeId,
   949→        });
   950→      }
   951→
   952→      // Validate weekdayKm
   953→      if (weekdayKm < 0 || weekdayKm > 2000) {
   954→        throw new ValidationError('Weekday km must be between 0 and 2000', {
   955→          field: 'weekdayKm',
   956→          context: { value: weekdayKm },
   957→        });
   958→      }
   959→
   960→      // Check for duplicate (same route and effective date)
   961→      const existing = await tx.query.routeUtilizationProfiles.findFirst({
   962→        where: and(
   963→          eq(routeUtilizationProfiles.routeId, routeId),
   964→          eq(routeUtilizationProfiles.effectiveDate, effectiveDate)
   965→        ),
   966→      });
   967→
   968→      if (existing) {
   969→        throw new DuplicateError(
   970→          `Profile already exists for route ${route.routeCode} on ${effectiveDate}`,
   971→          {
   972→            field: 'effectiveDate',
   973→            value: effectiveDate,
   974→            context: { routeId, routeCode: route.routeCode },
   975→          }
   976→        );
   977→      }
   978→
   979→      // Create profile
   980→      const profileData: NewRouteUtilizationProfile = {
   981→        routeId,
   982→        effectiveDate,
   983→        weekdayKm,
   984→        saturdayKm: saturdayKm ?? null,
   985→        sundayKm: sundayKm ?? null,
   986→        holidayKm: holidayKm ?? null,
   987→        peakSeasonMultiplier: peakSeasonMultiplier.toString(),
   988→        offPeakMultiplier: offPeakMultiplier.toString(),
   989→        serviceHoursPerDay: serviceHoursPerDay?.toString() ?? null,
   990→        roundTripKm: roundTripKm?.toString() ?? null,
   991→        tripsPerDay: tripsPerDay ?? null,
   992→        source: source ?? null,
   993→        confidence,
   994→        notes: notes ?? null,
   995→      };
   996→
   997→      const [result] = await tx
   998→        .insert(routeUtilizationProfiles)
   999→        .values(profileData)
  1000→        .returning();
  1001→
  1002→      span.setAttribute('profile.id', result.id);
  1003→
  1004→      this.log.info(
  1005→        {
  1006→          profileId: result.id,
  1007→          routeId,
  1008→          routeCode: route.routeCode,
  1009→          effectiveDate,
  1010→          weekdayKm,
  1011→          confidence,
  1012→        },
  1013→        `Created route utilization profile for ${route.routeCode}: ${weekdayKm} km/day (weekday)`
  1014→      );
