  1048→      }
  1049→
  1050→      // Build update object
  1051→      const updateData: Record<string, unknown> = { updatedAt: new Date() };
  1052→
  1053→      if (data.weekdayKm !== undefined) updateData.weekdayKm = data.weekdayKm;
  1054→      if (data.saturdayKm !== undefined) updateData.saturdayKm = data.saturdayKm;
  1055→      if (data.sundayKm !== undefined) updateData.sundayKm = data.sundayKm;
  1056→      if (data.holidayKm !== undefined) updateData.holidayKm = data.holidayKm;
  1057→      if (data.peakSeasonMultiplier !== undefined) {
