  1059→      }
  1060→      if (data.offPeakMultiplier !== undefined) {
  1061→        updateData.offPeakMultiplier = data.offPeakMultiplier.toString();
  1062→      }
  1063→      if (data.serviceHoursPerDay !== undefined) {
