  1069→      if (data.tripsPerDay !== undefined) updateData.tripsPerDay = data.tripsPerDay;
  1070→      if (data.source !== undefined) updateData.source = data.source;
  1071→      if (data.confidence !== undefined) updateData.confidence = data.confidence;
  1072→      if (data.notes !== undefined) updateData.notes = data.notes;
  1073→
  1074→      const [result] = await tx
  1075→        .update(routeUtilizationProfiles)
