  1165→  // ===========================================================================
  1166→  // Projection Accuracy Analysis
  1167→  // ===========================================================================
  1168→
  1169→  /**
  1170→   * Analyze projection accuracy across the fleet.
  1171→   *
  1172→   * This method identifies trains that are using fallback calculations
  1173→   * (fleet average or system default) instead of route-specific profiles.
  1174→   * Fleet-wide averages can result in 60,000+ km projection error over
  1175→   * the 12-year contract period.
  1176→   *
  1177→   * @param fleetIds - Optional list of fleet IDs to analyze (all fleets if not specified)
  1178→   * @returns Comprehensive analysis of projection accuracy
  1179→   */
  1180→  async analyzeProjectionAccuracy(fleetIds?: string[]): Promise<ProjectionAccuracyAnalysis> {
  1181→    return this.traced('analyzeProjectionAccuracy', async (span) => {
  1182→      const analysisTime = new Date().toISOString();
  1183→      const targetDate = new Date().toISOString().split('T')[0];
  1184→
  1185→      // Get all active trains
  1186→      const allTrains = await this.db.query.trains.findMany({
  1187→        where: eq(trains.fitnessStatus, 'FIT'),
  1188→        with: { fleet: true },
  1189→      });
  1190→      const filteredTrains = fleetIds
  1191→        ? allTrains.filter((t) => fleetIds.includes(t.fleetId))
  1192→        : allTrains;
  1193→
  1194→      span.setAttribute('analysis.totalTrains', filteredTrains.length);
  1195→
  1196→      const fallbackTrains: TrainProjectionInfo[] = [];
  1197→      let routeProfileCount = 0;
  1198→      let fleetAverageCount = 0;
  1199→      let systemDefaultCount = 0;
  1200→      let totalImpactKm = 0;
  1201→
  1202→      // Analyze each train's projection source
  1203→      for (const train of filteredTrains) {
  1204→        const rate = await this.calculateDailyRate(train.id, targetDate);
  1205→
  1206→        if (rate.source.startsWith('route:')) {
  1207→          routeProfileCount++;
  1208→        } else if (rate.source === 'fleet_average') {
  1209→          fleetAverageCount++;
  1210→          // Estimate projection uncertainty: fleet averages have ~20% variance
  1211→          const dailyVariance = rate.dailyKm * 0.2;
  1212→          const yearlyImpact = dailyVariance * 365;
  1213→          const twelveYearImpact = Math.round(yearlyImpact * 12);
  1214→          totalImpactKm += twelveYearImpact;
  1215→
  1216→          fallbackTrains.push({
  1217→            trainId: train.id,
  1218→            trainNumber: train.trainNumber,
  1219→            fleetId: train.fleetId,
  1220→            fleetCode: train.fleet?.code ?? 'UNKNOWN',
  1221→            source: rate.source,
  1222→            confidence: rate.confidence,
  1223→            dailyKm: rate.dailyKm,
  1224→            projectionImpactKm: twelveYearImpact,
  1225→            confidenceClass: this.getConfidenceClass(rate.confidence),
  1226→          });
  1227→        } else {
  1228→          systemDefaultCount++;
  1229→          // System default has very high uncertainty: ~50%
  1230→          const dailyVariance = rate.dailyKm * 0.5;
  1231→          const yearlyImpact = dailyVariance * 365;
  1232→          const twelveYearImpact = Math.round(yearlyImpact * 12);
  1233→          totalImpactKm += twelveYearImpact;
  1234→
  1235→          fallbackTrains.push({
  1236→            trainId: train.id,
  1237→            trainNumber: train.trainNumber,
  1238→            fleetId: train.fleetId,
  1239→            fleetCode: train.fleet?.code ?? 'UNKNOWN',
  1240→            source: rate.source,
  1241→            confidence: rate.confidence,
  1242→            dailyKm: rate.dailyKm,
  1243→            projectionImpactKm: twelveYearImpact,
  1244→            confidenceClass: this.getConfidenceClass(rate.confidence),
  1245→          });
  1246→        }
  1247→      }
  1248→
  1249→      const totalTrains = filteredTrains.length;
  1250→      const routeCoveragePct =
  1251→        totalTrains > 0 ? Math.round((routeProfileCount / totalTrains) * 100) : 0;
  1252→
  1253→      // Estimate potential missed PMs: each PM cycle is ~25,000 km for C1
  1254→      const potentialMissedPMs = Math.round(totalImpactKm / 25000);
  1255→
  1256→      // Generate recommendations
  1257→      const recommendations = this.generateAccuracyRecommendations(
  1258→        routeCoveragePct,
  1259→        fleetAverageCount,
  1260→        systemDefaultCount,
  1261→        fallbackTrains
  1262→      );
  1263→
  1264→      // Determine if warning is needed
  1265→      const { requiresWarning, warningSeverity } = this.determineWarningSeverity(
  1266→        routeCoveragePct,
  1267→        systemDefaultCount
  1268→      );
  1269→
  1270→      span.setAttribute('analysis.routeCoverage', routeCoveragePct);
  1271→      span.setAttribute('analysis.fallbackCount', fallbackTrains.length);
  1272→      span.setAttribute('analysis.requiresWarning', requiresWarning);
  1273→      if (warningSeverity) {
  1274→        span.setAttribute('analysis.warningSeverity', warningSeverity);
  1275→      }
  1276→
  1277→      const analysis: ProjectionAccuracyAnalysis = {
  1278→        analysisTime,
  1279→        totalTrains,
  1280→        routeProfileCount,
  1281→        fleetAverageCount,
  1282→        systemDefaultCount,
  1283→        routeCoveragePct,
  1284→        fallbackTrains,
  1285→        totalImpactKm,
  1286→        potentialMissedPMs,
  1287→        recommendations,
  1288→        requiresWarning,
  1289→        warningSeverity,
  1290→      };
  1291→
  1292→      if (requiresWarning) {
  1293→        this.log.warn(
  1294→          {
  1295→            routeCoveragePct,
  1296→            fallbackCount: fallbackTrains.length,
  1297→            systemDefaultCount,
  1298→            totalImpactKm,
  1299→            severity: warningSeverity,
  1300→          },
  1301→          `Projection accuracy warning: ${100 - routeCoveragePct}% of trains lack route-specific profiles. Potential ${totalImpactKm.toLocaleString()} km projection error over 12 years.`
  1302→        );
  1303→      }
  1304→
  1305→      return analysis;
  1306→    });
  1307→  }
  1308→
  1309→  /**
  1310→   * Emit a projection accuracy warning notification.
  1311→   *
  1312→   * This should be called periodically (e.g., weekly) or when route profiles
  1313→   * are modified to alert stakeholders about projection accuracy issues.
  1314→   *
  1315→   * @param analysis - The projection accuracy analysis result
  1316→   * @param recipientIds - User IDs to receive the notification
  1317→   * @returns Job ID if notification was queued, null if no warning needed
  1318→   */
  1319→  async emitProjectionAccuracyWarning(
  1320→    analysis: ProjectionAccuracyAnalysis,
  1321→    recipientIds: string[]
  1322→  ): Promise<string | null> {
  1323→    return this.traced('emitProjectionAccuracyWarning', async (span) => {
  1324→      if (!analysis.requiresWarning) {
  1325→        span.setAttribute('warning.skipped', true);
  1326→        span.setAttribute('warning.reason', 'no_warning_needed');
  1327→        return null;
  1328→      }
  1329→
  1330→      span.setAttribute('warning.severity', analysis.warningSeverity ?? 'MEDIUM');
  1331→      span.setAttribute('warning.recipientCount', recipientIds.length);
  1332→
  1333→      // Queue notification job
  1334→      const job = await addJob(QUEUE_NAMES.NOTIFICATION, 'projection_accuracy_warning', {
  1335→        type: 'PROJECTION_ACCURACY_WARNING' as const,
  1336→        severity: analysis.warningSeverity ?? 'MEDIUM',
  1337→        recipients: recipientIds,
  1338→        template: 'projection_accuracy_warning',
  1339→        subject: `[MMS] Projection Accuracy Warning - ${100 - analysis.routeCoveragePct}% of trains using fallback rates`,
  1340→        data: {
  1341→          severity: analysis.warningSeverity,
  1342→          detectionTime: analysis.analysisTime,
  1343→          trainCount: analysis.fallbackTrains.length,
  1344→          routeCoverage: analysis.routeCoveragePct,
  1345→          trains: analysis.fallbackTrains.slice(0, 20).map((t) => ({
  1346→            trainNumber: t.trainNumber,
  1347→            fleetCode: t.fleetCode,
  1348→            confidence: t.confidence,
  1349→            confidenceClass: t.confidenceClass,
  1350→            source: t.source === 'fleet_average' ? 'Fleet Average' : 'System Default',
  1351→            dailyKm: t.dailyKm,
  1352→            projectionImpactKm: t.projectionImpactKm.toLocaleString(),
  1353→          })),
  1354→          totalImpactKm: analysis.totalImpactKm.toLocaleString(),
  1355→          potentialMissedPMs: analysis.potentialMissedPMs.toLocaleString(),
  1356→          recommendations: analysis.recommendations,
  1357→          dashboardUrl: '/admin/route-utilization',
  1358→        },
  1359→      });
  1360→
  1361→      this.log.info(
  1362→        {
  1363→          jobId: job.id,
  1364→          severity: analysis.warningSeverity,
  1365→          fallbackCount: analysis.fallbackTrains.length,
  1366→          totalImpactKm: analysis.totalImpactKm,
  1367→        },
  1368→        'Projection accuracy warning notification queued'
  1369→      );
  1370→
  1371→      return job.id ?? null;
  1372→    });
  1373→  }
