  1375→  /**
  1376→   * Get CSS class name for confidence level.
  1377→   */
  1378→  private getConfidenceClass(
  1379→    confidence: ConfidenceLevel
  1380→  ): 'high-confidence' | 'medium-confidence' | 'low-confidence' | 'estimated' {
  1381→    switch (confidence) {
  1382→      case 'HIGH':
  1383→        return 'high-confidence';
  1384→      case 'MEDIUM':
  1385→        return 'medium-confidence';
  1386→      case 'LOW':
  1387→        return 'low-confidence';
  1388→      case 'ESTIMATED':
  1389→        return 'estimated';
  1390→    }
  1391→  }
  1392→
  1393→  /**
  1394→   * Generate recommendations based on analysis results.
  1395→   */
  1396→  private generateAccuracyRecommendations(
  1397→    routeCoveragePct: number,
  1398→    fleetAverageCount: number,
  1399→    systemDefaultCount: number,
  1400→    fallbackTrains: TrainProjectionInfo[]
  1401→  ): string[] {
  1402→    const recommendations: string[] = [];
  1403→
  1404→    if (systemDefaultCount > 0) {
  1405→      recommendations.push(
  1406→        `CRITICAL: ${systemDefaultCount} train(s) using system default (250 km/day). ` +
  1407→          'Add route utilization profiles or improve mileage data collection.'
  1408→      );
  1409→    }
  1410→
  1411→    if (routeCoveragePct < 50) {
  1412→      recommendations.push(
  1413→        `Route profile coverage is ${routeCoveragePct}% - below 50% threshold. ` +
  1414→          'Create route-specific utilization profiles for accurate PM scheduling.'
  1415→      );
  1416→    }
  1417→
  1418→    if (fleetAverageCount > 0 && fleetAverageCount <= 10) {
  1419→      const affectedTrains = fallbackTrains
  1420→        .filter((t) => t.source === 'fleet_average')
  1421→        .map((t) => t.trainNumber)
  1422→        .slice(0, 5);
  1423→      recommendations.push(
  1424→        `Assign routes to these trains for improved accuracy: ${affectedTrains.join(', ')}${fleetAverageCount > 5 ? '...' : ''}`
  1425→      );
  1426→    }
  1427→
  1428→    if (routeCoveragePct >= 80 && routeCoveragePct < 95) {
  1429→      recommendations.push(
  1430→        'Route coverage is good but could be improved. Consider adding profiles for remaining routes.'
  1431→      );
  1432→    }
  1433→
  1434→    if (recommendations.length === 0) {
  1435→      recommendations.push('Projection accuracy is within acceptable limits.');
  1436→    }
  1437→
  1438→    return recommendations;
  1439→  }
  1440→
  1441→  /**
  1442→   * Determine warning severity based on analysis metrics.
  1443→   */
  1444→  private determineWarningSeverity(
  1445→    routeCoveragePct: number,
  1446→    systemDefaultCount: number
  1447→  ): { requiresWarning: boolean; warningSeverity?: 'CRITICAL' | 'HIGH' | 'MEDIUM' | 'LOW' } {
  1448→    // CRITICAL: Any train using system default (highest uncertainty)
  1449→    if (systemDefaultCount > 0) {
  1450→      return { requiresWarning: true, warningSeverity: 'CRITICAL' };
  1451→    }
  1452→
  1453→    // HIGH: Less than 50% route coverage
  1454→    if (routeCoveragePct < 50) {
  1455→      return { requiresWarning: true, warningSeverity: 'HIGH' };
  1456→    }
  1457→
  1458→    // MEDIUM: Less than 70% route coverage
  1459→    if (routeCoveragePct < 70) {
  1460→      return { requiresWarning: true, warningSeverity: 'MEDIUM' };
  1461→    }
  1462→
  1463→    // LOW: Less than 90% route coverage
  1464→    if (routeCoveragePct < 90) {
  1465→      return { requiresWarning: true, warningSeverity: 'LOW' };
  1466→    }
  1467→
  1468→    // No warning needed for >= 90% coverage with no system defaults
  1469→    return { requiresWarning: false };
  1470→  }
