/**
 * MMS Route Utilization Service
 *
 * Provides route-specific daily mileage rates for accurate long-term projections.
 * Critical for PM scheduling as fleet-wide averages can result in 60,000+ km
 * projection error over the 12-year contract period.
 *
 * Key responsibilities:
 * - Retrieve route-specific utilization profiles
 * - Calculate expected daily km for trains with fallback hierarchy
 * - Project cumulative mileage over time horizons
 * - Apply seasonal multipliers for peak/off-peak periods
 *
 * Fallback hierarchy (in priority order):
 * 1. Route-specific profile from route_utilization_profiles table
 * 2. Fleet-wide average from last 30 days of mileage readings
 * 3. System default: 250 km/day (conservative estimate)
 *
 * @see specs/004-domain-services.md Section 4.2.7 (Route Utilization Service)
 * @see specs/003-database-schema.md Section 3.2.2 (Route Utilization Profiles)
 */

import { eq, and, sql, desc, lte, gte, avg, inArray } from 'drizzle-orm';
import type { SQL } from 'drizzle-orm';
import { addDays } from 'date-fns';
import { BaseService, MmsAttributes } from '../lib/services/base';
import {
  routeUtilizationProfiles,
  trains,
  fleets,
  routes,
  mileageReadings,
  runAssignments,
  type RouteUtilizationProfile,
  type NewRouteUtilizationProfile,
} from '../lib/db/schema';
import { NotFoundError, ValidationError, DuplicateError } from '../lib/errors';
import { addJob, QUEUE_NAMES } from '../lib/queue';

// =============================================================================
// Types
// =============================================================================

/** Day type for utilization lookup */
export type UtilizationDayType = 'WEEKDAY' | 'SATURDAY' | 'SUNDAY' | 'HOLIDAY';

/** Confidence level for mileage estimates */
export type ConfidenceLevel = 'HIGH' | 'MEDIUM' | 'LOW' | 'ESTIMATED';

/** Source of the daily rate calculation */
export type RateSource =
  | `route:${string}` // Route-specific profile with route ID
  | 'fleet_average'   // Calculated from recent mileage readings
  | 'system_default'; // Conservative fallback (250 km/day)

/** Result of daily rate calculation */
export interface DailyRateResult {
  dailyKm: number;
  source: RateSource;
  confidence: ConfidenceLevel;
  details?: {
    routeId?: string;
    routeCode?: string;
    fleetId?: string;
    fleetCode?: string;
    dayType?: UtilizationDayType;
    seasonalMultiplier?: number;
    profileEffectiveDate?: string;
  };
}

/** Single day projection */
export interface MileageProjection {
  date: string;
  projectedDailyKm: number;
  cumulativeKm: number;
  source: RateSource;
  confidence: ConfidenceLevel;
}

/** Route profile with additional metadata */
export interface RouteProfileWithMeta extends RouteUtilizationProfile {
  routeCode?: string;
  routeName?: string;
}

/** Create route utilization profile request */
export interface CreateProfileRequest {
  routeId: string;
  effectiveDate?: string;
  weekdayKm: number;
  saturdayKm?: number;
  sundayKm?: number;
  holidayKm?: number;
  peakSeasonMultiplier?: number;
  offPeakMultiplier?: number;
  serviceHoursPerDay?: number;
  roundTripKm?: number;
  tripsPerDay?: number;
  source?: string;
  confidence?: ConfidenceLevel;
  notes?: string;
}

/** Update route utilization profile request */
export interface UpdateProfileRequest {
  weekdayKm?: number;
  saturdayKm?: number | null;
  sundayKm?: number | null;
  holidayKm?: number | null;
  peakSeasonMultiplier?: number;
  offPeakMultiplier?: number;
  serviceHoursPerDay?: number | null;
  roundTripKm?: number | null;
  tripsPerDay?: number | null;
  source?: string | null;
  confidence?: ConfidenceLevel;
  notes?: string | null;
}

/** Filter options for listing profiles */
export interface ProfileListFilters {
  routeId?: string;
  routeIds?: string[];
  confidence?: ConfidenceLevel | ConfidenceLevel[];
  effectiveDateFrom?: string;
  effectiveDateTo?: string;
  active?: boolean;
}

/** Fleet average calculation result */
export interface FleetAverageResult {
  fleetId: string;
  fleetCode: string;
  averageDailyKm: number;
  sampleSize: number;
  periodStart: string;
  periodEnd: string;
  confidence: ConfidenceLevel;
}

/** Individual train projection accuracy info */
export interface TrainProjectionInfo {
  trainId: string;
  trainNumber: string;
  fleetId: string;
  fleetCode: string;
  source: RateSource;
  confidence: ConfidenceLevel;
  dailyKm: number;
  /** Estimated projection uncertainty over 12 years in km */
  projectionImpactKm: number;
  confidenceClass: 'high-confidence' | 'medium-confidence' | 'low-confidence' | 'estimated';
}

/** Projection accuracy analysis result */
export interface ProjectionAccuracyAnalysis {
  /** Timestamp of analysis */
  analysisTime: string;
  /** Total number of trains analyzed */
  totalTrains: number;
  /** Number of trains with route-specific profiles */
  routeProfileCount: number;
  /** Number of trains using fleet average */
  fleetAverageCount: number;
  /** Number of trains using system default */
  systemDefaultCount: number;
  /** Percentage of trains with route profiles */
  routeCoveragePct: number;
  /** Trains using fallback calculations (fleet average or system default) */
  fallbackTrains: TrainProjectionInfo[];
  /** Total projected uncertainty across all fallback trains */
  totalImpactKm: number;
  /** Estimated number of PM scheduling decisions that could be affected */
  potentialMissedPMs: number;
  /** Recommendations for improving accuracy */
  recommendations: string[];
  /** Whether this analysis triggers a warning */
  requiresWarning: boolean;
  /** Warning severity if triggered */
  warningSeverity?: 'CRITICAL' | 'HIGH' | 'MEDIUM' | 'LOW';
}

// =============================================================================
// Constants
// =============================================================================

/** Conservative default daily km when no data available */
const SYSTEM_DEFAULT_DAILY_KM = 250;

/** Number of days to look back for fleet average calculation */
const FLEET_AVERAGE_LOOKBACK_DAYS = 30;

/** Minimum sample size for reliable fleet average */
const MIN_SAMPLE_SIZE_FOR_HIGH_CONFIDENCE = 20;
const MIN_SAMPLE_SIZE_FOR_MEDIUM_CONFIDENCE = 10;

/** Peak months (0-indexed): Jan-Feb (CNY), Jun (school), Nov-Dec (holidays) */
const PEAK_MONTHS = [0, 1, 5, 10, 11];

/** Default multipliers for day types relative to weekday baseline */
const DEFAULT_DAY_TYPE_MULTIPLIERS = {
  WEEKDAY: 1.0,
  SATURDAY: 0.8,
  SUNDAY: 0.7,
  HOLIDAY: 0.6,
};

// =============================================================================
// Route Utilization Service
// =============================================================================

export class RouteUtilizationService extends BaseService {
  constructor() {
    super({ name: 'route-utilization-service', version: '1.0.0' });
  }

  // ===========================================================================
  // Profile Retrieval
  // ===========================================================================

  /**
   * Get the utilization profile for a route at a specific date.
   *
   * Returns the most recent effective profile for the route. If no profile
   * exists, returns null (callers should fall back to fleet average or default).
   *
   * @param routeId - Route UUID
   * @param asOfDate - Date to find effective profile for (defaults to today)
   * @returns Profile if found, null otherwise
   */
  async getProfile(
    routeId: string,
    asOfDate?: string
  ): Promise<RouteProfileWithMeta | null> {
    return this.traced('getProfile', async (span) => {
      span.setAttribute('route.id', routeId);
      const effectiveDate = asOfDate ?? new Date().toISOString().split('T')[0];
      span.setAttribute('profile.effectiveDate', effectiveDate);

      // Find most recent effective profile
      const profile = await this.db.query.routeUtilizationProfiles.findFirst({
        where: and(
          eq(routeUtilizationProfiles.routeId, routeId),
          lte(routeUtilizationProfiles.effectiveDate, effectiveDate)
        ),
        orderBy: desc(routeUtilizationProfiles.effectiveDate),
        with: { route: true },
      });

      if (!profile) {
        span.setAttribute('profile.found', false);
        return null;
      }

      span.setAttribute('profile.found', true);
      span.setAttribute('profile.id', profile.id);
      span.setAttribute('profile.confidence', profile.confidence ?? 'MEDIUM');

      return {
        ...profile,
        routeCode: profile.route?.routeCode,
        routeName: profile.route?.routeName,
      };
    });
  }

  /**
   * Get profile by ID.
   */
  async getProfileById(id: string): Promise<RouteProfileWithMeta> {
    return this.traced('getProfileById', async (span) => {
      span.setAttribute('profile.id', id);

      const profile = await this.db.query.routeUtilizationProfiles.findFirst({
        where: eq(routeUtilizationProfiles.id, id),
        with: { route: true },
      });

      if (!profile) {
        throw new NotFoundError(`Route utilization profile not found: ${id}`, {
          entityType: 'route_utilization_profile',
          entityId: id,
        });
      }

      return {
        ...profile,
        routeCode: profile.route?.routeCode,
        routeName: profile.route?.routeName,
      };
    });
  }

  /**
   * Get all profiles for a route (historical).
   */
  async getProfileHistory(routeId: string): Promise<RouteUtilizationProfile[]> {
    return this.traced('getProfileHistory', async (span) => {
      span.setAttribute('route.id', routeId);

      // Verify route exists
      const route = await this.db.query.routes.findFirst({
        where: eq(routes.id, routeId),
      });

      if (!route) {
        throw new NotFoundError(`Route not found: ${routeId}`, {
          entityType: 'route',
          entityId: routeId,
        });
      }

      const profiles = await this.db.query.routeUtilizationProfiles.findMany({
        where: eq(routeUtilizationProfiles.routeId, routeId),
        orderBy: desc(routeUtilizationProfiles.effectiveDate),
      });

      span.setAttribute('profile.count', profiles.length);
      return profiles;
    });
  }

  // ===========================================================================
  // Daily Rate Calculation
  // ===========================================================================

  /**
   * Calculate expected daily km for a train based on available data.
   *
   * This is the primary method for mileage projection. It follows the
   * fallback hierarchy:
   * 1. Route-specific profile (if train has assigned route or default route)
   * 2. Fleet-wide average from recent mileage readings
   * 3. System default (250 km/day)
   *
   * The result includes source and confidence metadata for transparency.
   *
   * @param trainId - Train UUID
   * @param targetDate - Date to calculate rate for
   * @param routeId - Optional specific route ID (if known)
   * @param holidays - Optional array of holiday dates (YYYY-MM-DD)
   * @returns Daily rate with source and confidence
   */
  async calculateDailyRate(
    trainId: string,
    targetDate: string,
    routeId?: string,
    holidays?: string[]
  ): Promise<DailyRateResult> {
    return this.traced('calculateDailyRate', async (span) => {
      span.setAttribute(MmsAttributes.TRAIN_ID, trainId);
      span.setAttribute('rate.targetDate', targetDate);

      // Get train details
      const train = await this.db.query.trains.findFirst({
        where: eq(trains.id, trainId),
        with: { fleet: true },
      });

      if (!train) {
        throw new NotFoundError(`Train not found: ${trainId}`, {
          entityType: 'train',
          entityId: trainId,
        });
      }

      span.setAttribute(MmsAttributes.FLEET_ID, train.fleetId);

      // Determine day type
      const dayType = this.getDayType(targetDate, holidays);
      span.setAttribute('rate.dayType', dayType);

      // Try route-specific profile first
      if (routeId) {
        const profile = await this.getProfile(routeId, targetDate);
        if (profile) {
          const result = this.calculateFromProfile(profile, targetDate, dayType);
          span.setAttribute('rate.source', result.source);
          span.setAttribute('rate.dailyKm', result.dailyKm);
          span.setAttribute('rate.confidence', result.confidence);
          return result;
        }
      }

      // Try typical route assignment from recent history
      const typicalRoute = await this.getTypicalRouteAssignment(trainId);
      if (typicalRoute) {
        const profile = await this.getProfile(typicalRoute.routeId, targetDate);
        if (profile) {
          const result = this.calculateFromProfile(profile, targetDate, dayType);
          // Slightly lower confidence since it's inferred from history
          result.confidence = result.confidence === 'HIGH' ? 'MEDIUM' : result.confidence;
          result.details = {
            ...result.details,
            routeCode: typicalRoute.routeCode,
          };
          span.setAttribute('rate.source', result.source);
          span.setAttribute('rate.sourceMethod', 'typical_route_assignment');
          span.setAttribute('rate.dailyKm', result.dailyKm);
          span.setAttribute('rate.confidence', result.confidence);

          this.log.debug(
            {
              trainId,
              trainNumber: train.trainNumber,
              routeId: typicalRoute.routeId,
              routeCode: typicalRoute.routeCode,
              dailyKm: result.dailyKm,
              assignmentCount: typicalRoute.assignmentCount,
            },
            `Using typical route ${typicalRoute.routeCode} for train ${train.trainNumber}: ${result.dailyKm} km/day`
          );

          return result;
        }
      }

      // Fall back to fleet average
      const fleetAverage = await this.getFleetAverage(train.fleetId, targetDate);
      if (fleetAverage && fleetAverage.sampleSize >= MIN_SAMPLE_SIZE_FOR_MEDIUM_CONFIDENCE) {
        const result: DailyRateResult = {
          dailyKm: Math.round(fleetAverage.averageDailyKm),
          source: 'fleet_average',
          confidence: fleetAverage.confidence,
          details: {
            fleetId: train.fleetId,
            fleetCode: train.fleet?.code,
            dayType,
          },
        };

        span.setAttribute('rate.source', result.source);
        span.setAttribute('rate.dailyKm', result.dailyKm);
        span.setAttribute('rate.confidence', result.confidence);

        this.log.debug(
          {
            trainId,
            fleetId: train.fleetId,
            dailyKm: result.dailyKm,
            sampleSize: fleetAverage.sampleSize,
          },
          `Using fleet average for train ${train.trainNumber}: ${result.dailyKm} km/day`
        );

        return result;
      }

      // Fall back to system default
      const result: DailyRateResult = {
        dailyKm: SYSTEM_DEFAULT_DAILY_KM,
        source: 'system_default',
        confidence: 'ESTIMATED',
        details: {
          fleetId: train.fleetId,
          fleetCode: train.fleet?.code,
          dayType,
        },
      };

      span.setAttribute('rate.source', result.source);
      span.setAttribute('rate.dailyKm', result.dailyKm);
      span.setAttribute('rate.confidence', result.confidence);

      this.log.warn(
        {
          trainId,
          trainNumber: train.trainNumber,
          fleetId: train.fleetId,
          targetDate,
        },
        `No route profile or fleet average for train ${train.trainNumber}. Using system default ${SYSTEM_DEFAULT_DAILY_KM} km/day. This may cause significant projection errors over time.`
      );

      return result;
    });
  }

  /**
   * Calculate rate for a specific route (without train context).
   *
   * Used when planning route-level capacity or before train assignment.
   */
  async calculateRouteRate(
    routeId: string,
    targetDate: string,
    holidays?: string[]
  ): Promise<DailyRateResult> {
    return this.traced('calculateRouteRate', async (span) => {
      span.setAttribute('route.id', routeId);
      span.setAttribute('rate.targetDate', targetDate);

      // Verify route exists
      const route = await this.db.query.routes.findFirst({
        where: eq(routes.id, routeId),
      });

      if (!route) {
        throw new NotFoundError(`Route not found: ${routeId}`, {
          entityType: 'route',
          entityId: routeId,
        });
      }

      const dayType = this.getDayType(targetDate, holidays);
      span.setAttribute('rate.dayType', dayType);

      // Try route-specific profile
      const profile = await this.getProfile(routeId, targetDate);
      if (profile) {
        const result = this.calculateFromProfile(profile, targetDate, dayType);
        span.setAttribute('rate.source', result.source);
        span.setAttribute('rate.dailyKm', result.dailyKm);
        return result;
      }

      // Fall back to route's default daily km if defined
      if (route.defaultDailyKm) {
        const result: DailyRateResult = {
          dailyKm: route.defaultDailyKm,
          source: `route:${routeId}`,
          confidence: 'LOW',
          details: {
            routeId,
            routeCode: route.routeCode,
            dayType,
          },
        };
        span.setAttribute('rate.source', result.source);
        span.setAttribute('rate.dailyKm', result.dailyKm);
        return result;
      }

      // Fall back to expected km per day
      if (route.expectedKmPerDay) {
        const multiplier = DEFAULT_DAY_TYPE_MULTIPLIERS[dayType];
        const result: DailyRateResult = {
          dailyKm: Math.round(route.expectedKmPerDay * multiplier),
          source: `route:${routeId}`,
          confidence: 'LOW',
          details: {
            routeId,
            routeCode: route.routeCode,
            dayType,
          },
        };
        span.setAttribute('rate.source', result.source);
        span.setAttribute('rate.dailyKm', result.dailyKm);
        return result;
      }

      // System default
      const result: DailyRateResult = {
        dailyKm: SYSTEM_DEFAULT_DAILY_KM,
        source: 'system_default',
        confidence: 'ESTIMATED',
        details: {
          routeId,
          routeCode: route.routeCode,
          dayType,
        },
      };
      span.setAttribute('rate.source', result.source);
      span.setAttribute('rate.dailyKm', result.dailyKm);
      return result;
    });
  }

  // ===========================================================================
  // Mileage Projection
  // ===========================================================================

  /**
   * Project mileage for a train over a time horizon.
   *
   * Starting from the train's current mileage, calculates daily projections
   * for the specified number of days. This is used by:
   * - PM scheduling (determine when train will hit maintenance thresholds)
   * - Drift monitoring (compare projected vs. actual)
   * - Strategic planning (long-term fleet mileage distribution)
   *
   * @param trainId - Train UUID
   * @param startDate - Projection start date (YYYY-MM-DD)
   * @param horizonDays - Number of days to project
   * @param routeId - Optional fixed route for all projections
   * @param holidays - Optional array of holiday dates
   * @returns Array of daily projections with cumulative mileage
   */
  async projectMileage(
    trainId: string,
    startDate: string,
    horizonDays: number,
    routeId?: string,
    holidays?: string[]
  ): Promise<MileageProjection[]> {
    return this.traced('projectMileage', async (span) => {
      span.setAttribute(MmsAttributes.TRAIN_ID, trainId);
      span.setAttribute('projection.startDate', startDate);
      span.setAttribute('projection.horizonDays', horizonDays);

      if (horizonDays < 1) {
        throw new ValidationError('Horizon days must be at least 1', {
          field: 'horizonDays',
          context: { value: horizonDays },
        });
      }

      if (horizonDays > 3650) {
        throw new ValidationError('Horizon days cannot exceed 3650 (10 years)', {
          field: 'horizonDays',
          context: { value: horizonDays },
        });
      }

      // Get train's current mileage
      const train = await this.db.query.trains.findFirst({
        where: eq(trains.id, trainId),
      });

      if (!train) {
        throw new NotFoundError(`Train not found: ${trainId}`, {
          entityType: 'train',
          entityId: trainId,
        });
      }

      let cumulativeKm = train.currentMileageKm;
      const projections: MileageProjection[] = [];
      const start = new Date(startDate);

      // Calculate daily projections
      for (let day = 0; day < horizonDays; day++) {
        const targetDate = addDays(start, day);
        const dateStr = targetDate.toISOString().split('T')[0];

        const rate = await this.calculateDailyRate(trainId, dateStr, routeId, holidays);
        cumulativeKm += rate.dailyKm;

        projections.push({
          date: dateStr,
          projectedDailyKm: rate.dailyKm,
          cumulativeKm,
          source: rate.source,
          confidence: rate.confidence,
        });
      }

      span.setAttribute('projection.count', projections.length);
      span.setAttribute(
        'projection.finalCumulativeKm',
        projections[projections.length - 1]?.cumulativeKm ?? cumulativeKm
      );

      return projections;
    });
  }

  /**
   * Project when a train will reach a target mileage.
   *
   * Useful for PM scheduling - determines the date when a train will hit
   * the next maintenance threshold.
   *
   * @param trainId - Train UUID
   * @param targetMileageKm - Target cumulative mileage to reach
   * @param maxHorizonDays - Maximum days to search (default: 365)
   * @returns Projected date and details, or null if not reached within horizon
   */
  async projectDateForMileage(
    trainId: string,
    targetMileageKm: number,
    maxHorizonDays: number = 365,
    routeId?: string,
    holidays?: string[]
  ): Promise<{
    projectedDate: string;
    daysFromNow: number;
    projectedMileage: number;
    confidence: ConfidenceLevel;
  } | null> {
    return this.traced('projectDateForMileage', async (span) => {
      span.setAttribute(MmsAttributes.TRAIN_ID, trainId);
      span.setAttribute('target.mileageKm', targetMileageKm);
      span.setAttribute('target.maxHorizonDays', maxHorizonDays);

      // Get train's current mileage
      const train = await this.db.query.trains.findFirst({
        where: eq(trains.id, trainId),
      });

      if (!train) {
        throw new NotFoundError(`Train not found: ${trainId}`, {
          entityType: 'train',
          entityId: trainId,
        });
      }

      if (train.currentMileageKm >= targetMileageKm) {
        span.setAttribute('result.alreadyReached', true);
        return {
          projectedDate: new Date().toISOString().split('T')[0],
          daysFromNow: 0,
          projectedMileage: train.currentMileageKm,
          confidence: 'HIGH',
        };
      }

      const startDate = new Date().toISOString().split('T')[0];
      let cumulativeKm = train.currentMileageKm;
      const start = new Date(startDate);
      let worstConfidence: ConfidenceLevel = 'HIGH';

      for (let day = 1; day <= maxHorizonDays; day++) {
        const targetDate = addDays(start, day);
        const dateStr = targetDate.toISOString().split('T')[0];

        const rate = await this.calculateDailyRate(trainId, dateStr, routeId, holidays);
        cumulativeKm += rate.dailyKm;

        // Track worst confidence level
        if (this.confidenceRank(rate.confidence) < this.confidenceRank(worstConfidence)) {
          worstConfidence = rate.confidence;
        }

        if (cumulativeKm >= targetMileageKm) {
          span.setAttribute('result.found', true);
          span.setAttribute('result.projectedDate', dateStr);
          span.setAttribute('result.daysFromNow', day);
          return {
            projectedDate: dateStr,
            daysFromNow: day,
            projectedMileage: cumulativeKm,
            confidence: worstConfidence,
          };
        }
      }

      span.setAttribute('result.found', false);
      span.setAttribute('result.reachedMileage', cumulativeKm);
      return null;
    });
  }

  // ===========================================================================
  // Fleet Average Calculation
  // ===========================================================================

  /**
   * Calculate fleet-wide average daily km from recent mileage readings.
   *
   * Uses the last 30 days of validated mileage readings to compute
   * a reliable average. Returns confidence based on sample size.
   *
   * @param fleetId - Fleet UUID
   * @param asOfDate - Calculate as of this date (defaults to today)
   * @returns Fleet average with metadata, or null if no data
   */
  async getFleetAverage(
    fleetId: string,
    asOfDate?: string
  ): Promise<FleetAverageResult | null> {
    return this.traced('getFleetAverage', async (span) => {
      span.setAttribute(MmsAttributes.FLEET_ID, fleetId);

      const endDate = asOfDate ?? new Date().toISOString().split('T')[0];
      const startDate = addDays(new Date(endDate), -FLEET_AVERAGE_LOOKBACK_DAYS)
        .toISOString()
        .split('T')[0];

      span.setAttribute('average.startDate', startDate);
      span.setAttribute('average.endDate', endDate);

      // Get fleet for validation and metadata
      const fleet = await this.db.query.fleets.findFirst({
        where: eq(fleets.id, fleetId),
      });

      if (!fleet) {
        throw new NotFoundError(`Fleet not found: ${fleetId}`, {
          entityType: 'fleet',
          entityId: fleetId,
        });
      }

      // Calculate average from valid mileage readings
      const result = await this.db
        .select({
          avgDaily: avg(mileageReadings.dailyKm),
          sampleSize: sql<number>`COUNT(*)::int`,
        })
        .from(mileageReadings)
        .innerJoin(trains, eq(mileageReadings.trainId, trains.id))
        .where(
          and(
            eq(trains.fleetId, fleetId),
            eq(trains.active, true),
            gte(mileageReadings.readingDate, startDate),
            lte(mileageReadings.readingDate, endDate),
            eq(mileageReadings.validationStatus, 'VALID'),
            sql`${mileageReadings.dailyKm} > 0` // Exclude zero or null readings
          )
        );

      const { avgDaily, sampleSize } = result[0];

      if (!avgDaily || sampleSize === 0) {
        span.setAttribute('average.found', false);
        this.log.debug(
          { fleetId, fleetCode: fleet.code, startDate, endDate },
          `No valid mileage readings found for fleet ${fleet.code}`
        );
        return null;
      }

      // Determine confidence based on sample size
      let confidence: ConfidenceLevel;
      if (sampleSize >= MIN_SAMPLE_SIZE_FOR_HIGH_CONFIDENCE) {
        confidence = 'MEDIUM'; // Fleet average is never "HIGH" - route-specific is preferred
      } else if (sampleSize >= MIN_SAMPLE_SIZE_FOR_MEDIUM_CONFIDENCE) {
        confidence = 'LOW';
      } else {
        confidence = 'ESTIMATED';
      }

      span.setAttribute('average.found', true);
      span.setAttribute('average.value', Number(avgDaily));
      span.setAttribute('average.sampleSize', sampleSize);
      span.setAttribute('average.confidence', confidence);

      return {
        fleetId,
        fleetCode: fleet.code,
        averageDailyKm: Math.round(Number(avgDaily)),
        sampleSize,
        periodStart: startDate,
        periodEnd: endDate,
        confidence,
      };
    });
  }

  // ===========================================================================
  // Typical Route Assignment Lookup
  // ===========================================================================

  /**
   * Find the typical route assignment for a train based on recent history.
   *
   * Queries the run_assignments table to find the most frequently assigned
   * route for the train in the last 30 days. This enables more accurate
   * mileage projections when the train doesn't have a fixed route assignment.
   *
   * @param trainId - Train UUID
   * @returns Most common route info if found, null otherwise
   */
  private async getTypicalRouteAssignment(
    trainId: string
  ): Promise<{ routeId: string; routeCode: string; assignmentCount: number } | null> {
    return this.traced('getTypicalRouteAssignment', async (span) => {
      span.setAttribute(MmsAttributes.TRAIN_ID, trainId);

      const thirtyDaysAgo = addDays(new Date(), -30).toISOString().split('T')[0];
      span.setAttribute('lookback.startDate', thirtyDaysAgo);

      // Find the most frequently assigned route in the last 30 days
      const result = await this.db
        .select({
          routeId: runAssignments.routeId,
          routeCode: routes.routeCode,
          assignmentCount: sql<number>`COUNT(*)::int`,
        })
        .from(runAssignments)
        .innerJoin(routes, eq(runAssignments.routeId, routes.id))
        .where(
          and(
            eq(runAssignments.trainId, trainId),
            gte(runAssignments.assignmentDate, thirtyDaysAgo)
          )
        )
        .groupBy(runAssignments.routeId, routes.routeCode)
        .orderBy(desc(sql`COUNT(*)`))
        .limit(1);

      if (result.length === 0 || !result[0]) {
        span.setAttribute('typicalRoute.found', false);
        return null;
      }

      const { routeId, routeCode, assignmentCount } = result[0];

      span.setAttribute('typicalRoute.found', true);
      span.setAttribute('typicalRoute.routeId', routeId);
      span.setAttribute('typicalRoute.routeCode', routeCode ?? 'UNKNOWN');
      span.setAttribute('typicalRoute.assignmentCount', assignmentCount);

      this.log.debug(
        {
          trainId,
          routeId,
          routeCode,
          assignmentCount,
        },
        `Found typical route ${routeCode} for train with ${assignmentCount} assignments in last 30 days`
      );

      return { routeId, routeCode: routeCode ?? 'UNKNOWN', assignmentCount };
    });
  }

  // ===========================================================================
  // CRUD Operations
  // ===========================================================================

  /**
   * Create a new route utilization profile.
   */
  async createProfile(request: CreateProfileRequest): Promise<RouteUtilizationProfile> {
    return this.inTransaction('createProfile', async (tx, span) => {
      const {
        routeId,
        effectiveDate = new Date().toISOString().split('T')[0],
        weekdayKm,
        saturdayKm,
        sundayKm,
        holidayKm,
        peakSeasonMultiplier = 1.0,
        offPeakMultiplier = 1.0,
        serviceHoursPerDay,
        roundTripKm,
        tripsPerDay,
        source,
        confidence = 'MEDIUM',
        notes,
      } = request;

      span.setAttribute('route.id', routeId);
      span.setAttribute('profile.effectiveDate', effectiveDate);

      // Verify route exists
      const route = await tx.query.routes.findFirst({
        where: eq(routes.id, routeId),
      });

      if (!route) {
        throw new NotFoundError(`Route not found: ${routeId}`, {
          entityType: 'route',
          entityId: routeId,
        });
      }

      // Validate weekdayKm
      if (weekdayKm < 0 || weekdayKm > 2000) {
        throw new ValidationError('Weekday km must be between 0 and 2000', {
          field: 'weekdayKm',
          context: { value: weekdayKm },
        });
      }

      // Check for duplicate (same route and effective date)
      const existing = await tx.query.routeUtilizationProfiles.findFirst({
        where: and(
          eq(routeUtilizationProfiles.routeId, routeId),
          eq(routeUtilizationProfiles.effectiveDate, effectiveDate)
        ),
      });

      if (existing) {
        throw new DuplicateError(
          `Profile already exists for route ${route.routeCode} on ${effectiveDate}`,
          {
            field: 'effectiveDate',
            value: effectiveDate,
            context: { routeId, routeCode: route.routeCode },
          }
        );
      }

      // Create profile
      const profileData: NewRouteUtilizationProfile = {
        routeId,
        effectiveDate,
        weekdayKm,
        saturdayKm: saturdayKm ?? null,
        sundayKm: sundayKm ?? null,
        holidayKm: holidayKm ?? null,
        peakSeasonMultiplier: peakSeasonMultiplier.toString(),
        offPeakMultiplier: offPeakMultiplier.toString(),
        serviceHoursPerDay: serviceHoursPerDay?.toString() ?? null,
        roundTripKm: roundTripKm?.toString() ?? null,
        tripsPerDay: tripsPerDay ?? null,
        source: source ?? null,
        confidence,
        notes: notes ?? null,
      };

      const [result] = await tx
        .insert(routeUtilizationProfiles)
        .values(profileData)
        .returning();

      span.setAttribute('profile.id', result.id);

      this.log.info(
        {
          profileId: result.id,
          routeId,
          routeCode: route.routeCode,
          effectiveDate,
          weekdayKm,
          confidence,
        },
        `Created route utilization profile for ${route.routeCode}: ${weekdayKm} km/day (weekday)`
      );

      return result;
    });
  }

  /**
   * Update an existing route utilization profile.
   */
  async updateProfile(
    id: string,
    data: UpdateProfileRequest
  ): Promise<RouteUtilizationProfile> {
    return this.inTransaction('updateProfile', async (tx, span) => {
      span.setAttribute('profile.id', id);

      const existing = await tx.query.routeUtilizationProfiles.findFirst({
        where: eq(routeUtilizationProfiles.id, id),
        with: { route: true },
      });

      if (!existing) {
        throw new NotFoundError(`Route utilization profile not found: ${id}`, {
          entityType: 'route_utilization_profile',
          entityId: id,
        });
      }

      // Validate weekdayKm if changing
      if (data.weekdayKm !== undefined && (data.weekdayKm < 0 || data.weekdayKm > 2000)) {
        throw new ValidationError('Weekday km must be between 0 and 2000', {
          field: 'weekdayKm',
          context: { value: data.weekdayKm },
        });
      }

      // Build update object
      const updateData: Record<string, unknown> = { updatedAt: new Date() };

      if (data.weekdayKm !== undefined) updateData.weekdayKm = data.weekdayKm;
      if (data.saturdayKm !== undefined) updateData.saturdayKm = data.saturdayKm;
      if (data.sundayKm !== undefined) updateData.sundayKm = data.sundayKm;
      if (data.holidayKm !== undefined) updateData.holidayKm = data.holidayKm;
      if (data.peakSeasonMultiplier !== undefined) {
        updateData.peakSeasonMultiplier = data.peakSeasonMultiplier.toString();
      }
      if (data.offPeakMultiplier !== undefined) {
        updateData.offPeakMultiplier = data.offPeakMultiplier.toString();
      }
      if (data.serviceHoursPerDay !== undefined) {
        updateData.serviceHoursPerDay = data.serviceHoursPerDay?.toString() ?? null;
      }
      if (data.roundTripKm !== undefined) {
        updateData.roundTripKm = data.roundTripKm?.toString() ?? null;
      }
      if (data.tripsPerDay !== undefined) updateData.tripsPerDay = data.tripsPerDay;
      if (data.source !== undefined) updateData.source = data.source;
      if (data.confidence !== undefined) updateData.confidence = data.confidence;
      if (data.notes !== undefined) updateData.notes = data.notes;

      const [result] = await tx
        .update(routeUtilizationProfiles)
        .set(updateData)
        .where(eq(routeUtilizationProfiles.id, id))
        .returning();

      this.log.info(
        { profileId: id, updates: data },
        'Route utilization profile updated'
      );

      return result;
    });
  }

  /**
   * List profiles with filtering.
   */
  async listProfiles(filters?: ProfileListFilters): Promise<RouteProfileWithMeta[]> {
    return this.traced('listProfiles', async (span) => {
      const conditions: SQL<unknown>[] = [];

      if (filters?.routeId) {
        conditions.push(eq(routeUtilizationProfiles.routeId, filters.routeId));
      }
      if (filters?.routeIds && filters.routeIds.length > 0) {
        conditions.push(inArray(routeUtilizationProfiles.routeId, filters.routeIds));
      }
      if (filters?.confidence) {
        if (Array.isArray(filters.confidence)) {
          conditions.push(inArray(routeUtilizationProfiles.confidence, filters.confidence));
        } else {
          conditions.push(eq(routeUtilizationProfiles.confidence, filters.confidence));
        }
      }
      if (filters?.effectiveDateFrom) {
        conditions.push(gte(routeUtilizationProfiles.effectiveDate, filters.effectiveDateFrom));
      }
      if (filters?.effectiveDateTo) {
        conditions.push(lte(routeUtilizationProfiles.effectiveDate, filters.effectiveDateTo));
      }

      const profiles = await this.db.query.routeUtilizationProfiles.findMany({
        where: conditions.length > 0 ? and(...conditions) : undefined,
        orderBy: [desc(routeUtilizationProfiles.effectiveDate)],
        with: { route: true },
      });

      span.setAttribute('result.count', profiles.length);

      return profiles.map((p) => ({
        ...p,
        routeCode: p.route?.routeCode,
        routeName: p.route?.routeName,
      }));
    });
  }

  /**
   * Delete a profile.
   */
  async deleteProfile(id: string): Promise<void> {
    return this.inTransaction('deleteProfile', async (tx, span) => {
      span.setAttribute('profile.id', id);

      const existing = await tx.query.routeUtilizationProfiles.findFirst({
        where: eq(routeUtilizationProfiles.id, id),
        with: { route: true },
      });

      if (!existing) {
        throw new NotFoundError(`Route utilization profile not found: ${id}`, {
          entityType: 'route_utilization_profile',
          entityId: id,
        });
      }

      await tx.delete(routeUtilizationProfiles).where(eq(routeUtilizationProfiles.id, id));

      this.log.info(
        {
          profileId: id,
          routeId: existing.routeId,
          routeCode: existing.route?.routeCode,
          effectiveDate: existing.effectiveDate,
        },
        `Deleted route utilization profile for ${existing.route?.routeCode}`
      );
    });
  }

  // ===========================================================================
  // Projection Accuracy Analysis
  // ===========================================================================

  /**
   * Analyze projection accuracy across the fleet.
   *
   * This method identifies trains that are using fallback calculations
   * (fleet average or system default) instead of route-specific profiles.
   * Fleet-wide averages can result in 60,000+ km projection error over
   * the 12-year contract period.
   *
   * @param fleetIds - Optional list of fleet IDs to analyze (all fleets if not specified)
   * @returns Comprehensive analysis of projection accuracy
   */
  async analyzeProjectionAccuracy(fleetIds?: string[]): Promise<ProjectionAccuracyAnalysis> {
    return this.traced('analyzeProjectionAccuracy', async (span) => {
      const analysisTime = new Date().toISOString();
      const targetDate = new Date().toISOString().split('T')[0];

      // Get all active trains
      const allTrains = await this.db.query.trains.findMany({
        where: eq(trains.fitnessStatus, 'FIT'),
        with: { fleet: true },
      });
      const filteredTrains = fleetIds
        ? allTrains.filter((t) => fleetIds.includes(t.fleetId))
        : allTrains;

      span.setAttribute('analysis.totalTrains', filteredTrains.length);

      const fallbackTrains: TrainProjectionInfo[] = [];
      let routeProfileCount = 0;
      let fleetAverageCount = 0;
      let systemDefaultCount = 0;
      let totalImpactKm = 0;

      // Analyze each train's projection source
      for (const train of filteredTrains) {
        const rate = await this.calculateDailyRate(train.id, targetDate);

        if (rate.source.startsWith('route:')) {
          routeProfileCount++;
        } else if (rate.source === 'fleet_average') {
          fleetAverageCount++;
          // Estimate projection uncertainty: fleet averages have ~20% variance
          const dailyVariance = rate.dailyKm * 0.2;
          const yearlyImpact = dailyVariance * 365;
          const twelveYearImpact = Math.round(yearlyImpact * 12);
          totalImpactKm += twelveYearImpact;

          fallbackTrains.push({
            trainId: train.id,
            trainNumber: train.trainNumber,
            fleetId: train.fleetId,
            fleetCode: train.fleet?.code ?? 'UNKNOWN',
            source: rate.source,
            confidence: rate.confidence,
            dailyKm: rate.dailyKm,
            projectionImpactKm: twelveYearImpact,
            confidenceClass: this.getConfidenceClass(rate.confidence),
          });
        } else {
          systemDefaultCount++;
          // System default has very high uncertainty: ~50%
          const dailyVariance = rate.dailyKm * 0.5;
          const yearlyImpact = dailyVariance * 365;
          const twelveYearImpact = Math.round(yearlyImpact * 12);
          totalImpactKm += twelveYearImpact;

          fallbackTrains.push({
            trainId: train.id,
            trainNumber: train.trainNumber,
            fleetId: train.fleetId,
            fleetCode: train.fleet?.code ?? 'UNKNOWN',
            source: rate.source,
            confidence: rate.confidence,
            dailyKm: rate.dailyKm,
            projectionImpactKm: twelveYearImpact,
            confidenceClass: this.getConfidenceClass(rate.confidence),
          });
        }
      }

      const totalTrains = filteredTrains.length;
      const routeCoveragePct =
        totalTrains > 0 ? Math.round((routeProfileCount / totalTrains) * 100) : 0;

      // Estimate potential missed PMs: each PM cycle is ~25,000 km for C1
      const potentialMissedPMs = Math.round(totalImpactKm / 25000);

      // Generate recommendations
      const recommendations = this.generateAccuracyRecommendations(
        routeCoveragePct,
        fleetAverageCount,
        systemDefaultCount,
        fallbackTrains
      );

      // Determine if warning is needed
      const { requiresWarning, warningSeverity } = this.determineWarningSeverity(
        routeCoveragePct,
        systemDefaultCount
      );

      span.setAttribute('analysis.routeCoverage', routeCoveragePct);
      span.setAttribute('analysis.fallbackCount', fallbackTrains.length);
      span.setAttribute('analysis.requiresWarning', requiresWarning);
      if (warningSeverity) {
        span.setAttribute('analysis.warningSeverity', warningSeverity);
      }

      const analysis: ProjectionAccuracyAnalysis = {
        analysisTime,
        totalTrains,
        routeProfileCount,
        fleetAverageCount,
        systemDefaultCount,
        routeCoveragePct,
        fallbackTrains,
        totalImpactKm,
        potentialMissedPMs,
        recommendations,
        requiresWarning,
        warningSeverity,
      };

      if (requiresWarning) {
        this.log.warn(
          {
            routeCoveragePct,
            fallbackCount: fallbackTrains.length,
            systemDefaultCount,
            totalImpactKm,
            severity: warningSeverity,
          },
          `Projection accuracy warning: ${100 - routeCoveragePct}% of trains lack route-specific profiles. Potential ${totalImpactKm.toLocaleString()} km projection error over 12 years.`
        );
      }

      return analysis;
    });
  }

  /**
   * Emit a projection accuracy warning notification.
   *
   * This should be called periodically (e.g., weekly) or when route profiles
   * are modified to alert stakeholders about projection accuracy issues.
   *
   * @param analysis - The projection accuracy analysis result
   * @param recipientIds - User IDs to receive the notification
   * @returns Job ID if notification was queued, null if no warning needed
   */
  async emitProjectionAccuracyWarning(
    analysis: ProjectionAccuracyAnalysis,
    recipientIds: string[]
  ): Promise<string | null> {
    return this.traced('emitProjectionAccuracyWarning', async (span) => {
      if (!analysis.requiresWarning) {
        span.setAttribute('warning.skipped', true);
        span.setAttribute('warning.reason', 'no_warning_needed');
        return null;
      }

      span.setAttribute('warning.severity', analysis.warningSeverity ?? 'MEDIUM');
      span.setAttribute('warning.recipientCount', recipientIds.length);

      // Queue notification job
      const job = await addJob(QUEUE_NAMES.NOTIFICATION, 'projection_accuracy_warning', {
        type: 'PROJECTION_ACCURACY_WARNING' as const,
        severity: analysis.warningSeverity ?? 'MEDIUM',
        recipients: recipientIds,
        template: 'projection_accuracy_warning',
        subject: `[MMS] Projection Accuracy Warning - ${100 - analysis.routeCoveragePct}% of trains using fallback rates`,
        data: {
          severity: analysis.warningSeverity,
          detectionTime: analysis.analysisTime,
          trainCount: analysis.fallbackTrains.length,
          routeCoverage: analysis.routeCoveragePct,
          trains: analysis.fallbackTrains.slice(0, 20).map((t) => ({
            trainNumber: t.trainNumber,
            fleetCode: t.fleetCode,
            confidence: t.confidence,
            confidenceClass: t.confidenceClass,
            source: t.source === 'fleet_average' ? 'Fleet Average' : 'System Default',
            dailyKm: t.dailyKm,
            projectionImpactKm: t.projectionImpactKm.toLocaleString(),
          })),
          totalImpactKm: analysis.totalImpactKm.toLocaleString(),
          potentialMissedPMs: analysis.potentialMissedPMs.toLocaleString(),
          recommendations: analysis.recommendations,
          dashboardUrl: '/admin/route-utilization',
        },
      });

      this.log.info(
        {
          jobId: job.id,
          severity: analysis.warningSeverity,
          fallbackCount: analysis.fallbackTrains.length,
          totalImpactKm: analysis.totalImpactKm,
        },
        'Projection accuracy warning notification queued'
      );

      return job.id ?? null;
    });
  }

  /**
   * Get CSS class name for confidence level.
   */
  private getConfidenceClass(
    confidence: ConfidenceLevel
  ): 'high-confidence' | 'medium-confidence' | 'low-confidence' | 'estimated' {
    switch (confidence) {
      case 'HIGH':
        return 'high-confidence';
      case 'MEDIUM':
        return 'medium-confidence';
      case 'LOW':
        return 'low-confidence';
      case 'ESTIMATED':
        return 'estimated';
    }
  }

  /**
   * Generate recommendations based on analysis results.
   */
  private generateAccuracyRecommendations(
    routeCoveragePct: number,
    fleetAverageCount: number,
    systemDefaultCount: number,
    fallbackTrains: TrainProjectionInfo[]
  ): string[] {
    const recommendations: string[] = [];

    if (systemDefaultCount > 0) {
      recommendations.push(
        `CRITICAL: ${systemDefaultCount} train(s) using system default (250 km/day). ` +
          'Add route utilization profiles or improve mileage data collection.'
      );
    }

    if (routeCoveragePct < 50) {
      recommendations.push(
        `Route profile coverage is ${routeCoveragePct}% - below 50% threshold. ` +
          'Create route-specific utilization profiles for accurate PM scheduling.'
      );
    }

    if (fleetAverageCount > 0 && fleetAverageCount <= 10) {
      const affectedTrains = fallbackTrains
        .filter((t) => t.source === 'fleet_average')
        .map((t) => t.trainNumber)
        .slice(0, 5);
      recommendations.push(
        `Assign routes to these trains for improved accuracy: ${affectedTrains.join(', ')}${fleetAverageCount > 5 ? '...' : ''}`
      );
    }

    if (routeCoveragePct >= 80 && routeCoveragePct < 95) {
      recommendations.push(
        'Route coverage is good but could be improved. Consider adding profiles for remaining routes.'
      );
    }

    if (recommendations.length === 0) {
      recommendations.push('Projection accuracy is within acceptable limits.');
    }

    return recommendations;
  }

  /**
   * Determine warning severity based on analysis metrics.
   */
  private determineWarningSeverity(
    routeCoveragePct: number,
    systemDefaultCount: number
  ): { requiresWarning: boolean; warningSeverity?: 'CRITICAL' | 'HIGH' | 'MEDIUM' | 'LOW' } {
    // CRITICAL: Any train using system default (highest uncertainty)
    if (systemDefaultCount > 0) {
      return { requiresWarning: true, warningSeverity: 'CRITICAL' };
    }

    // HIGH: Less than 50% route coverage
    if (routeCoveragePct < 50) {
      return { requiresWarning: true, warningSeverity: 'HIGH' };
    }

    // MEDIUM: Less than 70% route coverage
    if (routeCoveragePct < 70) {
      return { requiresWarning: true, warningSeverity: 'MEDIUM' };
    }

    // LOW: Less than 90% route coverage
    if (routeCoveragePct < 90) {
      return { requiresWarning: true, warningSeverity: 'LOW' };
    }

    // No warning needed for >= 90% coverage with no system defaults
    return { requiresWarning: false };
  }

  // ===========================================================================
  // Helper Methods
  // ===========================================================================

  /**
   * Determine day type for a given date.
   */
  getDayType(dateStr: string, holidays?: string[]): UtilizationDayType {
    if (holidays?.includes(dateStr)) {
      return 'HOLIDAY';
    }

    const date = new Date(dateStr);
    const dayOfWeek = date.getDay();

    if (dayOfWeek === 0) return 'SUNDAY';
    if (dayOfWeek === 6) return 'SATURDAY';
    return 'WEEKDAY';
  }

  /**
   * Check if a date is in peak season.
   */
  isPeakSeason(dateStr: string): boolean {
    const date = new Date(dateStr);
    return PEAK_MONTHS.includes(date.getMonth());
  }

  /**
   * Calculate daily rate from a route profile.
   */
  private calculateFromProfile(
    profile: RouteUtilizationProfile,
    targetDate: string,
    dayType: UtilizationDayType
  ): DailyRateResult {
    // Get base km for day type
    let baseKm: number;
    switch (dayType) {
      case 'SATURDAY':
        baseKm = profile.saturdayKm ?? Math.round(profile.weekdayKm * DEFAULT_DAY_TYPE_MULTIPLIERS.SATURDAY);
        break;
      case 'SUNDAY':
        baseKm = profile.sundayKm ?? Math.round(profile.weekdayKm * DEFAULT_DAY_TYPE_MULTIPLIERS.SUNDAY);
        break;
      case 'HOLIDAY':
        baseKm = profile.holidayKm ?? Math.round(profile.weekdayKm * DEFAULT_DAY_TYPE_MULTIPLIERS.HOLIDAY);
        break;
      default:
        baseKm = profile.weekdayKm;
    }

    // Apply seasonal multiplier
    const isPeak = this.isPeakSeason(targetDate);
    const multiplier = isPeak
      ? parseFloat(profile.peakSeasonMultiplier ?? '1.0')
      : parseFloat(profile.offPeakMultiplier ?? '1.0');

    const dailyKm = Math.round(baseKm * multiplier);

    return {
      dailyKm,
      source: `route:${profile.routeId}`,
      confidence: (profile.confidence ?? 'MEDIUM') as ConfidenceLevel,
      details: {
        routeId: profile.routeId,
        dayType,
        seasonalMultiplier: multiplier,
        profileEffectiveDate: profile.effectiveDate,
      },
    };
  }

  /**
   * Get numeric rank for confidence level (higher = better).
   */
  private confidenceRank(confidence: ConfidenceLevel): number {
    switch (confidence) {
      case 'HIGH':
        return 4;
      case 'MEDIUM':
        return 3;
      case 'LOW':
        return 2;
      case 'ESTIMATED':
        return 1;
    }
  }
}

// =============================================================================
// Singleton Export
// =============================================================================

let routeUtilizationServiceInstance: RouteUtilizationService | null = null;

export function getRouteUtilizationService(): RouteUtilizationService {
  if (!routeUtilizationServiceInstance) {
    routeUtilizationServiceInstance = new RouteUtilizationService();
  }
  return routeUtilizationServiceInstance;
}

export default RouteUtilizationService;

