    40→  | 'IMPORTED'
    41→  | 'NO_HISTORY';
    42→
    43→/** Confidence level for assumption quality */
    44→export type ConfidenceLevel = 'HIGH' | 'MEDIUM' | 'LOW' | 'ESTIMATED';
    45→
    46→/** Review status for assumptions */
    47→export type ReviewStatus = 'PENDING_REVIEW' | 'REVIEWED' | 'APPLIED' | 'REJECTED';
