    49→/** PM hierarchy mapping - higher PMs satisfy lower ones */
    50→const PM_HIERARCHY: Record<string, string[]> = {
    51→  OVERHAUL: ['C4', 'C3', 'C2', 'C1'],
    52→  C4: ['C3', 'C2', 'C1'],
    53→  C3: ['C2', 'C1'],
    54→  C2: ['C1'],
    55→  C1: [],
    56→};
    57→
    58→/** Default PM intervals in months */
    59→const DEFAULT_PM_INTERVALS: Record<string, number> = {
    60→  C1: 6,
    61→  C2: 12,
    62→  C3: 24,
    63→  C4: 48,
    64→  OVERHAUL: 96,
    65→};
