   435→        // Update review requirement based on new confidence
   436→        updates.requiresReview =
   437→          request.confidenceLevel === 'LOW' || request.confidenceLevel === 'ESTIMATED';
   438→      }
   439→      if (request.inferenceSource !== undefined) {
