/**
 * MMS Unavailability Service
 *
 * Tracks trains that are out of service due to corrective maintenance,
 * incidents, collisions, or other events. This is a CRITICAL v2.1 service
 * that integrates with Maximo CMMS and provides constraints to the optimizer.
 *
 * Key responsibilities:
 * - Create/resolve unavailability events
 * - Automatically sync train fitness status
 * - Detect conflicts with scheduled PM
 * - Provide active events for optimizer constraints
 * - Support Maximo work order integration
 *
 * Business rules:
 * - ACTIVE events update train fitness to restriction_level (RESTRICTED/GROUNDED)
 * - RESOLVED events restore train fitness to FIT (unless other active events exist)
 * - Events with blocks_run_assignment=true prevent optimizer from assigning train
 * - Events with blocks_pm_scheduling=true prevent PM scheduler from planning train
 *
 * @see specs/003-database-schema.md Section 3.2.3 (Unavailability Events)
 * @see specs/004-domain-services.md Section 4.2.5 (Unavailability Service)
 */

import { eq, and, inArray, sql, desc, count, gte, lte } from 'drizzle-orm';
import type { SQL } from 'drizzle-orm';
import { BaseService, MmsAttributes } from '../lib/services/base';
import {
  unavailabilityEvents,
  trains,
  pmSchedule,
  type UnavailabilityEvent,
  type NewUnavailabilityEvent,
  type Train,
} from '../lib/db/schema';
import {
  NotFoundError,
  TrainNotFoundError,
  BusinessRuleError,
  ConflictError,
} from '../lib/errors';

// =============================================================================
// Types
// =============================================================================

/** Unavailability event types */
type UnavailabilityType = 'CORRECTIVE' | 'INCIDENT' | 'COLLISION' | 'VANDALISM' | 'EXTERNAL' | 'PLANNED_OUTAGE';

/** Event status */
type UnavailabilityStatus = 'ACTIVE' | 'RESOLVED';

/** Restriction level (maps to fitness status) */
type RestrictionLevel = 'RESTRICTED' | 'GROUNDED';

/** Create event request */
export interface CreateEventRequest {
  trainId: string;
  eventType: UnavailabilityType;
  restrictionLevel: RestrictionLevel;
  description?: string;
  failureCode?: string;
  affectedSystem?: string;
  estimatedRepairHours?: number;
  estimatedReturnDate?: string;
  sourceSystem?: string;
  externalReference?: string;
  externalStatus?: string;
  blocksPmScheduling?: boolean;
  blocksRunAssignment?: boolean;
  reportedBy?: string;
}

/** Resolve event request */
export interface ResolveEventRequest {
  eventId: string;
  actualReturnDate: string;
  resolutionNotes?: string;
  resolvedBy?: string;
}

/** Query filters for listing events */
export interface EventListFilters {
  trainId?: string;
  trainIds?: string[];
  status?: UnavailabilityStatus;
  eventType?: UnavailabilityType | UnavailabilityType[];
  restrictionLevel?: RestrictionLevel;
  sourceSystem?: string;
  dateFrom?: string;
  dateTo?: string;
  blocksPmScheduling?: boolean;
  blocksRunAssignment?: boolean;
}

/** PM conflict detection result */
export interface PMConflict {
  pmScheduleId: string;
  trainId: string;
  trainNumber: string;
  pmCode: string;
  targetDate: string;
  unavailabilityEventId: string;
  eventType: UnavailabilityType;
  estimatedReturnDate: string | null;
  severity: 'HIGH' | 'MEDIUM' | 'LOW';
  message: string;
}

/** Event with related train details */
export interface EventWithTrain extends UnavailabilityEvent {
  train: Train | null;
}

/** Active events summary for optimizer */
export interface OptimizerConstraints {
  groundedTrainIds: string[];
  restrictedTrainIds: string[];
  blockedFromPmTrainIds: string[];
  blockedFromRunAssignmentTrainIds: string[];
  totalActiveEvents: number;
}

// =============================================================================
// Unavailability Service
// =============================================================================

export class UnavailabilityService extends BaseService {
  constructor() {
    super({ name: 'unavailability-service', version: '1.0.0' });
  }

  // ===========================================================================
  // Event Creation
  // ===========================================================================

  /**
   * Create a new unavailability event.
   *
   * This method:
   * 1. Validates the train exists
   * 2. Creates the event record
   * 3. Updates train fitness status to match restriction level
   *
   * @param request - Event creation parameters
   * @returns Created event with updated train fitness
   */
  async createEvent(request: CreateEventRequest): Promise<UnavailabilityEvent> {
    return this.inTransaction('createEvent', async (tx, span) => {
      const {
        trainId,
        eventType,
        restrictionLevel,
        description,
        failureCode,
        affectedSystem,
        estimatedRepairHours,
        estimatedReturnDate,
        sourceSystem,
        externalReference,
        externalStatus,
        blocksPmScheduling = true,
        blocksRunAssignment = true,
      } = request;

      span.setAttribute(MmsAttributes.TRAIN_ID, trainId);
      span.setAttribute('event.type', eventType);
      span.setAttribute('event.restrictionLevel', restrictionLevel);

      // Validate train exists
      const train = await tx.query.trains.findFirst({
        where: eq(trains.id, trainId),
      });

      if (!train) {
        throw new TrainNotFoundError(trainId);
      }

      span.setAttribute(MmsAttributes.TRAIN_NUMBER, train.trainNumber);

      // Check for duplicate external reference if provided
      if (externalReference && sourceSystem) {
        const existing = await tx.query.unavailabilityEvents.findFirst({
          where: and(
            eq(unavailabilityEvents.sourceSystem, sourceSystem),
            eq(unavailabilityEvents.externalReference, externalReference)
          ),
        });

        if (existing) {
          throw new ConflictError(
            `Unavailability event already exists for ${sourceSystem} reference ${externalReference}`
          );
        }
      }

      // Create the event
      const eventData: NewUnavailabilityEvent = {
        trainId,
        eventType,
        status: 'ACTIVE',
        restrictionLevel,
        reportedAt: new Date(),
        estimatedRepairHours,
        estimatedReturnDate: estimatedReturnDate ?? null,
        sourceSystem,
        externalReference,
        externalStatus,
        description,
        failureCode,
        affectedSystem,
        blocksPmScheduling,
        blocksRunAssignment,
      };

      const [event] = await tx.insert(unavailabilityEvents).values(eventData).returning();
      span.setAttribute('event.id', event.id);

      // Update train fitness status
      await tx
        .update(trains)
        .set({
          fitnessStatus: restrictionLevel,
          fitnessNotes: `${eventType}: ${description ?? 'No description provided'}`,
          updatedAt: new Date(),
        })
        .where(eq(trains.id, trainId));

      this.log.info(
        {
          eventId: event.id,
          trainId,
          trainNumber: train.trainNumber,
          eventType,
          restrictionLevel,
          sourceSystem,
          externalReference,
        },
        `Unavailability event created: ${train.trainNumber} is now ${restrictionLevel}`
      );

      this.recordEvent('unavailability.created', {
        [MmsAttributes.TRAIN_ID]: trainId,
        [MmsAttributes.TRAIN_NUMBER]: train.trainNumber,
        'event.id': event.id,
        'event.type': eventType,
        'event.restrictionLevel': restrictionLevel,
      }, span);

      return event;
    });
  }

  // ===========================================================================
  // Event Resolution
  // ===========================================================================

  /**
   * Resolve an unavailability event.
   *
   * This method:
   * 1. Updates the event status to RESOLVED
   * 2. Records actual return date and resolution notes
   * 3. Restores train fitness to FIT (if no other active events)
   *
   * @param request - Resolution parameters
   * @returns Resolved event
   */
  async resolveEvent(request: ResolveEventRequest): Promise<UnavailabilityEvent> {
    return this.inTransaction('resolveEvent', async (tx, span) => {
      const { eventId, actualReturnDate, resolutionNotes, resolvedBy } = request;

      span.setAttribute('event.id', eventId);

      // Get the event
      const event = await tx.query.unavailabilityEvents.findFirst({
        where: eq(unavailabilityEvents.id, eventId),
        with: { train: true },
      });

      if (!event) {
        throw new NotFoundError(`Unavailability event not found: ${eventId}`, {
          entityType: 'unavailability_event',
          entityId: eventId,
        });
      }

      if (event.status === 'RESOLVED') {
        throw new BusinessRuleError('Event is already resolved', {
          rule: 'event_already_resolved',
          context: { eventId, resolvedAt: event.resolvedAt },
        });
      }

      span.setAttribute(MmsAttributes.TRAIN_ID, event.trainId);

      // Resolve the event
      const [resolvedEvent] = await tx
        .update(unavailabilityEvents)
        .set({
          status: 'RESOLVED',
          actualReturnDate,
          resolvedAt: new Date(),
          resolvedBy: resolvedBy ?? null,
          resolutionNotes,
          updatedAt: new Date(),
        })
        .where(eq(unavailabilityEvents.id, eventId))
        .returning();

      // Check if train has any other active events
      const otherActiveEvents = await tx.query.unavailabilityEvents.findMany({
        where: and(
          eq(unavailabilityEvents.trainId, event.trainId),
          eq(unavailabilityEvents.status, 'ACTIVE')
        ),
      });

      // Determine new fitness status
      let newFitnessStatus: 'FIT' | 'RESTRICTED' | 'GROUNDED' = 'FIT';
      let fitnessNotes = 'All unavailability events resolved';

      if (otherActiveEvents.length > 0) {
        // Find the most restrictive active event
        const hasGrounded = otherActiveEvents.some((e) => e.restrictionLevel === 'GROUNDED');
        newFitnessStatus = hasGrounded ? 'GROUNDED' : 'RESTRICTED';
        fitnessNotes = `${otherActiveEvents.length} active unavailability event(s) remaining`;
      }

      // Update train fitness
      await tx
        .update(trains)
        .set({
          fitnessStatus: newFitnessStatus,
          fitnessNotes,
          updatedAt: new Date(),
        })
        .where(eq(trains.id, event.trainId));

      const trainNumber = (event as EventWithTrain).train?.trainNumber ?? 'unknown';

      this.log.info(
        {
          eventId,
          trainId: event.trainId,
          trainNumber,
          actualReturnDate,
          newFitnessStatus,
          remainingActiveEvents: otherActiveEvents.length,
        },
        `Unavailability event resolved: ${trainNumber} is now ${newFitnessStatus}`
      );

      this.recordEvent('unavailability.resolved', {
        [MmsAttributes.TRAIN_ID]: event.trainId,
        'event.id': eventId,
        'event.actualReturnDate': actualReturnDate,
        'train.newFitnessStatus': newFitnessStatus,
      }, span);

      return resolvedEvent;
    });
  }

  // ===========================================================================
  // Event Queries
  // ===========================================================================

  /**
   * Get an event by ID with train details
   */
  async getEventById(eventId: string): Promise<EventWithTrain> {
    return this.traced('getEventById', async (span) => {
      span.setAttribute('event.id', eventId);

      const event = await this.db.query.unavailabilityEvents.findFirst({
        where: eq(unavailabilityEvents.id, eventId),
        with: { train: true },
      });

      if (!event) {
        throw new NotFoundError(`Unavailability event not found: ${eventId}`, {
          entityType: 'unavailability_event',
          entityId: eventId,
        });
      }

      return event as EventWithTrain;
    });
  }

  /**
   * Get event by external reference (Maximo WO number)
   */
  async getEventByExternalReference(
    sourceSystem: string,
    externalReference: string
  ): Promise<UnavailabilityEvent | null> {
    return this.traced('getEventByExternalReference', async (span) => {
      span.setAttribute('event.sourceSystem', sourceSystem);
      span.setAttribute('event.externalReference', externalReference);

      const event = await this.db.query.unavailabilityEvents.findFirst({
        where: and(
          eq(unavailabilityEvents.sourceSystem, sourceSystem),
          eq(unavailabilityEvents.externalReference, externalReference)
        ),
      });

      return event ?? null;
    });
  }

  /**
   * List events with filtering
   */
  async listEvents(filters?: EventListFilters): Promise<UnavailabilityEvent[]> {
    return this.traced('listEvents', async (span) => {
      const conditions: SQL<unknown>[] = [];

      if (filters?.trainId) {
        conditions.push(eq(unavailabilityEvents.trainId, filters.trainId));
      }
      if (filters?.trainIds && filters.trainIds.length > 0) {
        conditions.push(inArray(unavailabilityEvents.trainId, filters.trainIds));
      }
      if (filters?.status) {
        conditions.push(eq(unavailabilityEvents.status, filters.status));
      }
      if (filters?.eventType) {
        if (Array.isArray(filters.eventType)) {
          conditions.push(inArray(unavailabilityEvents.eventType, filters.eventType));
        } else {
          conditions.push(eq(unavailabilityEvents.eventType, filters.eventType));
        }
      }
      if (filters?.restrictionLevel) {
        conditions.push(eq(unavailabilityEvents.restrictionLevel, filters.restrictionLevel));
      }
      if (filters?.sourceSystem) {
        conditions.push(eq(unavailabilityEvents.sourceSystem, filters.sourceSystem));
      }
      if (filters?.dateFrom) {
        conditions.push(gte(unavailabilityEvents.reportedAt, new Date(filters.dateFrom)));
      }
      if (filters?.dateTo) {
        conditions.push(lte(unavailabilityEvents.reportedAt, new Date(filters.dateTo)));
      }
      if (filters?.blocksPmScheduling !== undefined) {
        conditions.push(eq(unavailabilityEvents.blocksPmScheduling, filters.blocksPmScheduling));
      }
      if (filters?.blocksRunAssignment !== undefined) {
        conditions.push(eq(unavailabilityEvents.blocksRunAssignment, filters.blocksRunAssignment));
      }

      const result = await this.db.query.unavailabilityEvents.findMany({
        where: conditions.length > 0 ? and(...conditions) : undefined,
        orderBy: desc(unavailabilityEvents.reportedAt),
      });

      span.setAttribute('result.count', result.length);
      return result;
    });
  }

  /**
   * Query active events for a train
   */
  async getActiveEventsForTrain(trainId: string): Promise<UnavailabilityEvent[]> {
    return this.traced('getActiveEventsForTrain', async (span) => {
      span.setAttribute(MmsAttributes.TRAIN_ID, trainId);

      const result = await this.db.query.unavailabilityEvents.findMany({
        where: and(
          eq(unavailabilityEvents.trainId, trainId),
          eq(unavailabilityEvents.status, 'ACTIVE')
        ),
        orderBy: desc(unavailabilityEvents.reportedAt),
      });

      span.setAttribute('result.count', result.length);
      return result;
    });
  }

  /**
   * Query all active events (for optimizer constraints)
   */
  async queryActiveEvents(): Promise<OptimizerConstraints> {
    return this.traced('queryActiveEvents', async (span) => {
      const activeEvents = await this.db.query.unavailabilityEvents.findMany({
        where: eq(unavailabilityEvents.status, 'ACTIVE'),
      });

      const groundedTrainIds = new Set<string>();
      const restrictedTrainIds = new Set<string>();
      const blockedFromPmTrainIds = new Set<string>();
      const blockedFromRunAssignmentTrainIds = new Set<string>();

      for (const event of activeEvents) {
        if (event.restrictionLevel === 'GROUNDED') {
          groundedTrainIds.add(event.trainId);
        } else if (event.restrictionLevel === 'RESTRICTED') {
          restrictedTrainIds.add(event.trainId);
        }

        if (event.blocksPmScheduling) {
          blockedFromPmTrainIds.add(event.trainId);
        }
        if (event.blocksRunAssignment) {
          blockedFromRunAssignmentTrainIds.add(event.trainId);
        }
      }

      const result: OptimizerConstraints = {
        groundedTrainIds: Array.from(groundedTrainIds),
        restrictedTrainIds: Array.from(restrictedTrainIds),
        blockedFromPmTrainIds: Array.from(blockedFromPmTrainIds),
        blockedFromRunAssignmentTrainIds: Array.from(blockedFromRunAssignmentTrainIds),
        totalActiveEvents: activeEvents.length,
      };

      span.setAttribute('result.groundedCount', result.groundedTrainIds.length);
      span.setAttribute('result.restrictedCount', result.restrictedTrainIds.length);
      span.setAttribute('result.totalEvents', result.totalActiveEvents);

      this.log.debug(
        {
          groundedCount: result.groundedTrainIds.length,
          restrictedCount: result.restrictedTrainIds.length,
          pmBlockedCount: result.blockedFromPmTrainIds.length,
          runBlockedCount: result.blockedFromRunAssignmentTrainIds.length,
        },
        'Optimizer constraints from active unavailability events'
      );

      return result;
    });
  }

  // ===========================================================================
  // PM Conflict Detection
  // ===========================================================================

  /**
   * Detect PM schedule conflicts with unavailability events.
   *
   * Checks if any scheduled PM overlaps with active unavailability events
   * where the train cannot be scheduled for maintenance.
   *
   * @param dateFrom - Start of date range to check
   * @param dateTo - End of date range to check
   * @returns List of detected conflicts
   */
  async detectPMConflicts(dateFrom: string, dateTo: string): Promise<PMConflict[]> {
    return this.traced('detectPMConflicts', async (span) => {
      span.setAttribute('dateRange.from', dateFrom);
      span.setAttribute('dateRange.to', dateTo);

      // Get active unavailability events that block PM scheduling
      const blockingEvents = await this.db.query.unavailabilityEvents.findMany({
        where: and(
          eq(unavailabilityEvents.status, 'ACTIVE'),
          eq(unavailabilityEvents.blocksPmScheduling, true)
        ),
        with: { train: true },
      });

      if (blockingEvents.length === 0) {
        span.setAttribute('result.conflicts', 0);
        return [];
      }

      const blockedTrainIds = blockingEvents.map((e) => e.trainId);

      // Get scheduled PM for blocked trains in the date range
      const scheduledPm = await this.db.query.pmSchedule.findMany({
        where: and(
          inArray(pmSchedule.trainId, blockedTrainIds),
          eq(pmSchedule.status, 'SCHEDULED'),
          gte(pmSchedule.targetDate, dateFrom),
          lte(pmSchedule.targetDate, dateTo)
        ),
        with: {
          train: true,
          pmType: true,
        },
      });

      // Build conflict report
      const conflicts: PMConflict[] = [];

      for (const pm of scheduledPm) {
        const event = blockingEvents.find((e) => e.trainId === pm.trainId);
        if (!event) continue;

        const pmTargetDate = pm.targetDate;
        const estimatedReturn = event.estimatedReturnDate;

        // Determine severity
        let severity: 'HIGH' | 'MEDIUM' | 'LOW' = 'MEDIUM';
        if (event.restrictionLevel === 'GROUNDED') {
          severity = 'HIGH';
        } else if (estimatedReturn && pmTargetDate && pmTargetDate < estimatedReturn) {
          severity = 'HIGH';
        }

        const trainNumber = pm.train?.trainNumber ?? 'unknown';
        const pmCode = pm.pmType?.pmCode ?? 'unknown';

        conflicts.push({
          pmScheduleId: pm.id,
          trainId: pm.trainId,
          trainNumber,
          pmCode,
          targetDate: pmTargetDate ?? '',
          unavailabilityEventId: event.id,
          eventType: event.eventType as UnavailabilityType,
          estimatedReturnDate: estimatedReturn,
          severity,
          message: `PM ${pmCode} for ${trainNumber} scheduled on ${pmTargetDate} conflicts with ${event.eventType} event (${event.restrictionLevel})`,
        });
      }

      span.setAttribute('result.conflicts', conflicts.length);

      if (conflicts.length > 0) {
        this.log.warn(
          {
            conflictCount: conflicts.length,
            dateRange: { from: dateFrom, to: dateTo },
            highSeverityCount: conflicts.filter((c) => c.severity === 'HIGH').length,
          },
          `Detected ${conflicts.length} PM scheduling conflicts with unavailability events`
        );
      }

      return conflicts;
    });
  }

  // ===========================================================================
  // Maximo Integration Helpers
  // ===========================================================================

  /**
   * Update event from Maximo status change.
   * Called by Maximo webhook receiver.
   */
  async updateFromMaximo(
    externalReference: string,
    maximoStatus: string,
    updates?: Partial<{
      estimatedRepairHours: number;
      estimatedReturnDate: string;
      description: string;
      failureCode: string;
    }>
  ): Promise<UnavailabilityEvent | null> {
    return this.inTransaction('updateFromMaximo', async (tx, span) => {
      span.setAttribute('maximo.reference', externalReference);
      span.setAttribute('maximo.status', maximoStatus);

      const event = await tx.query.unavailabilityEvents.findFirst({
        where: and(
          eq(unavailabilityEvents.sourceSystem, 'MAXIMO'),
          eq(unavailabilityEvents.externalReference, externalReference)
        ),
      });

      if (!event) {
        this.log.warn(
          { externalReference, maximoStatus },
          'Maximo status update for unknown event - ignoring'
        );
        return null;
      }

      // Map Maximo status to event status
      // COMP, CLOSE, CAN = resolved
      const isResolved = ['COMP', 'CLOSE', 'CAN'].includes(maximoStatus);

      if (isResolved && event.status === 'ACTIVE') {
        // Resolve the event
        const [resolved] = await tx
          .update(unavailabilityEvents)
          .set({
            status: 'RESOLVED',
            externalStatus: maximoStatus,
            actualReturnDate: new Date().toISOString().split('T')[0],
            resolvedAt: new Date(),
            resolutionNotes: `Resolved via Maximo status: ${maximoStatus}`,
            updatedAt: new Date(),
            ...updates,
          })
          .where(eq(unavailabilityEvents.id, event.id))
          .returning();

        // Restore train fitness (check for other active events)
        await this.restoreTrainFitness(tx, event.trainId);

        this.log.info(
          { eventId: event.id, trainId: event.trainId, maximoStatus },
          `Event resolved via Maximo status: ${maximoStatus}`
        );

        return resolved;
      } else {
        // Just update the external status and any provided fields
        const [updated] = await tx
          .update(unavailabilityEvents)
          .set({
            externalStatus: maximoStatus,
            updatedAt: new Date(),
            ...updates,
          })
          .where(eq(unavailabilityEvents.id, event.id))
          .returning();

        return updated;
      }
    });
  }

  /**
   * Restore train fitness status after event resolution.
   * Checks for other active events and sets appropriate status.
   */
  private async restoreTrainFitness(
    tx: Parameters<Parameters<BaseService['inTransaction']>[1]>[0],
    trainId: string
  ): Promise<void> {
    const otherActiveEvents = await tx.query.unavailabilityEvents.findMany({
      where: and(
        eq(unavailabilityEvents.trainId, trainId),
        eq(unavailabilityEvents.status, 'ACTIVE')
      ),
    });

    let newFitnessStatus: 'FIT' | 'RESTRICTED' | 'GROUNDED' = 'FIT';
    let fitnessNotes = 'All unavailability events resolved';

    if (otherActiveEvents.length > 0) {
      const hasGrounded = otherActiveEvents.some((e) => e.restrictionLevel === 'GROUNDED');
      newFitnessStatus = hasGrounded ? 'GROUNDED' : 'RESTRICTED';
      fitnessNotes = `${otherActiveEvents.length} active unavailability event(s) remaining`;
    }

    await tx
      .update(trains)
      .set({
        fitnessStatus: newFitnessStatus,
        fitnessNotes,
        updatedAt: new Date(),
      })
      .where(eq(trains.id, trainId));
  }

  // ===========================================================================
  // Statistics
  // ===========================================================================

  /**
   * Get summary statistics for unavailability events
   */
  async getStatistics(): Promise<{
    totalActive: number;
    byType: Record<UnavailabilityType, number>;
    byRestrictionLevel: Record<RestrictionLevel, number>;
    avgResolutionHours: number;
    trainsAffected: number;
  }> {
    return this.traced('getStatistics', async (span) => {
      // Active events count
      const [{ activeCount }] = await this.db
        .select({ activeCount: count() })
        .from(unavailabilityEvents)
        .where(eq(unavailabilityEvents.status, 'ACTIVE'));

      // Count by type
      const byTypeResults = await this.db
        .select({
          eventType: unavailabilityEvents.eventType,
          count: count(),
        })
        .from(unavailabilityEvents)
        .where(eq(unavailabilityEvents.status, 'ACTIVE'))
        .groupBy(unavailabilityEvents.eventType);

      const byType: Record<string, number> = {};
      for (const row of byTypeResults) {
        byType[row.eventType] = row.count;
      }

      // Count by restriction level
      const byLevelResults = await this.db
        .select({
          restrictionLevel: unavailabilityEvents.restrictionLevel,
          count: count(),
        })
        .from(unavailabilityEvents)
        .where(eq(unavailabilityEvents.status, 'ACTIVE'))
        .groupBy(unavailabilityEvents.restrictionLevel);

      const byRestrictionLevel: Record<string, number> = {};
      for (const row of byLevelResults) {
        if (row.restrictionLevel) {
          byRestrictionLevel[row.restrictionLevel] = row.count;
        }
      }

      // Unique affected trains
      const affectedTrains = await this.db
        .selectDistinct({ trainId: unavailabilityEvents.trainId })
        .from(unavailabilityEvents)
        .where(eq(unavailabilityEvents.status, 'ACTIVE'));

      // Average resolution time (for resolved events with actual return)
      const avgResolutionResult = await this.db
        .select({
          avgHours: sql<number>`
            AVG(
              EXTRACT(EPOCH FROM (${unavailabilityEvents.resolvedAt} - ${unavailabilityEvents.reportedAt})) / 3600
            )
          `,
        })
        .from(unavailabilityEvents)
        .where(
          and(
            eq(unavailabilityEvents.status, 'RESOLVED'),
            sql`${unavailabilityEvents.resolvedAt} IS NOT NULL`
          )
        );

      const avgResolutionHours = Math.round(Number(avgResolutionResult[0]?.avgHours) || 0);

      const result = {
        totalActive: activeCount,
        byType: byType as Record<UnavailabilityType, number>,
        byRestrictionLevel: byRestrictionLevel as Record<RestrictionLevel, number>,
        avgResolutionHours,
        trainsAffected: affectedTrains.length,
      };

      span.setAttribute('stats.totalActive', result.totalActive);
      span.setAttribute('stats.trainsAffected', result.trainsAffected);

      return result;
    });
  }
}

// =============================================================================
// Singleton Export
// =============================================================================

let unavailabilityServiceInstance: UnavailabilityService | null = null;

export function getUnavailabilityService(): UnavailabilityService {
  if (!unavailabilityServiceInstance) {
    unavailabilityServiceInstance = new UnavailabilityService();
  }
  return unavailabilityServiceInstance;
}

export default UnavailabilityService;
